async fn internal_replication_apply(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
    Json(body): Json<InternalReplicationApplyRequest>,
) -> Response {
    if let Err(response) = ensure_internal_token(&headers) {
        return response;
    }
    if !valid_bucket_name(&body.source_bucket) {
        return (
            StatusCode::BAD_REQUEST,
            Json(json!({ "error": bilingual_text("源桶名无效", "存储桶名称无效 / invalid bucket name") })),
        )
            .into_response();
    }
    let site_root = state
        .data_dir
        .join(".rustio_replication")
        .join("sites")
        .join(&body.target_site)
        .join(&body.source_bucket);
    let object_space_root = internal_replication_object_space_root(
        &state.data_dir,
        &body.target_site,
        &body.source_bucket,
    );
    let marker_path = state
        .data_dir
        .join(".rustio_replication")
        .join(".internal_applied")
        .join(format!("{}.done", body.idempotency_key));
    if marker_path.exists() {
        return (StatusCode::OK, Json(json!({ "status": "idempotent" }))).into_response();
    }

    let Some(target_path) = safe_internal_replication_path(&site_root, &body.object_key) else {
        return (
            StatusCode::BAD_REQUEST,
            Json(json!({ "error": bilingual_text("对象键无效", "invalid object key") })),
        )
            .into_response();
    };
    let Some(object_space_target_path) =
        safe_internal_replication_path(&object_space_root, &body.object_key)
    else {
        return (
            StatusCode::BAD_REQUEST,
            Json(json!({ "error": bilingual_text("对象键无效", "invalid object key") })),
        )
            .into_response();
    };
    let object_meta = body.object_meta.clone();
    if body.operation == "delete" {
        let _ = tokio::fs::remove_file(&target_path).await;
        let _ = tokio::fs::remove_file(&object_space_target_path).await;
        if let Some(meta_path) = internal_replication_meta_path(&site_root, &body.object_key) {
            let _ = tokio::fs::remove_file(meta_path).await;
        }
        if let Some(meta_path) =
            internal_replication_meta_path(&object_space_root, &body.object_key)
        {
            let _ = tokio::fs::remove_file(meta_path).await;
        }
        if let Some(version_id) = body.version_id.as_deref() {
            if let Some(version_meta_path) =
                internal_replication_version_meta_path(&site_root, &body.object_key, version_id)
            {
                let _ = tokio::fs::remove_file(version_meta_path).await;
            }
            if let Some(version_payload_path) =
                internal_replication_version_payload_path(&site_root, &body.object_key, version_id)
            {
                let _ = tokio::fs::remove_file(version_payload_path).await;
            }
            if let Some(version_meta_path) = internal_replication_version_meta_path(
                &object_space_root,
                &body.object_key,
                version_id,
            ) {
                let _ = tokio::fs::remove_file(version_meta_path).await;
            }
            if let Some(version_payload_path) = internal_replication_version_payload_path(
                &object_space_root,
                &body.object_key,
                version_id,
            ) {
                let _ = tokio::fs::remove_file(version_payload_path).await;
            }
        }

        if object_meta
            .as_ref()
            .map(|meta| meta.delete_marker)
            .unwrap_or(false)
        {
            if let Some(meta_path) = internal_replication_meta_path(&site_root, &body.object_key) {
                if let Some(parent) = meta_path.parent() {
                    let _ = tokio::fs::create_dir_all(parent).await;
                }
                if let Some(meta) = object_meta.as_ref() {
                    if let Ok(bytes) = serde_json::to_vec_pretty(meta) {
                        let _ = tokio::fs::write(meta_path, bytes).await;
                    }
                }
            }
            if let Some(meta_path) =
                internal_replication_meta_path(&object_space_root, &body.object_key)
            {
                if let Some(parent) = meta_path.parent() {
                    let _ = tokio::fs::create_dir_all(parent).await;
                }
                if let Some(meta) = object_meta.as_ref() {
                    if let Ok(bytes) = serde_json::to_vec_pretty(meta) {
                        let _ = tokio::fs::write(meta_path, bytes).await;
                    }
                }
            }
            if let (Some(meta), Some(version_meta_path)) = (
                object_meta.as_ref(),
                body.version_id.as_deref().and_then(|version_id| {
                    internal_replication_version_meta_path(&site_root, &body.object_key, version_id)
                }),
            ) {
                if let Some(parent) = version_meta_path.parent() {
                    let _ = tokio::fs::create_dir_all(parent).await;
                }
                if let Ok(bytes) = serde_json::to_vec_pretty(meta) {
                    let _ = tokio::fs::write(version_meta_path, bytes).await;
                }
            }
            if let (Some(meta), Some(version_meta_path)) = (
                object_meta.as_ref(),
                body.version_id.as_deref().and_then(|version_id| {
                    internal_replication_version_meta_path(
                        &object_space_root,
                        &body.object_key,
                        version_id,
                    )
                }),
            ) {
                if let Some(parent) = version_meta_path.parent() {
                    let _ = tokio::fs::create_dir_all(parent).await;
                }
                if let Ok(bytes) = serde_json::to_vec_pretty(meta) {
                    let _ = tokio::fs::write(version_meta_path, bytes).await;
                }
            }
        }
    } else {
        let payload = body
            .payload_base64
            .as_deref()
            .and_then(|value| BASE64.decode(value).ok())
            .unwrap_or_default();
        if let Some(parent) = target_path.parent() {
            if let Err(err) = tokio::fs::create_dir_all(parent).await {
                return (
                    StatusCode::INTERNAL_SERVER_ERROR,
                    Json(json!({
                        "error": bilingual_text(
                            "创建目标目录失败",
                            &format!("failed to create target dir: {err}")
                        )
                    })),
                )
                    .into_response();
            }
        }
        if let Some(parent) = object_space_target_path.parent() {
            let _ = tokio::fs::create_dir_all(parent).await;
        }
        if let Err(err) = tokio::fs::write(&target_path, &payload).await {
            return (
                StatusCode::INTERNAL_SERVER_ERROR,
                Json(json!({
                    "error": bilingual_text(
                        "写入目标对象失败",
                        &format!("failed to write target object: {err}")
                    )
                })),
            )
                .into_response();
        }
        let _ = tokio::fs::write(&object_space_target_path, &payload).await;

        if let Some(meta) = object_meta.as_ref() {
            if let Some(meta_path) = internal_replication_meta_path(&site_root, &body.object_key) {
                if let Some(parent) = meta_path.parent() {
                    let _ = tokio::fs::create_dir_all(parent).await;
                }
                if let Ok(bytes) = serde_json::to_vec_pretty(meta) {
                    let _ = tokio::fs::write(meta_path, bytes).await;
                }
            }
            if let Some(meta_path) =
                internal_replication_meta_path(&object_space_root, &body.object_key)
            {
                if let Some(parent) = meta_path.parent() {
                    let _ = tokio::fs::create_dir_all(parent).await;
                }
                if let Ok(bytes) = serde_json::to_vec_pretty(meta) {
                    let _ = tokio::fs::write(meta_path, bytes).await;
                }
            }
            if let Some(version_id) = body.version_id.as_deref() {
                if let Some(version_meta_path) =
                    internal_replication_version_meta_path(&site_root, &body.object_key, version_id)
                {
                    if let Some(parent) = version_meta_path.parent() {
                        let _ = tokio::fs::create_dir_all(parent).await;
                    }
                    if let Ok(bytes) = serde_json::to_vec_pretty(meta) {
                        let _ = tokio::fs::write(version_meta_path, bytes).await;
                    }
                }
                if let Some(version_meta_path) = internal_replication_version_meta_path(
                    &object_space_root,
                    &body.object_key,
                    version_id,
                ) {
                    if let Some(parent) = version_meta_path.parent() {
                        let _ = tokio::fs::create_dir_all(parent).await;
                    }
                    if let Ok(bytes) = serde_json::to_vec_pretty(meta) {
                        let _ = tokio::fs::write(version_meta_path, bytes).await;
                    }
                }
                if let Some(version_payload_path) = internal_replication_version_payload_path(
                    &site_root,
                    &body.object_key,
                    version_id,
                ) {
                    if let Some(parent) = version_payload_path.parent() {
                        let _ = tokio::fs::create_dir_all(parent).await;
                    }
                    let _ = tokio::fs::write(version_payload_path, &payload).await;
                }
                if let Some(version_payload_path) = internal_replication_version_payload_path(
                    &object_space_root,
                    &body.object_key,
                    version_id,
                ) {
                    if let Some(parent) = version_payload_path.parent() {
                        let _ = tokio::fs::create_dir_all(parent).await;
                    }
                    let _ = tokio::fs::write(version_payload_path, &payload).await;
                }
            }
        }
    }

    if let Some(parent) = marker_path.parent() {
        let _ = tokio::fs::create_dir_all(parent).await;
    }
    if let Err(err) = tokio::fs::write(&marker_path, body.checkpoint.to_string()).await {
        return (
            StatusCode::INTERNAL_SERVER_ERROR,
            Json(json!({
                "error": bilingual_text(
                    "写入复制标记失败",
                    &format!("failed to persist marker: {err}")
                )
            })),
        )
            .into_response();
    }
    (StatusCode::OK, Json(json!({ "status": "applied" }))).into_response()
}

async fn internal_console_session_sync(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
    Json(body): Json<ConsoleSession>,
) -> Response {
    if let Err(response) = ensure_internal_token(&headers) {
        return response;
    }
    match state.upsert_console_session_runtime(body).await {
        Ok(()) => (StatusCode::OK, Json(json!({ "ok": true }))).into_response(),
        Err(message) => (
            StatusCode::INTERNAL_SERVER_ERROR,
            Json(json!({
                "error": bilingual_text(
                    "同步控制台会话失败",
                    &format!("failed to sync console session: {message}")
                )
            })),
        )
            .into_response(),
    }
}

async fn internal_console_session_delete(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
    Path(session_id): Path<String>,
) -> Response {
    if let Err(response) = ensure_internal_token(&headers) {
        return response;
    }
    match state.delete_console_session_runtime(&session_id).await {
        Ok(()) => (StatusCode::OK, Json(json!({ "ok": true }))).into_response(),
        Err(message) => (
            StatusCode::INTERNAL_SERVER_ERROR,
            Json(json!({
                "error": bilingual_text(
                    "删除控制台会话同步失败",
                    &format!("failed to delete synced console session: {message}")
                )
            })),
        )
            .into_response(),
    }
}

#[derive(Debug)]
struct ExternalIdentityProfile {
    username: String,
    role: String,
    display_name: String,
    groups: Vec<String>,
    provider: String,
    subject: Option<String>,
    audience: Option<String>,
}

#[derive(Debug, Default)]
struct ExternalIdentityClaimOverrides {
    username_claim: Option<String>,
    groups_claim: Option<String>,
    role_claim: Option<String>,
    default_role: Option<String>,
    group_role_map: Option<String>,
    display_name_claim: Option<String>,
    subject_claim: Option<String>,
    audience_claim: Option<String>,
    provider_name: Option<String>,
}

#[derive(Debug, Deserialize)]
struct OidcDiscoveryDocument {
    issuer: String,
    jwks_uri: String,
    authorization_endpoint: String,
    token_endpoint: String,
    #[serde(default)]
    id_token_signing_alg_values_supported: Vec<String>,
}

#[derive(Debug, Deserialize)]
struct OidcTokenResponse {
    #[serde(default)]
    id_token: String,
}

#[derive(Debug, Deserialize)]
struct OidcCallbackQuery {
    code: Option<String>,
    state: Option<String>,
    error: Option<String>,
    error_description: Option<String>,
}

#[derive(Debug)]
struct LdapIdentityRecord {
    username: String,
    display_name: String,
    groups: Vec<String>,
}

fn env_trimmed(key: &str) -> Option<String> {
    std::env::var(key)
        .ok()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
}

fn normalize_role_name(role: &str) -> Option<String> {
    match role.trim().to_ascii_lowercase().as_str() {
        "admin" => Some("admin".to_string()),
        "operator" => Some("operator".to_string()),
        "auditor" => Some("auditor".to_string()),
        "viewer" => Some("viewer".to_string()),
        _ => None,
    }
}

type RoleMappings = Vec<(String, String)>;

fn parse_role_mapping(raw: Option<String>) -> RoleMappings {
    raw.unwrap_or_default()
        .split([',', ';'])
        .filter_map(|entry| {
            let mut split = entry.splitn(2, '=');
            let key = split.next()?.trim().to_ascii_lowercase();
            let value = normalize_role_name(split.next()?.trim())?;
            (!key.is_empty()).then_some((key, value))
        })
        .collect()
}

fn resolve_external_role(
    explicit_role: Option<String>,
    groups: &[String],
    mappings: &RoleMappings,
    default_role: &str,
) -> String {
    if let Some(role) = explicit_role.as_deref().and_then(normalize_role_name) {
        return role;
    }
    let normalized_groups = groups
        .iter()
        .map(|group| group.trim().to_ascii_lowercase())
        .filter(|group| !group.is_empty())
        .collect::<HashSet<_>>();
    for (group_name, role) in mappings {
        if normalized_groups.contains(group_name) {
            return role.clone();
        }
    }
    normalize_role_name(default_role).unwrap_or_else(|| "viewer".to_string())
}

fn json_value_by_path<'a>(value: &'a Value, path: &str) -> Option<&'a Value> {
    let mut current = value;
    for segment in path.split('.').filter(|segment| !segment.is_empty()) {
        current = current.get(segment)?;
    }
    Some(current)
}

fn json_string_by_path(value: &Value, path: &str) -> Option<String> {
    match json_value_by_path(value, path) {
        Some(Value::String(text)) => Some(text.trim().to_string()).filter(|text| !text.is_empty()),
        Some(Value::Number(number)) => Some(number.to_string()),
        Some(Value::Bool(flag)) => Some(flag.to_string()),
        _ => None,
    }
}

fn json_string_list_by_path(value: &Value, path: &str) -> Vec<String> {
    match json_value_by_path(value, path) {
        Some(Value::String(text)) => {
            let trimmed = text.trim();
            (!trimmed.is_empty())
                .then_some(trimmed.to_string())
                .into_iter()
                .collect()
        }
        Some(Value::Array(items)) => items
            .iter()
            .filter_map(|item| match item {
                Value::String(text) => Some(text.trim().to_string()),
                Value::Number(number) => Some(number.to_string()),
                _ => None,
            })
            .filter(|item| !item.is_empty())
            .collect(),
        _ => Vec::new(),
    }
}

fn parse_algorithm_name(value: &str) -> Option<Algorithm> {
    match value.trim().to_ascii_uppercase().as_str() {
        "HS256" => Some(Algorithm::HS256),
        "HS384" => Some(Algorithm::HS384),
        "HS512" => Some(Algorithm::HS512),
        "RS256" => Some(Algorithm::RS256),
        "RS384" => Some(Algorithm::RS384),
        "RS512" => Some(Algorithm::RS512),
        "PS256" => Some(Algorithm::PS256),
        "PS384" => Some(Algorithm::PS384),
        "PS512" => Some(Algorithm::PS512),
        "ES256" => Some(Algorithm::ES256),
        "ES384" => Some(Algorithm::ES384),
        "EDDSA" => Some(Algorithm::EdDSA),
        _ => None,
    }
}

fn configured_text(configured: &str, env_key: &str) -> Option<String> {
    let configured = configured.trim();
    if !configured.is_empty() {
        return Some(configured.to_string());
    }
    env_trimmed(env_key)
}

fn configured_text_env_first(configured: &str, env_key: &str) -> Option<String> {
    env_trimmed(env_key).or_else(|| {
        let configured = configured.trim();
        (!configured.is_empty()).then_some(configured.to_string())
    })
}

fn configured_or_default_env_first(configured: &str, env_key: &str, default: &str) -> String {
    configured_text_env_first(configured, env_key).unwrap_or_else(|| default.to_string())
}

fn oidc_discovery_url(security: &rustio_core::SecurityConfig) -> Option<String> {
    configured_text(&security.oidc_discovery_url, "RUSTIO_OIDC_DISCOVERY_URL").or_else(|| {
        configured_text(&security.oidc_issuer, "RUSTIO_OIDC_ISSUER").map(|issuer| {
            format!(
                "{}/.well-known/openid-configuration",
                issuer.trim_end_matches('/')
            )
        })
    })
}

fn oidc_jwks_url_override(security: &rustio_core::SecurityConfig) -> Option<String> {
    configured_text(&security.oidc_jwks_url, "RUSTIO_OIDC_JWKS_URL")
}

fn oidc_expected_issuer(
    security: &rustio_core::SecurityConfig,
    discovery: &OidcDiscoveryDocument,
) -> String {
    configured_text(&security.oidc_issuer, "RUSTIO_OIDC_ISSUER")
        .unwrap_or_else(|| discovery.issuer.clone())
}

fn oidc_client_id(security: &rustio_core::SecurityConfig) -> Option<String> {
    configured_text(&security.oidc_client_id, "RUSTIO_OIDC_CLIENT_ID")
}

fn oidc_client_secret() -> Option<String> {
    env_trimmed("RUSTIO_OIDC_CLIENT_SECRET")
}

fn oidc_missing_requirements(security: &rustio_core::SecurityConfig) -> Vec<String> {
    let mut missing = Vec::new();
    if oidc_discovery_url(security).is_none() {
        missing.push("oidc_discovery_url".to_string());
    }
    if oidc_client_id(security).is_none() {
        missing.push("oidc_client_id".to_string());
    }
    missing
}

fn ensure_oidc_login_available(
    security: &rustio_core::SecurityConfig,
) -> Result<Vec<String>, AppError> {
    if !security.oidc_enabled {
        return Err(AppError::forbidden(
            "OIDC 登录未启用 / oidc login is disabled",
        ));
    }
    let missing = oidc_missing_requirements(security);
    if !missing.is_empty() {
        let joined = missing.join(", ");
        return Err(AppError::forbidden(format!(
            "OIDC 登录未完成配置，缺少 {} / oidc login is not fully configured, missing {}",
            joined, joined
        )));
    }
    Ok(missing)
}

fn oidc_browser_scopes() -> String {
    env_trimmed("RUSTIO_OIDC_SCOPES").unwrap_or_else(|| "openid profile email".to_string())
}

fn oidc_username_claim(security: &rustio_core::SecurityConfig) -> String {
    configured_or_default_env_first(
        &security.oidc_username_claim,
        "RUSTIO_OIDC_USERNAME_CLAIM",
        "preferred_username",
    )
}

fn oidc_groups_claim(security: &rustio_core::SecurityConfig) -> String {
    configured_or_default_env_first(
        &security.oidc_groups_claim,
        "RUSTIO_OIDC_GROUPS_CLAIM",
        "groups",
    )
}

fn oidc_role_claim(security: &rustio_core::SecurityConfig) -> String {
    configured_or_default_env_first(&security.oidc_role_claim, "RUSTIO_OIDC_ROLE_CLAIM", "role")
}

fn oidc_default_role(security: &rustio_core::SecurityConfig) -> String {
    configured_text_env_first(&security.oidc_default_role, "RUSTIO_OIDC_DEFAULT_ROLE")
        .and_then(|role| normalize_role_name(&role))
        .unwrap_or_else(|| "viewer".to_string())
}

fn oidc_role_mapping(security: &rustio_core::SecurityConfig) -> RoleMappings {
    parse_role_mapping(configured_text(
        &security.oidc_group_role_map,
        "RUSTIO_OIDC_GROUP_ROLE_MAP",
    ))
}

fn oidc_allowed_algorithms(
    security: &rustio_core::SecurityConfig,
    discovery: &OidcDiscoveryDocument,
) -> Vec<Algorithm> {
    configured_text(&security.oidc_allowed_algs, "RUSTIO_OIDC_ALLOWED_ALGS")
        .map(|raw| {
            raw.split([',', ';'])
                .filter_map(parse_algorithm_name)
                .collect::<Vec<_>>()
        })
        .filter(|items| !items.is_empty())
        .unwrap_or_else(|| {
            discovery
                .id_token_signing_alg_values_supported
                .iter()
                .filter_map(|value| parse_algorithm_name(value))
                .collect::<Vec<_>>()
        })
}

fn oidc_console_callback_path() -> &'static str {
    "/login/oidc/callback"
}

fn url_encode_component(value: &str) -> String {
    utf8_percent_encode(value, NON_ALPHANUMERIC).to_string()
}

fn request_origin(headers: &HeaderMap) -> Result<String, AppError> {
    let host = headers
        .get("x-forwarded-host")
        .or_else(|| headers.get(HOST))
        .and_then(|value| value.to_str().ok())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| AppError::bad_request("缺少 Host 请求头 / missing host header"))?;
    let scheme = headers
        .get("x-forwarded-proto")
        .and_then(|value| value.to_str().ok())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("http");
    Ok(format!("{scheme}://{host}"))
}

fn oidc_backend_callback_url(headers: &HeaderMap) -> Result<String, AppError> {
    Ok(format!(
        "{}{}",
        request_origin(headers)?,
        "/api/v1/auth/oidc/callback"
    ))
}

fn oidc_callback_redirect_target(request_id: Option<&str>, error: Option<&str>) -> String {
    let mut target = oidc_console_callback_path().to_string();
    let mut query = Vec::new();
    if let Some(request_id) = request_id.filter(|value| !value.is_empty()) {
        query.push(format!("request_id={}", url_encode_component(request_id)));
    }
    if let Some(error) = error.filter(|value| !value.is_empty()) {
        query.push(format!("error={}", url_encode_component(error)));
    }
    if !query.is_empty() {
        target.push('?');
        target.push_str(&query.join("&"));
    }
    target
}

fn oidc_pkce_verifier() -> String {
    let entropy = format!(
        "{}-{}-{}",
        Uuid::new_v4(),
        Uuid::new_v4(),
        Utc::now().timestamp_nanos_opt().unwrap_or_default()
    );
    let digest = Sha256::digest(entropy.as_bytes());
    URL_SAFE_NO_PAD.encode(digest)
}

fn oidc_pkce_challenge(verifier: &str) -> String {
    URL_SAFE_NO_PAD.encode(Sha256::digest(verifier.as_bytes()))
}

async fn purge_stale_oidc_browser_state(state: &AppState) {
    let expires_before = Utc::now() - Duration::minutes(10);
    state
        .oidc_auth_requests
        .write()
        .await
        .retain(|_, item| item.created_at >= expires_before);
    state
        .oidc_completed_logins
        .write()
        .await
        .retain(|_, item| item.created_at >= expires_before);
}

async fn fetch_json_document<T: DeserializeOwned>(
    client: &Client,
    url: &str,
) -> Result<T, AppError> {
    let response = client.get(url).send().await.map_err(|err| {
        AppError::internal(format!(
            "访问外部身份提供方失败 / failed to reach external identity provider: {err}"
        ))
    })?;
    if !response.status().is_success() {
        return Err(AppError::internal(format!(
            "外部身份提供方返回异常状态 / external identity provider returned unexpected status: {}",
            response.status()
        )));
    }
    response.json::<T>().await.map_err(|err| {
        AppError::internal(format!(
            "解析外部身份响应失败 / failed to decode external identity response: {err}"
        ))
    })
}

async fn decode_oidc_claims(
    security: &rustio_core::SecurityConfig,
    id_token: &str,
    expected_nonce: Option<&str>,
) -> Result<Value, AppError> {
    ensure_oidc_login_available(security)?;
    let id_token = id_token.trim();
    if id_token.is_empty() {
        return Err(AppError::bad_request(
            "OIDC ID Token 不能为空 / oidc id token cannot be empty",
        ));
    }
    let discovery_url = oidc_discovery_url(security).ok_or_else(|| {
        AppError::internal("OIDC Discovery 地址未配置 / oidc discovery url is not configured")
    })?;
    let client = Client::new();
    let discovery = fetch_json_document::<OidcDiscoveryDocument>(&client, &discovery_url).await?;
    let expected_issuer = oidc_expected_issuer(security, &discovery);
    let jwks_url = oidc_jwks_url_override(security).unwrap_or_else(|| discovery.jwks_uri.clone());
    let jwks = fetch_json_document::<JwkSet>(&client, &jwks_url).await?;

    let header = decode_header(id_token).map_err(|err| {
        AppError::unauthorized(format!(
            "OIDC Token 头解析失败 / failed to decode oidc token header: {err}"
        ))
    })?;
    let allowed_algs = oidc_allowed_algorithms(security, &discovery);
    if !allowed_algs.is_empty() && !allowed_algs.contains(&header.alg) {
        return Err(AppError::unauthorized(format!(
            "OIDC Token 签名算法不受支持 / oidc token signing algorithm is unsupported: {:?}",
            header.alg
        )));
    }
    let jwk = header
        .kid
        .as_deref()
        .and_then(|kid| jwks.find(kid))
        .or_else(|| (jwks.keys.len() == 1).then_some(&jwks.keys[0]))
        .ok_or_else(|| {
            AppError::unauthorized(
                "OIDC Token 未匹配到签名密钥 / oidc token signing key was not found",
            )
        })?;
    let decoding_key = DecodingKey::from_jwk(jwk).map_err(|err| {
        AppError::unauthorized(format!(
            "OIDC 签名密钥无效 / oidc signing key is invalid: {err}"
        ))
    })?;

    let mut validation = Validation::new(header.alg);
    validation.validate_nbf = true;
    validation.set_issuer(&[expected_issuer]);
    if let Some(client_id) = oidc_client_id(security) {
        validation.set_audience(&[client_id]);
    } else {
        validation.validate_aud = false;
    }

    let claims = jwt_decode::<Value>(id_token, &decoding_key, &validation)
        .map_err(|err| {
            AppError::unauthorized(format!(
                "OIDC Token 校验失败 / oidc token validation failed: {err}"
            ))
        })?
        .claims;
    if let Some(expected_nonce) = expected_nonce.filter(|value| !value.trim().is_empty()) {
        let actual_nonce = json_string_by_path(&claims, "nonce").unwrap_or_default();
        if actual_nonce != expected_nonce {
            return Err(AppError::unauthorized(
                "OIDC Token nonce 不匹配 / oidc token nonce does not match",
            ));
        }
    }
    Ok(claims)
}

fn external_identity_profile_from_oidc_claims(
    security: &rustio_core::SecurityConfig,
    claims: &Value,
    overrides: &ExternalIdentityClaimOverrides,
) -> Result<ExternalIdentityProfile, AppError> {
    let username_claim = overrides
        .username_claim
        .clone()
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| oidc_username_claim(security));
    let groups_claim = overrides
        .groups_claim
        .clone()
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| oidc_groups_claim(security));
    let role_claim = overrides
        .role_claim
        .clone()
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| oidc_role_claim(security));
    let default_role = overrides
        .default_role
        .clone()
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| oidc_default_role(security));
    let role_mapping = overrides
        .group_role_map
        .clone()
        .filter(|value| !value.trim().is_empty())
        .map(|value| parse_role_mapping(Some(value)))
        .unwrap_or_else(|| oidc_role_mapping(security));
    let display_name_claim = overrides
        .display_name_claim
        .clone()
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| "name".to_string());
    let subject_claim = overrides
        .subject_claim
        .clone()
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| "sub".to_string());
    let audience_claim = overrides
        .audience_claim
        .clone()
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| "aud".to_string());

    let username = json_string_by_path(claims, &username_claim)
        .or_else(|| json_string_by_path(&claims, "email"))
        .or_else(|| json_string_by_path(&claims, "sub"))
        .filter(|value| !value.is_empty())
        .ok_or_else(|| {
            AppError::unauthorized(
                "OIDC Token 缺少主体标识 / oidc token does not contain a principal identifier",
            )
        })?;
    let groups = json_string_list_by_path(claims, &groups_claim);
    let role = resolve_external_role(
        json_string_by_path(claims, &role_claim),
        &groups,
        &role_mapping,
        &default_role,
    );
    let display_name = json_string_by_path(claims, &display_name_claim)
        .or_else(|| json_string_by_path(claims, "display_name"))
        .unwrap_or_else(|| username.clone());

    Ok(ExternalIdentityProfile {
        username,
        role,
        display_name,
        groups,
        provider: overrides
            .provider_name
            .clone()
            .filter(|value| !value.trim().is_empty())
            .unwrap_or_else(|| "oidc".to_string()),
        subject: json_string_by_path(claims, &subject_claim)
            .or_else(|| json_string_by_path(claims, "sub")),
        audience: json_string_by_path(claims, &audience_claim).or_else(|| {
            json_string_list_by_path(claims, &audience_claim)
                .into_iter()
                .next()
        }),
    })
}

async fn authenticate_oidc_token(
    security: &rustio_core::SecurityConfig,
    id_token: &str,
    expected_nonce: Option<&str>,
) -> Result<ExternalIdentityProfile, AppError> {
    let claims = decode_oidc_claims(security, id_token, expected_nonce).await?;
    external_identity_profile_from_oidc_claims(
        security,
        &claims,
        &ExternalIdentityClaimOverrides::default(),
    )
}

async fn authenticate_oidc_identity(
    security: &rustio_core::SecurityConfig,
    body: &LoginRequest,
) -> Result<ExternalIdentityProfile, AppError> {
    let id_token = body
        .id_token
        .as_deref()
        .map(str::trim)
        .filter(|token| !token.is_empty())
        .ok_or_else(|| {
            AppError::bad_request("OIDC ID Token 不能为空 / oidc id token cannot be empty")
        })?;
    authenticate_oidc_token(security, id_token, None).await
}

fn oidc_callback_error_response(message: &str) -> Response {
    Redirect::temporary(&oidc_callback_redirect_target(None, Some(message))).into_response()
}

fn append_query_to_url(base: &str, query: &str) -> String {
    let separator = if base.contains('?') { '&' } else { '?' };
    format!("{base}{separator}{query}")
}

async fn exchange_oidc_authorization_code(
    security: &rustio_core::SecurityConfig,
    client: &Client,
    discovery: &OidcDiscoveryDocument,
    code: &str,
    redirect_uri: &str,
    code_verifier: &str,
) -> Result<OidcTokenResponse, AppError> {
    let client_id = oidc_client_id(security).ok_or_else(|| {
        AppError::internal("OIDC Client ID 未配置 / oidc client id is not configured")
    })?;
    if discovery.token_endpoint.trim().is_empty() {
        return Err(AppError::internal(
            "OIDC Token Endpoint 未配置 / oidc token endpoint is not configured",
        ));
    }

    let mut form = vec![
        ("grant_type", "authorization_code".to_string()),
        ("code", code.to_string()),
        ("redirect_uri", redirect_uri.to_string()),
        ("client_id", client_id),
        ("code_verifier", code_verifier.to_string()),
    ];
    if let Some(secret) = oidc_client_secret() {
        form.push(("client_secret", secret));
    }

    let response = client
        .post(&discovery.token_endpoint)
        .form(&form)
        .send()
        .await
        .map_err(|err| {
            AppError::internal(format!(
                "请求 OIDC Token Endpoint 失败 / failed to request oidc token endpoint: {err}"
            ))
        })?;
    if !response.status().is_success() {
        let status = response.status();
        let body = response.text().await.unwrap_or_default();
        return Err(AppError::unauthorized(format!(
            "OIDC 授权码换取令牌失败 / oidc authorization code exchange failed: {status} {}",
            body.trim()
        )));
    }

    response.json::<OidcTokenResponse>().await.map_err(|err| {
        AppError::internal(format!(
            "解析 OIDC Token 响应失败 / failed to decode oidc token response: {err}"
        ))
    })
}

async fn begin_oidc_browser_login(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
) -> Result<Redirect, AppError> {
    purge_stale_oidc_browser_state(&state).await;
    let security = state.security.read().await.clone();
    ensure_oidc_login_available(&security)?;

    let discovery_url = oidc_discovery_url(&security).ok_or_else(|| {
        AppError::internal("OIDC Discovery 地址未配置 / oidc discovery url is not configured")
    })?;
    let client_id = oidc_client_id(&security).ok_or_else(|| {
        AppError::internal("OIDC Client ID 未配置 / oidc client id is not configured")
    })?;
    let client = Client::new();
    let discovery = fetch_json_document::<OidcDiscoveryDocument>(&client, &discovery_url).await?;
    if discovery.authorization_endpoint.trim().is_empty() {
        return Err(AppError::internal(
            "OIDC Authorization Endpoint 未配置 / oidc authorization endpoint is not configured",
        ));
    }

    let callback_url = oidc_backend_callback_url(&headers)?;
    let auth_request_id = format!("oidc-{}", Uuid::new_v4().simple());
    let nonce = Uuid::new_v4().simple().to_string();
    let code_verifier = oidc_pkce_verifier();
    let code_challenge = oidc_pkce_challenge(&code_verifier);
    state.oidc_auth_requests.write().await.insert(
        auth_request_id.clone(),
        PendingOidcAuthorization {
            code_verifier,
            nonce: nonce.clone(),
            created_at: Utc::now(),
        },
    );

    let query = [
        format!("response_type={}", url_encode_component("code")),
        format!("client_id={}", url_encode_component(&client_id)),
        format!("redirect_uri={}", url_encode_component(&callback_url)),
        format!("scope={}", url_encode_component(&oidc_browser_scopes())),
        format!("state={}", url_encode_component(&auth_request_id)),
        format!("nonce={}", url_encode_component(&nonce)),
        format!("code_challenge={}", url_encode_component(&code_challenge)),
        format!("code_challenge_method={}", url_encode_component("S256")),
    ]
    .join("&");
    Ok(Redirect::temporary(&append_query_to_url(
        &discovery.authorization_endpoint,
        &query,
    )))
}

async fn complete_oidc_browser_login(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
    Query(query): Query<OidcCallbackQuery>,
) -> Response {
    purge_stale_oidc_browser_state(&state).await;

    if let Some(error) = query
        .error
        .as_deref()
        .filter(|value| !value.trim().is_empty())
    {
        let description = query
            .error_description
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .unwrap_or(error);
        return oidc_callback_error_response(&format!(
            "OIDC 浏览器登录失败 / oidc browser login failed: {description}"
        ));
    }

    let state_id = match query
        .state
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        Some(value) => value.to_string(),
        None => {
            return oidc_callback_error_response(
                "OIDC 回调缺少 state / oidc callback is missing state",
            )
        }
    };
    let code = match query
        .code
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        Some(value) => value.to_string(),
        None => {
            return oidc_callback_error_response(
                "OIDC 回调缺少 code / oidc callback is missing authorization code",
            )
        }
    };

    let pending = match state.oidc_auth_requests.write().await.remove(&state_id) {
        Some(item) => item,
        None => {
            return oidc_callback_error_response(
                "OIDC 登录状态不存在或已过期 / oidc login state does not exist or has expired",
            )
        }
    };
    let security = state.security.read().await.clone();
    if let Err(err) = ensure_oidc_login_available(&security) {
        return oidc_callback_error_response(&err.message);
    }
    let discovery_url = match oidc_discovery_url(&security) {
        Some(value) => value,
        None => {
            return oidc_callback_error_response(
                "OIDC Discovery 地址未配置 / oidc discovery url is not configured",
            )
        }
    };
    let callback_url = match oidc_backend_callback_url(&headers) {
        Ok(value) => value,
        Err(err) => return oidc_callback_error_response(&err.message),
    };
    let client = Client::new();
    let discovery =
        match fetch_json_document::<OidcDiscoveryDocument>(&client, &discovery_url).await {
            Ok(value) => value,
            Err(err) => return oidc_callback_error_response(&err.message),
        };
    let token_response = match exchange_oidc_authorization_code(
        &security,
        &client,
        &discovery,
        &code,
        &callback_url,
        &pending.code_verifier,
    )
    .await
    {
        Ok(value) => value,
        Err(err) => return oidc_callback_error_response(&err.message),
    };
    if token_response.id_token.trim().is_empty() {
        return oidc_callback_error_response(
            "OIDC Token 响应缺少 ID Token / oidc token response does not contain id token",
        );
    }

    let profile =
        match authenticate_oidc_token(&security, &token_response.id_token, Some(&pending.nonce))
            .await
        {
            Ok(value) => value,
            Err(err) => return oidc_callback_error_response(&err.message),
        };
    if let Err(err) = sync_external_identity_profile(&state, &profile).await {
        return oidc_callback_error_response(&err.message);
    }
    let (response, session) = match create_console_login_response(
        state.as_ref(),
        &profile.username,
        &profile.role,
        "oidc",
    )
    .await
    {
        Ok(value) => value,
        Err(err) => return oidc_callback_error_response(&err.message),
    };

    let completed_request_id = format!("oidc-session-{}", Uuid::new_v4().simple());
    state.oidc_completed_logins.write().await.insert(
        completed_request_id.clone(),
        CompletedOidcLogin {
            response,
            created_at: Utc::now(),
        },
    );
    state
        .append_runtime_audit(
            &profile.username,
            "auth.login.oidc.browser",
            "session",
            "success",
            None,
            json!({
                "role": profile.role,
                "groups": profile.groups,
                "provider": profile.provider,
                "session_id": session.session_id,
                "redirect": "console"
            }),
        )
        .await;

    Redirect::temporary(&oidc_callback_redirect_target(
        Some(&completed_request_id),
        None,
    ))
    .into_response()
}

async fn redeem_oidc_browser_login(
    State(state): State<Arc<AppState>>,
    Path(request_id): Path<String>,
) -> Result<Json<ApiEnvelope<rustio_core::LoginResponse>>, AppError> {
    purge_stale_oidc_browser_state(&state).await;
    let completed = state
        .oidc_completed_logins
        .write()
        .await
        .remove(&request_id)
        .ok_or_else(|| {
            AppError::not_found(
                "OIDC 登录会话不存在或已过期 / oidc login session does not exist or has expired",
            )
        })?;
    Ok(wrap(completed.response))
}

fn ldap_url(security: &rustio_core::SecurityConfig) -> Option<String> {
    configured_text(&security.ldap_url, "RUSTIO_LDAP_URL")
}

fn ldap_bind_dn(security: &rustio_core::SecurityConfig) -> Option<String> {
    configured_text(&security.ldap_bind_dn, "RUSTIO_LDAP_BIND_DN")
}

fn ldap_bind_password(_security: &rustio_core::SecurityConfig) -> Option<String> {
    env_trimmed("RUSTIO_LDAP_BIND_PASSWORD")
}

fn ldap_missing_requirements(security: &rustio_core::SecurityConfig) -> Vec<String> {
    let mut missing = Vec::new();
    if ldap_url(security).is_none() {
        missing.push("ldap_url".to_string());
    }
    if ldap_user_base_dn(security).is_none() {
        missing.push("ldap_user_base_dn".to_string());
    }
    missing
}

fn ensure_ldap_login_available(
    security: &rustio_core::SecurityConfig,
) -> Result<Vec<String>, AppError> {
    if !security.ldap_enabled {
        return Err(AppError::forbidden(
            "LDAP 登录未启用 / ldap login is disabled",
        ));
    }
    let missing = ldap_missing_requirements(security);
    if !missing.is_empty() {
        let joined = missing.join(", ");
        return Err(AppError::forbidden(format!(
            "LDAP 登录未完成配置，缺少 {} / ldap login is not fully configured, missing {}",
            joined, joined
        )));
    }
    Ok(missing)
}

fn ldap_user_base_dn(security: &rustio_core::SecurityConfig) -> Option<String> {
    configured_text(&security.ldap_user_base_dn, "RUSTIO_LDAP_USER_BASE_DN")
}

fn ldap_user_filter_template(security: &rustio_core::SecurityConfig) -> String {
    configured_or_default_env_first(
        &security.ldap_user_filter,
        "RUSTIO_LDAP_USER_FILTER",
        "(uid={username})",
    )
}

fn ldap_group_base_dn(security: &rustio_core::SecurityConfig) -> Option<String> {
    configured_text(&security.ldap_group_base_dn, "RUSTIO_LDAP_GROUP_BASE_DN")
}

fn ldap_group_filter_template(security: &rustio_core::SecurityConfig) -> String {
    configured_or_default_env_first(
        &security.ldap_group_filter,
        "RUSTIO_LDAP_GROUP_FILTER",
        "(member={user_dn})",
    )
}

fn ldap_group_attribute(security: &rustio_core::SecurityConfig) -> String {
    configured_or_default_env_first(
        &security.ldap_group_attribute,
        "RUSTIO_LDAP_GROUP_ATTRIBUTE",
        "memberOf",
    )
}

fn ldap_group_name_attribute(security: &rustio_core::SecurityConfig) -> String {
    configured_or_default_env_first(
        &security.ldap_group_name_attribute,
        "RUSTIO_LDAP_GROUP_NAME_ATTRIBUTE",
        "cn",
    )
}

fn ldap_default_role(security: &rustio_core::SecurityConfig) -> String {
    configured_text_env_first(&security.ldap_default_role, "RUSTIO_LDAP_DEFAULT_ROLE")
        .and_then(|role| normalize_role_name(&role))
        .unwrap_or_else(|| "viewer".to_string())
}

fn ldap_role_mapping(security: &rustio_core::SecurityConfig) -> RoleMappings {
    parse_role_mapping(configured_text(
        &security.ldap_group_role_map,
        "RUSTIO_LDAP_GROUP_ROLE_MAP",
    ))
}

fn ldap_escape_filter_value(value: &str) -> String {
    let mut escaped = String::new();
    for byte in value.as_bytes() {
        match byte {
            b'*' => escaped.push_str("\\2a"),
            b'(' => escaped.push_str("\\28"),
            b')' => escaped.push_str("\\29"),
            b'\\' => escaped.push_str("\\5c"),
            0 => escaped.push_str("\\00"),
            _ => escaped.push(*byte as char),
        }
    }
    escaped
}

fn render_ldap_filter(template: &str, username: &str, user_dn: &str) -> String {
    template
        .replace("{username}", &ldap_escape_filter_value(username))
        .replace("{user_dn}", &ldap_escape_filter_value(user_dn))
}

fn ldap_group_name_from_dn(dn: &str, attribute_name: &str) -> Option<String> {
    let attribute_name = if attribute_name.trim().is_empty() {
        "cn"
    } else {
        attribute_name.trim()
    };
    dn.split(',').find_map(|segment| {
        let mut split = segment.trim().splitn(2, '=');
        let key = split.next()?.trim();
        let value = split.next()?.trim();
        key.eq_ignore_ascii_case(attribute_name)
            .then_some(value.to_string())
    })
}

fn ldap_search_single_user(
    ldap: &mut LdapConn,
    security: &rustio_core::SecurityConfig,
    username: &str,
) -> Result<SearchEntry, AppError> {
    let base_dn = ldap_user_base_dn(security).ok_or_else(|| {
        AppError::internal("LDAP 用户 Base DN 未配置 / ldap user base dn is not configured")
    })?;
    let group_attr = ldap_group_attribute(security);
    let (entries, _result) = ldap
        .search(
            &base_dn,
            Scope::Subtree,
            &render_ldap_filter(&ldap_user_filter_template(security), username, ""),
            vec!["uid", "dn", "cn", "displayName", group_attr.as_str()],
        )
        .map_err(|err| {
            AppError::internal(format!(
                "执行 LDAP 用户查询失败 / failed to execute ldap user search: {err}"
            ))
        })?
        .success()
        .map_err(|err| {
            AppError::unauthorized(format!(
                "LDAP 用户查询被拒绝 / ldap user search was rejected: {err}"
            ))
        })?;
    entries
        .into_iter()
        .next()
        .map(SearchEntry::construct)
        .ok_or_else(|| AppError::unauthorized("LDAP 用户不存在 / ldap user does not exist"))
}

fn ldap_collect_groups(
    ldap: &mut LdapConn,
    security: &rustio_core::SecurityConfig,
    user_entry: &SearchEntry,
) -> Result<Vec<String>, AppError> {
    let group_attr = ldap_group_attribute(security);
    let group_name_attr = ldap_group_name_attribute(security);
    let mut groups = user_entry
        .attrs
        .get(&group_attr)
        .cloned()
        .unwrap_or_default()
        .into_iter()
        .filter_map(|value| ldap_group_name_from_dn(&value, &group_name_attr).or(Some(value)))
        .filter(|value| !value.is_empty())
        .collect::<Vec<_>>();

    if groups.is_empty() {
        if let Some(group_base_dn) = ldap_group_base_dn(security) {
            let (entries, _result) = ldap
                .search(
                    &group_base_dn,
                    Scope::Subtree,
                    &render_ldap_filter(
                        &ldap_group_filter_template(security),
                        &user_entry.dn,
                        &user_entry.dn,
                    ),
                    vec!["dn", group_name_attr.as_str()],
                )
                .map_err(|err| {
                    AppError::internal(format!(
                        "执行 LDAP 用户组查询失败 / failed to execute ldap group search: {err}"
                    ))
                })?
                .success()
                .map_err(|err| {
                    AppError::unauthorized(format!(
                        "LDAP 用户组查询被拒绝 / ldap group search was rejected: {err}"
                    ))
                })?;
            for entry in entries.into_iter().map(SearchEntry::construct) {
                if let Some(values) = entry.attrs.get(&group_name_attr) {
                    groups.extend(values.iter().filter(|value| !value.is_empty()).cloned());
                } else if let Some(name) = ldap_group_name_from_dn(&entry.dn, &group_name_attr) {
                    groups.push(name);
                }
            }
        }
    }

    groups.sort();
    groups.dedup();
    Ok(groups)
}

fn authenticate_ldap_identity_blocking(
    username: String,
    password: String,
    security: rustio_core::SecurityConfig,
) -> Result<ExternalIdentityProfile, AppError> {
    let url = ldap_url(&security)
        .ok_or_else(|| AppError::internal("LDAP 地址未配置 / ldap url is not configured"))?;

    let mut lookup_ldap = LdapConn::new(&url).map_err(|err| {
        AppError::internal(format!("连接 LDAP 失败 / failed to connect to ldap: {err}"))
    })?;
    if let Some(bind_dn) = ldap_bind_dn(&security) {
        let bind_password = ldap_bind_password(&security).unwrap_or_default();
        lookup_ldap
            .simple_bind(&bind_dn, &bind_password)
            .map_err(|err| {
                AppError::internal(format!(
                    "LDAP 管理绑定失败 / ldap administrative bind failed: {err}"
                ))
            })?
            .success()
            .map_err(|err| {
                AppError::internal(format!(
                    "LDAP 管理绑定被拒绝 / ldap administrative bind was rejected: {err}"
                ))
            })?;
    }
    let user_entry = ldap_search_single_user(&mut lookup_ldap, &security, &username)?;
    let user_dn = user_entry.dn.clone();

    let mut user_ldap = LdapConn::new(&url).map_err(|err| {
        AppError::internal(format!(
            "建立 LDAP 用户会话失败 / failed to establish ldap user session: {err}"
        ))
    })?;
    user_ldap
        .simple_bind(&user_dn, &password)
        .map_err(|err| {
            AppError::unauthorized(format!("LDAP 用户绑定失败 / ldap user bind failed: {err}"))
        })?
        .success()
        .map_err(|err| {
            AppError::unauthorized(format!(
                "LDAP 用户名或密码无效 / ldap username or password is invalid: {err}"
            ))
        })?;

    let groups = ldap_collect_groups(&mut lookup_ldap, &security, &user_entry)?;
    let display_name = user_entry
        .attrs
        .get("displayName")
        .and_then(|values| values.first().cloned())
        .or_else(|| {
            user_entry
                .attrs
                .get("cn")
                .and_then(|values| values.first().cloned())
        })
        .unwrap_or_else(|| username.clone());
    let record = LdapIdentityRecord {
        username: user_entry
            .attrs
            .get("uid")
            .and_then(|values| values.first().cloned())
            .unwrap_or(username),
        display_name,
        groups,
    };

    let _ = user_ldap.unbind();
    let _ = lookup_ldap.unbind();

    Ok(ExternalIdentityProfile {
        username: record.username,
        role: resolve_external_role(
            None,
            &record.groups,
            &ldap_role_mapping(&security),
            &ldap_default_role(&security),
        ),
        display_name: record.display_name,
        groups: record.groups,
        provider: "ldap".to_string(),
        subject: None,
        audience: None,
    })
}

async fn authenticate_ldap_identity(
    security: &rustio_core::SecurityConfig,
    body: &LoginRequest,
) -> Result<ExternalIdentityProfile, AppError> {
    ensure_ldap_login_available(security)?;
    let username = body.username.trim().to_string();
    if username.is_empty() {
        return Err(AppError::bad_request(
            "LDAP 用户名不能为空 / ldap username cannot be empty",
        ));
    }
    let password = body.password.clone();
    if password.trim().is_empty() {
        return Err(AppError::bad_request(
            "LDAP 密码不能为空 / ldap password cannot be empty",
        ));
    }
    let security = security.clone();
    tokio::task::spawn_blocking(move || {
        authenticate_ldap_identity_blocking(username, password, security)
    })
    .await
    .map_err(|err| {
        AppError::internal(format!(
            "LDAP 认证任务失败 / ldap authentication task failed: {err}"
        ))
    })?
}

async fn sync_external_identity_profile(
    state: &AppState,
    profile: &ExternalIdentityProfile,
) -> Result<(), AppError> {
    let rollback = capture_iam_runtime_snapshot(state).await;
    {
        let mut users = state.users.write().await;
        if let Some(user) = users
            .iter_mut()
            .find(|user| user.username == profile.username)
        {
            if !user.enabled {
                return Err(AppError::unauthorized("用户已禁用 / user is disabled"));
            }
            user.display_name = profile.display_name.clone();
            user.role = profile.role.clone();
        } else {
            users.push(IamUser {
                username: profile.username.clone(),
                display_name: profile.display_name.clone(),
                role: profile.role.clone(),
                enabled: true,
                created_at: Utc::now(),
            });
        }
    }

    {
        let desired_groups = profile
            .groups
            .iter()
            .map(|group_name| group_name.trim())
            .filter(|group_name| !group_name.is_empty())
            .map(str::to_string)
            .collect::<HashSet<_>>();
        let mut groups = state.groups.write().await;

        for group in groups.iter_mut() {
            if !group
                .members
                .iter()
                .any(|member| member == &profile.username)
            {
                continue;
            }
            if !desired_groups.contains(&group.name) {
                group.members.retain(|member| member != &profile.username);
            }
        }

        for group_name in desired_groups {
            if let Some(group) = groups.iter_mut().find(|group| group.name == group_name) {
                if !group
                    .members
                    .iter()
                    .any(|member| member == &profile.username)
                {
                    group.members.push(profile.username.clone());
                }
                continue;
            }
            groups.push(IamGroup {
                name: group_name,
                members: vec![profile.username.clone()],
            });
        }
    }
    align_console_sessions_for_principal_in_memory(state, &profile.username, &profile.role).await;
    commit_iam_runtime_change(state, "external-identity-sync", rollback).await?;
    Ok(())
}

#[derive(Clone)]
struct IamRuntimeSnapshot {
    credentials: HashMap<String, LocalCredential>,
    users: Vec<IamUser>,
    groups: Vec<IamGroup>,
    policies: Vec<IamPolicy>,
    service_accounts: Vec<rustio_core::ServiceAccount>,
    admin_sessions: Vec<ConsoleSession>,
    sts_sessions: Vec<rustio_core::StsSession>,
}

async fn capture_iam_runtime_snapshot(state: &AppState) -> IamRuntimeSnapshot {
    IamRuntimeSnapshot {
        credentials: state.credentials.read().await.clone(),
        users: state.users.read().await.clone(),
        groups: state.groups.read().await.clone(),
        policies: state.policies.read().await.clone(),
        service_accounts: state.service_accounts.read().await.clone(),
        admin_sessions: state.admin_sessions.read().await.clone(),
        sts_sessions: state.sts_sessions.read().await.clone(),
    }
}

async fn restore_iam_runtime_snapshot(state: &AppState, snapshot: IamRuntimeSnapshot) {
    *state.credentials.write().await = snapshot.credentials;
    *state.users.write().await = snapshot.users;
    *state.groups.write().await = snapshot.groups;
    *state.policies.write().await = snapshot.policies;
    *state.service_accounts.write().await = snapshot.service_accounts;
    *state.admin_sessions.write().await = snapshot.admin_sessions.clone();
    *state.sts_sessions.write().await = snapshot.sts_sessions;
    let _ = AppState::persist_console_sessions_snapshot(&state.data_dir, &snapshot.admin_sessions);
}

async fn commit_iam_runtime_change(
    state: &AppState,
    reason: &str,
    rollback: IamRuntimeSnapshot,
) -> Result<(), AppError> {
    if let Err(err) = state.sync_metadata_raft(reason).await {
        restore_iam_runtime_snapshot(state, rollback).await;
        return Err(AppError::internal(format!(
            "IAM 元数据 Raft 提交失败 / iam metadata raft commit failed: {err}"
        )));
    }

    let sessions = state.admin_sessions.read().await.clone();
    AppState::persist_console_sessions_snapshot(&state.data_dir, &sessions).map_err(|err| {
        AppError::internal(format!(
            "持久化控制台会话快照失败 / failed to persist console session snapshot: {err}"
        ))
    })?;
    Ok(())
}

async fn align_console_sessions_for_principal_in_memory(
    state: &AppState,
    principal: &str,
    role: &str,
) {
    let permissions = rustio_core::permissions_for_role(role)
        .into_iter()
        .map(|permission| permission.as_str().to_string())
        .collect::<Vec<_>>();
    let mut sessions = state.admin_sessions.write().await;
    for session in sessions.iter_mut() {
        if session.principal == principal && session.status == "active" {
            session.role = role.to_string();
            session.permissions = permissions.clone();
        }
    }
}

async fn revoke_console_sessions_for_principal_in_memory(
    state: &AppState,
    principal: &str,
    revoked_reason: &str,
) -> usize {
    let now = Utc::now();
    let mut sessions = state.admin_sessions.write().await;
    let mut revoked = 0usize;
    for session in sessions.iter_mut() {
        if session.principal == principal && session.status == "active" {
            session.status = "revoked".to_string();
            session.revoked_at = Some(now);
            session.revoked_reason = Some(revoked_reason.to_string());
            revoked += 1;
        }
    }
    revoked
}

async fn persist_console_session(
    state: &AppState,
    session: ConsoleSession,
) -> Result<(), AppError> {
    let previous_sessions = state.admin_sessions.read().await.clone();
    let next_sessions = {
        let mut sessions = previous_sessions.clone();
        sessions.retain(|item| item.session_id != session.session_id);
        sessions.push(session);
        sessions
    };
    {
        let mut sessions = state.admin_sessions.write().await;
        *sessions = next_sessions.clone();
    }

    if let Err(err) = AppState::persist_console_sessions_snapshot(&state.data_dir, &next_sessions) {
        *state.admin_sessions.write().await = previous_sessions;
        return Err(AppError::internal(format!(
            "持久化控制台会话失败 / failed to persist console sessions: {err}"
        )));
    }

    if let Some(synced_session) = next_sessions.last().cloned() {
        state
            .broadcast_console_session_runtime(&synced_session)
            .await;
    }

    Ok(())
}

async fn create_console_login_response(
    state: &AppState,
    username: &str,
    role: &str,
    provider: &str,
) -> Result<(rustio_core::LoginResponse, ConsoleSession), AppError> {
    let session = create_console_session(username, role, provider);
    let response = issue_tokens(&session, &state.jwt_secret)?;
    persist_console_session(state, session.clone()).await?;
    Ok((response, session))
}

async fn revoke_console_session(
    state: &AppState,
    session_id: &str,
    revoked_reason: &str,
) -> Result<Option<ConsoleSession>, AppError> {
    let previous_sessions = state.admin_sessions.read().await.clone();
    let mut next_sessions = previous_sessions.clone();
    let revoked = {
        let mut revoked_session = None;
        for session in next_sessions.iter_mut() {
            if session.session_id == session_id {
                session.status = "revoked".to_string();
                session.revoked_at = Some(Utc::now());
                session.revoked_reason = Some(revoked_reason.to_string());
                revoked_session = Some(session.clone());
                break;
            }
        }
        revoked_session
    };

    if revoked.is_none() {
        return Ok(None);
    }
    {
        let mut sessions = state.admin_sessions.write().await;
        *sessions = next_sessions.clone();
    }

    if let Err(err) = AppState::persist_console_sessions_snapshot(&state.data_dir, &next_sessions) {
        *state.admin_sessions.write().await = previous_sessions;
        return Err(AppError::internal(format!(
            "持久化控制台会话撤销失败 / failed to persist console session revocation: {err}"
        )));
    }

    if let Some(session) = revoked.as_ref() {
        state.broadcast_console_session_runtime(session).await;
    }

    Ok(revoked)
}

async fn list_auth_providers(
    State(state): State<Arc<AppState>>,
) -> Result<Json<ApiEnvelope<Vec<AuthProviderInfo>>>, AppError> {
    let security = state.security.read().await.clone();
    let oidc_missing = oidc_missing_requirements(&security);
    let ldap_missing = ldap_missing_requirements(&security);
    Ok(wrap(vec![
        AuthProviderInfo {
            id: "local".to_string(),
            enabled: true,
            configured: true,
            supports_username_password: true,
            supports_browser_redirect: false,
            supports_id_token: false,
            authorize_url: None,
            missing_requirements: Vec::new(),
        },
        AuthProviderInfo {
            id: "oidc".to_string(),
            enabled: security.oidc_enabled && oidc_missing.is_empty(),
            configured: oidc_missing.is_empty(),
            supports_username_password: false,
            supports_browser_redirect: true,
            supports_id_token: true,
            authorize_url: Some("/api/v1/auth/oidc/authorize".to_string()),
            missing_requirements: oidc_missing,
        },
        AuthProviderInfo {
            id: "ldap".to_string(),
            enabled: security.ldap_enabled && ldap_missing.is_empty(),
            configured: ldap_missing.is_empty(),
            supports_username_password: true,
            supports_browser_redirect: false,
            supports_id_token: false,
            authorize_url: None,
            missing_requirements: ldap_missing,
        },
    ]))
}

async fn login(
    State(state): State<Arc<AppState>>,
    Json(body): Json<LoginRequest>,
) -> Result<Json<ApiEnvelope<rustio_core::LoginResponse>>, AppError> {
    let provider = body
        .provider
        .as_deref()
        .map(str::trim)
        .filter(|provider| !provider.is_empty())
        .map(|provider| provider.to_ascii_lowercase());
    let security = state.security.read().await.clone();

    if matches!(provider.as_deref(), Some("oidc")) {
        let profile = authenticate_oidc_identity(&security, &body).await?;
        sync_external_identity_profile(&state, &profile).await?;
        let (response, session) =
            create_console_login_response(state.as_ref(), &profile.username, &profile.role, "oidc")
                .await?;
        state
            .append_runtime_audit(
                &profile.username,
                "auth.login.oidc",
                "session",
                "success",
                None,
                json!({
                    "role": profile.role,
                    "groups": profile.groups,
                    "provider": profile.provider,
                    "session_id": session.session_id
                }),
            )
            .await;
        return Ok(wrap(response));
    }

    if matches!(provider.as_deref(), Some("ldap")) {
        let profile = authenticate_ldap_identity(&security, &body).await?;
        sync_external_identity_profile(&state, &profile).await?;
        let (response, session) =
            create_console_login_response(state.as_ref(), &profile.username, &profile.role, "ldap")
                .await?;
        state
            .append_runtime_audit(
                &profile.username,
                "auth.login.ldap",
                "session",
                "success",
                None,
                json!({
                    "role": profile.role,
                    "groups": profile.groups,
                    "provider": profile.provider,
                    "session_id": session.session_id
                }),
            )
            .await;
        return Ok(wrap(response));
    }

    if let Some(provider) = provider {
        return Err(AppError::bad_request(format!(
            "不支持的登录提供方 / unsupported login provider: {provider}"
        )));
    }

    let credentials = state.credentials.read().await;
    let found = credentials
        .get(&body.username)
        .ok_or_else(|| AppError::unauthorized("凭证无效 / invalid credentials"))?;

    if found.password != body.password {
        return Err(AppError::unauthorized("凭证无效 / invalid credentials"));
    }

    if let Some(user) = state
        .users
        .read()
        .await
        .iter()
        .find(|item| item.username == body.username)
        .cloned()
    {
        if !user.enabled {
            return Err(AppError::unauthorized("用户已禁用 / user is disabled"));
        }
    }

    let (response, session) =
        create_console_login_response(state.as_ref(), &body.username, &found.role, "local").await?;
    state
        .append_runtime_audit(
            &body.username,
            "auth.login",
            "session",
            "success",
            None,
            json!({ "role": found.role, "session_id": session.session_id }),
        )
        .await;
    Ok(wrap(response))
}

async fn refresh_token(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
    body: Option<Json<RefreshTokenRequest>>,
) -> Result<Json<ApiEnvelope<rustio_core::LoginResponse>>, AppError> {
    let refresh_token = body
        .map(|payload| payload.0.refresh_token)
        .filter(|token| !token.trim().is_empty())
        .or_else(|| extract_access_token(&headers, None))
        .ok_or_else(|| AppError::bad_request("缺少刷新令牌 / missing refresh token"))?;
    let (_, current_session) = validate_refresh_token(&refresh_token, state.as_ref()).await?;
    let effective_role = state
        .users
        .read()
        .await
        .iter()
        .find(|user| user.username == current_session.principal)
        .map(|user| user.role.clone())
        .unwrap_or_else(|| current_session.role.clone());
    let mut next_session = refresh_console_session(&current_session);
    next_session.role = effective_role;
    next_session.permissions = rustio_core::permissions_for_role(&next_session.role)
        .into_iter()
        .map(|permission| permission.as_str().to_string())
        .collect();
    let response = issue_tokens(&next_session, &state.jwt_secret)?;
    persist_console_session(state.as_ref(), next_session.clone()).await?;
    state
        .append_runtime_audit(
            &next_session.principal,
            "auth.refresh",
            "session",
            "success",
            None,
            json!({
                "session_id": next_session.session_id,
                "provider": next_session.provider
            }),
        )
        .await;
    Ok(wrap(response))
}

async fn logout(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
) -> Result<Json<ApiEnvelope<serde_json::Value>>, AppError> {
    let session_id = auth.claims.session_id.clone();
    let revoked = revoke_console_session(
        state.as_ref(),
        &session_id,
        "用户主动退出 / user requested logout",
    )
    .await?;
    state
        .append_runtime_audit(
            &auth.username,
            "auth.logout",
            "session",
            "success",
            None,
            json!({
                "session_id": session_id,
                "revoked": revoked.is_some()
            }),
        )
        .await;
    Ok(wrap(json!({
        "logged_out": true,
        "session_id": auth.claims.session_id
    })))
}

async fn current_console_session(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
) -> Result<Json<ApiEnvelope<ConsoleSession>>, AppError> {
    let mut session = state
        .admin_sessions
        .read()
        .await
        .iter()
        .find(|session| session.session_id == auth.claims.session_id)
        .cloned()
        .ok_or_else(|| {
            AppError::unauthorized("会话不存在或已失效 / session does not exist or has expired")
        })?;
    session.role = auth.claims.role.clone();
    session.permissions = auth.claims.permissions.clone();
    Ok(wrap(session))
}

async fn list_console_sessions(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
) -> Result<Json<ApiEnvelope<Vec<ConsoleSession>>>, AppError> {
    auth.require(Permission::IamRead)?;
    let mut sessions = state.admin_sessions.read().await.clone();
    sessions.sort_by(|left, right| {
        right
            .issued_at
            .cmp(&left.issued_at)
            .then_with(|| left.session_id.cmp(&right.session_id))
    });
    Ok(wrap(sessions))
}

async fn delete_console_session(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
    Path(session_id): Path<String>,
) -> Result<Json<ApiEnvelope<serde_json::Value>>, AppError> {
    let target_session = state
        .admin_sessions
        .read()
        .await
        .iter()
        .find(|session| session.session_id == session_id)
        .cloned()
        .ok_or_else(|| AppError::not_found("控制台会话不存在 / console session not found"))?;

    let can_revoke_other = auth.claims.has_permission(Permission::IamWrite);
    if auth.claims.session_id != session_id
        && auth.username != target_session.principal
        && !can_revoke_other
    {
        return Err(AppError::forbidden(
            "无权回收其他用户会话 / not allowed to revoke another user's session",
        ));
    }

    let revoked = revoke_console_session(
        state.as_ref(),
        &session_id,
        &format!(
            "{} 主动回收会话 / {} revoked session",
            auth.username, auth.username
        ),
    )
    .await?;
    let revoked_session = revoked.unwrap_or(target_session.clone());
    let already_revoked = target_session.status != "active";

    state
        .append_runtime_audit(
            &auth.username,
            "auth.session.revoke",
            &format!("auth/session/{session_id}"),
            "success",
            None,
            json!({
                "principal": revoked_session.principal,
                "provider": revoked_session.provider,
                "already_revoked": already_revoked
            }),
        )
        .await;

    Ok(wrap(json!({
        "revoked": true,
        "already_revoked": already_revoked,
        "session_id": session_id
    })))
}

async fn cluster_health(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
) -> Result<Json<ApiEnvelope<ClusterHealth>>, AppError> {
    auth.require(Permission::ClusterRead)?;
    let nodes = state.nodes.read().await;
    let online = nodes.iter().filter(|node| node.online).count() as u32;
    let total = nodes.len() as u32;
    let status = if online == total {
        "healthy"
    } else if online == 0 {
        "critical"
    } else {
        "degraded"
    };

    Ok(wrap(ClusterHealth {
        status: status.to_string(),
        timestamp: Utc::now(),
        nodes_online: online,
        nodes_total: total,
    }))
}

async fn list_nodes(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
) -> Result<Json<ApiEnvelope<Vec<rustio_core::ClusterNode>>>, AppError> {
    auth.require(Permission::ClusterRead)?;
    Ok(wrap(state.nodes.read().await.clone()))
}

async fn set_node_offline(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
    Path(id): Path<String>,
    headers: HeaderMap,
    Json(body): Json<DangerActionRequest>,
) -> Result<Json<ApiEnvelope<rustio_core::ClusterNode>>, AppError> {
    auth.require(Permission::ClusterWrite)?;
    ensure_confirm_header(&headers)?;

    let mut nodes = state.nodes.write().await;
    let node = nodes
        .iter_mut()
        .find(|n| n.id == id)
        .ok_or_else(|| AppError::not_found("节点不存在 / node not found"))?;
    node.online = false;
    node.last_heartbeat = Utc::now();
    let snapshot = node.clone();

    state
        .append_audit(
            &auth.username,
            "cluster.node.offline",
            &format!("node/{}", snapshot.id),
            "success",
            Some(body.reason.clone()),
            json!({ "online": false }),
        )
        .await;
    state
        .push_event(
            "cluster.node.offline",
            "cluster-service",
            json!({ "node": snapshot.id }),
        )
        .await;
    Ok(wrap(snapshot))
}

async fn set_node_online(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
    Path(id): Path<String>,
    headers: HeaderMap,
    Json(body): Json<DangerActionRequest>,
) -> Result<Json<ApiEnvelope<rustio_core::ClusterNode>>, AppError> {
    auth.require(Permission::ClusterWrite)?;
    ensure_confirm_header(&headers)?;

    let mut nodes = state.nodes.write().await;
    let node = nodes
        .iter_mut()
        .find(|n| n.id == id)
        .ok_or_else(|| AppError::not_found("节点不存在 / node not found"))?;
    node.online = true;
    node.last_heartbeat = Utc::now();
    let snapshot = node.clone();

    state
        .append_audit(
            &auth.username,
            "cluster.node.online",
            &format!("node/{}", snapshot.id),
            "success",
            Some(body.reason.clone()),
            json!({ "online": true }),
        )
        .await;
    state
        .push_event(
            "cluster.node.online",
            "cluster-service",
            json!({ "node": snapshot.id }),
        )
        .await;
    Ok(wrap(snapshot))
}

async fn list_quotas(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
) -> Result<Json<ApiEnvelope<Vec<rustio_core::ClusterQuota>>>, AppError> {
    auth.require(Permission::ClusterRead)?;
    let quotas = {
        let tenants = state.tenants.read().await;
        tenants
            .iter()
            .map(|tenant| rustio_core::ClusterQuota {
                tenant: tenant.id.clone(),
                hard_limit_bytes: tenant.hard_limit_bytes,
                used_bytes: tenant.used_bytes,
            })
            .collect::<Vec<_>>()
    };
    *state.quotas.write().await = quotas.clone();
    Ok(wrap(quotas))
}

