async fn simulate_alert_rule_trigger(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
    Path(id): Path<String>,
) -> Result<Json<ApiEnvelope<AlertHistoryEntry>>, AppError> {
    auth.require(Permission::SecurityWrite)?;
    let history = state
        .evaluate_alert_rule_now(&id, &auth.username)
        .await
        .map_err(|err| {
            if err.contains("不存在 /") {
                AppError::not_found(err)
            } else {
                AppError::bad_request(err)
            }
        })?;
    let rule_id = history.rule_id.clone().unwrap_or(id);
    let delivery_enqueued = state
        .enqueue_alert_deliveries(&history)
        .await
        .map_err(AppError::bad_request)?;

    state
        .append_audit(
            &auth.username,
            "alerts.rule.evaluate",
            &format!("alerts/rules/{rule_id}"),
            "success",
            None,
            json!({
                "status": history.status,
                "message": history.message,
                "trigger_mode": "manual-evaluation",
                "delivery_enqueued": delivery_enqueued,
            }),
        )
        .await;
    state
        .push_event(
            "alerts.rule.evaluated",
            "alerts-service",
            json!({
                "rule_id": rule_id,
                "status": history.status,
                "severity": history.severity,
                "trigger_mode": "manual-evaluation",
                "delivery_enqueued": delivery_enqueued,
            }),
        )
        .await;

    Ok(wrap(history))
}

async fn list_alert_history(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
    Query(query): Query<AlertHistoryQuery>,
) -> Result<Json<ApiEnvelope<Vec<AlertHistoryEntry>>>, AppError> {
    auth.require(Permission::SecurityRead)?;
    let limit = query.limit.unwrap_or(200).clamp(1, 2000);
    let severity_filter = query
        .severity
        .as_ref()
        .map(|value| value.trim().to_ascii_lowercase());
    let status_filter = query
        .status
        .as_ref()
        .map(|value| value.trim().to_ascii_lowercase());
    let source_filter = query
        .source
        .as_ref()
        .map(|value| value.trim().to_ascii_lowercase());
    let rule_id_filter = query.rule_id.as_ref().map(|value| value.trim().to_string());

    let mut history = state
        .alert_history
        .read()
        .await
        .iter()
        .filter(|entry| {
            if let Some(filter) = &severity_filter {
                if entry.severity.to_ascii_lowercase() != *filter {
                    return false;
                }
            }
            if let Some(filter) = &status_filter {
                if entry.status.to_ascii_lowercase() != *filter {
                    return false;
                }
            }
            if let Some(filter) = &source_filter {
                if !entry.source.to_ascii_lowercase().contains(filter) {
                    return false;
                }
            }
            if let Some(filter) = &rule_id_filter {
                if entry.rule_id.as_deref() != Some(filter.as_str()) {
                    return false;
                }
            }
            true
        })
        .cloned()
        .collect::<Vec<_>>();
    history.sort_by(|left, right| right.triggered_at.cmp(&left.triggered_at));
    history.truncate(limit);
    Ok(wrap(history))
}

async fn claim_alert_history_entry(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
    Path(id): Path<String>,
) -> Result<Json<ApiEnvelope<AlertHistoryEntry>>, AppError> {
    auth.require(Permission::SecurityWrite)?;
    let now = Utc::now();

    let mut history = state.alert_history.write().await;
    let entry = history
        .iter_mut()
        .find(|entry| entry.id == id)
        .ok_or_else(|| AppError::not_found("告警历史记录不存在 / alert history entry not found"))?;
    entry.assignee = Some(auth.username.clone());
    entry.claimed_at = Some(now);
    let snapshot = entry.clone();
    drop(history);

    state
        .append_audit(
            &auth.username,
            "alerts.history.claim",
            &format!("alerts/history/{id}"),
            "success",
            None,
            json!({
                "assignee": snapshot.assignee,
            }),
        )
        .await;
    state
        .push_event(
            "alerts.history.claimed",
            "alerts-service",
            json!({ "id": id, "assignee": snapshot.assignee }),
        )
        .await;
    Ok(wrap(snapshot))
}

async fn ack_alert_history_entry(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
    Path(id): Path<String>,
) -> Result<Json<ApiEnvelope<AlertHistoryEntry>>, AppError> {
    auth.require(Permission::SecurityWrite)?;
    let now = Utc::now();

    let mut history = state.alert_history.write().await;
    let entry = history
        .iter_mut()
        .find(|entry| entry.id == id)
        .ok_or_else(|| AppError::not_found("告警历史记录不存在 / alert history entry not found"))?;
    entry.acknowledged_by = Some(auth.username.clone());
    entry.acknowledged_at = Some(now);
    if entry.status == "firing" || entry.status == "suppressed" {
        entry.status = "acknowledged".to_string();
    }
    let snapshot = entry.clone();
    drop(history);

    state
        .append_audit(
            &auth.username,
            "alerts.history.ack",
            &format!("alerts/history/{id}"),
            "success",
            None,
            json!({
                "status": snapshot.status,
                "acknowledged_by": snapshot.acknowledged_by,
            }),
        )
        .await;
    state
        .push_event(
            "alerts.history.acknowledged",
            "alerts-service",
            json!({ "id": id, "status": snapshot.status }),
        )
        .await;
    Ok(wrap(snapshot))
}

async fn resolve_alert_history_entry(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
    Path(id): Path<String>,
) -> Result<Json<ApiEnvelope<AlertHistoryEntry>>, AppError> {
    auth.require(Permission::SecurityWrite)?;
    let now = Utc::now();

    let mut history = state.alert_history.write().await;
    let entry = history
        .iter_mut()
        .find(|entry| entry.id == id)
        .ok_or_else(|| AppError::not_found("告警历史记录不存在 / alert history entry not found"))?;
    entry.status = "resolved".to_string();
    if entry.acknowledged_at.is_none() {
        entry.acknowledged_by = Some(auth.username.clone());
        entry.acknowledged_at = Some(now);
    }
    entry.resolved_by = Some(auth.username.clone());
    entry.resolved_at = Some(now);
    let snapshot = entry.clone();
    drop(history);

    state
        .append_audit(
            &auth.username,
            "alerts.history.resolve",
            &format!("alerts/history/{id}"),
            "success",
            None,
            json!({
                "status": snapshot.status,
                "resolved_by": snapshot.resolved_by,
            }),
        )
        .await;
    state
        .push_event(
            "alerts.history.resolved",
            "alerts-service",
            json!({ "id": id, "status": snapshot.status }),
        )
        .await;
    Ok(wrap(snapshot))
}

#[derive(Debug, Deserialize)]
struct AuditQuery {
    limit: Option<usize>,
    category: Option<String>,
    actor: Option<String>,
    action: Option<String>,
    action_prefix: Option<String>,
    resource: Option<String>,
    resource_prefix: Option<String>,
    outcome: Option<String>,
    keyword: Option<String>,
    reason: Option<String>,
    detail_key: Option<String>,
    detail_value: Option<String>,
    from: Option<String>,
    to: Option<String>,
}

fn json_lookup_path<'a>(value: &'a Value, path: &str) -> Option<&'a Value> {
    let mut current = value;
    for segment in path.split('.') {
        let key = segment.trim();
        if key.is_empty() {
            return None;
        }
        current = current.get(key)?;
    }
    Some(current)
}

fn json_value_contains(value: &Value, needle: &str) -> bool {
    match value {
        Value::Null => false,
        Value::Bool(flag) => flag.to_string().contains(needle),
        Value::Number(number) => number.to_string().contains(needle),
        Value::String(text) => text.to_ascii_lowercase().contains(needle),
        Value::Array(items) => items.iter().any(|item| json_value_contains(item, needle)),
        Value::Object(map) => map.iter().any(|(key, value)| {
            key.to_ascii_lowercase().contains(needle) || json_value_contains(value, needle)
        }),
    }
}

async fn list_audit_events(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
    Query(query): Query<AuditQuery>,
) -> Result<Json<ApiEnvelope<Vec<rustio_core::AuditEvent>>>, AppError> {
    auth.require(Permission::AuditRead)?;
    let limit = query.limit.unwrap_or(200).clamp(1, 2000);
    let category_filter = query
        .category
        .as_ref()
        .map(|value| value.to_ascii_lowercase());
    let actor_filter = query.actor.as_ref().map(|value| value.to_ascii_lowercase());
    let action_filter = query
        .action
        .as_ref()
        .map(|value| value.to_ascii_lowercase());
    let action_prefix_filter = query
        .action_prefix
        .as_ref()
        .map(|value| value.to_ascii_lowercase());
    let resource_filter = query
        .resource
        .as_ref()
        .map(|value| value.to_ascii_lowercase());
    let resource_prefix_filter = query
        .resource_prefix
        .as_ref()
        .map(|value| value.to_ascii_lowercase());
    let outcome_filter = query
        .outcome
        .as_ref()
        .map(|value| value.to_ascii_lowercase());
    let keyword_filter = query
        .keyword
        .as_ref()
        .map(|value| value.to_ascii_lowercase());
    let reason_filter = query
        .reason
        .as_ref()
        .map(|value| value.to_ascii_lowercase());
    let detail_key_filter = query
        .detail_key
        .as_ref()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty());
    let detail_value_filter = query
        .detail_value
        .as_ref()
        .map(|value| value.to_ascii_lowercase());

    let from = query
        .from
        .as_deref()
        .map(DateTime::parse_from_rfc3339)
        .transpose()
        .map_err(|_| {
            AppError::bad_request(
                "from 时间戳无效，应为 RFC3339 / invalid 'from' timestamp, expected RFC3339",
            )
        })?
        .map(|value| value.with_timezone(&Utc));
    let to = query
        .to
        .as_deref()
        .map(DateTime::parse_from_rfc3339)
        .transpose()
        .map_err(|_| {
            AppError::bad_request(
                "to 时间戳无效，应为 RFC3339 / invalid 'to' timestamp, expected RFC3339",
            )
        })?
        .map(|value| value.with_timezone(&Utc));

    let audits = state.audits.read().await;
    let mut events = audits
        .iter()
        .filter(|event| {
            if let Some(filter) = &category_filter {
                if audit_category(&event.action) != filter {
                    return false;
                }
            }
            if let Some(filter) = &actor_filter {
                if !event.actor.to_ascii_lowercase().contains(filter) {
                    return false;
                }
            }
            if let Some(filter) = &action_filter {
                if !event.action.to_ascii_lowercase().contains(filter) {
                    return false;
                }
            }
            if let Some(filter) = &action_prefix_filter {
                if !event.action.to_ascii_lowercase().starts_with(filter) {
                    return false;
                }
            }
            if let Some(filter) = &resource_filter {
                if !event.resource.to_ascii_lowercase().contains(filter) {
                    return false;
                }
            }
            if let Some(filter) = &resource_prefix_filter {
                if !event.resource.to_ascii_lowercase().starts_with(filter) {
                    return false;
                }
            }
            if let Some(filter) = &outcome_filter {
                if event.outcome.to_ascii_lowercase() != *filter {
                    return false;
                }
            }
            if let Some(filter) = &reason_filter {
                let reason = event
                    .reason
                    .as_deref()
                    .unwrap_or_default()
                    .to_ascii_lowercase();
                if !reason.contains(filter) {
                    return false;
                }
            }
            if let Some(filter) = &detail_key_filter {
                let Some(detail) = json_lookup_path(&event.details, filter) else {
                    return false;
                };
                if let Some(value_filter) = &detail_value_filter {
                    if !json_value_contains(detail, value_filter) {
                        return false;
                    }
                }
            } else if let Some(value_filter) = &detail_value_filter {
                if !json_value_contains(&event.details, value_filter) {
                    return false;
                }
            }
            if let Some(filter) = &keyword_filter {
                let in_reason = event
                    .reason
                    .as_ref()
                    .map(|value| value.to_ascii_lowercase().contains(filter))
                    .unwrap_or(false);
                let details = event.details.to_string().to_ascii_lowercase();
                if !event.actor.to_ascii_lowercase().contains(filter)
                    && !event.action.to_ascii_lowercase().contains(filter)
                    && !event.resource.to_ascii_lowercase().contains(filter)
                    && !event.outcome.to_ascii_lowercase().contains(filter)
                    && !in_reason
                    && !details.contains(filter)
                    && !json_value_contains(&event.details, filter)
                {
                    return false;
                }
            }
            if let Some(from_at) = from {
                if event.timestamp < from_at {
                    return false;
                }
            }
            if let Some(to_at) = to {
                if event.timestamp > to_at {
                    return false;
                }
            }
            true
        })
        .cloned()
        .collect::<Vec<_>>();

    events.sort_by(|left, right| right.timestamp.cmp(&left.timestamp));
    events.truncate(limit);
    Ok(wrap(events))
}

async fn export_audit_events(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
) -> Result<impl IntoResponse, AppError> {
    auth.require(Permission::AuditRead)?;
    let body = serde_json::to_string_pretty(&state.audits.read().await.clone()).map_err(|err| {
        AppError::internal(format!(
            "序列化审计导出失败 / failed to serialize audit export: {err}"
        ))
    })?;

    Ok((
        StatusCode::OK,
        [(
            axum::http::header::CONTENT_TYPE,
            "application/json; charset=utf-8",
        )],
        body,
    ))
}

