const KMS_WRAP_PREFIX_GENERIC: &str = "kms-generic:";
const KMS_WRAP_PREFIX_VAULT: &str = "kms-vault:";
const KMS_WRAP_PREFIX_KES: &str = "kms-kes:";

#[derive(Debug, Serialize)]
struct KesGenerateDataKeyRequest {
    plaintext: String,
    length: usize,
    #[serde(skip_serializing_if = "Option::is_none")]
    associated_data: Option<String>,
}

#[derive(Debug, Deserialize)]
struct KesGenerateDataKeyResponse {
    plaintext: String,
    ciphertext: String,
}

#[derive(Debug, Serialize)]
struct KesDecryptDataKeyRequest {
    ciphertext: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    associated_data: Option<String>,
}

#[derive(Debug, Deserialize)]
struct KesDecryptDataKeyResponse {
    plaintext: String,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum KmsProviderKind {
    Generic,
    VaultTransit,
    Kes,
}

fn kms_external_enabled() -> bool {
    std::env::var("RUSTIO_KMS_EXTERNAL_ENABLED")
        .map(|value| {
            matches!(
                value.trim().to_ascii_lowercase().as_str(),
                "1" | "true" | "yes" | "on"
            )
        })
        .unwrap_or(false)
}

fn kms_provider_kind() -> KmsProviderKind {
    match std::env::var("RUSTIO_KMS_PROVIDER")
        .unwrap_or_else(|_| "generic".to_string())
        .trim()
        .to_ascii_lowercase()
        .as_str()
    {
        "kes" => KmsProviderKind::Kes,
        "vault" | "vault-transit" | "vault_transit" => KmsProviderKind::VaultTransit,
        _ => KmsProviderKind::Generic,
    }
}

fn kms_provider_label() -> &'static str {
    match kms_provider_kind() {
        KmsProviderKind::Generic => "generic",
        KmsProviderKind::VaultTransit => "vault-transit",
        KmsProviderKind::Kes => "kes",
    }
}

fn kms_token() -> Option<String> {
    std::env::var("RUSTIO_KMS_TOKEN")
        .ok()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
}

fn kms_api_key() -> Option<String> {
    std::env::var("RUSTIO_KMS_API_KEY")
        .ok()
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
}

fn kms_auth_mode() -> String {
    match (
        kms_token().is_some(),
        kms_api_key().is_some(),
        kms_provider_kind(),
    ) {
        (true, true, KmsProviderKind::Kes) => "bearer+x-kes-api-key".to_string(),
        (true, _, KmsProviderKind::Kes) => "bearer".to_string(),
        (false, true, KmsProviderKind::Kes) => "x-kes-api-key".to_string(),
        (true, _, _) => "bearer+x-vault-token".to_string(),
        _ => "none".to_string(),
    }
}

fn kms_endpoint_valid(endpoint: &str) -> bool {
    !endpoint.is_empty() && (endpoint.starts_with("http://") || endpoint.starts_with("https://"))
}

fn s3_kms_not_configured(resource: &str, message: &str) -> Response {
    s3_error(
        StatusCode::SERVICE_UNAVAILABLE,
        "KMSNotConfigured",
        message,
        resource,
    )
}

fn s3_kms_unavailable(resource: &str, message: &str) -> Response {
    s3_error(
        StatusCode::SERVICE_UNAVAILABLE,
        "KMSUnavailable",
        message,
        resource,
    )
}

fn kms_context_json(meta: &S3ObjectMeta) -> Value {
    json!({
        "bucket": meta.bucket,
        "key": meta.key,
        "version_id": meta.version_id,
        "algorithm": meta.encryption.algorithm,
    })
}

fn kms_context_base64(meta: &S3ObjectMeta) -> String {
    let bytes = serde_json::to_vec(&kms_context_json(meta)).unwrap_or_else(|_| b"{}".to_vec());
    BASE64.encode(bytes)
}

fn kms_request_builder(client: &Client, url: String) -> reqwest::RequestBuilder {
    let mut request = client.post(url);
    match kms_provider_kind() {
        KmsProviderKind::Kes => {
            if let Some(token) = kms_token() {
                request = request.bearer_auth(token);
            }
            if let Some(api_key) = kms_api_key() {
                request = request.header("x-kes-api-key", api_key);
            }
        }
        KmsProviderKind::Generic | KmsProviderKind::VaultTransit => {
            if let Some(token) = kms_token() {
                request = request
                    .header("x-vault-token", token.clone())
                    .bearer_auth(token);
            }
        }
    }
    request
}

async fn kms_encrypt_data_key_remote(
    state: &AppState,
    resource: &str,
    meta: &S3ObjectMeta,
    data_key: &[u8; 32],
) -> Result<Option<String>, Response> {
    if !meta.encryption.algorithm.eq_ignore_ascii_case("aws:kms") || !kms_external_enabled() {
        return Ok(None);
    }

    let (endpoint, default_key_id) = {
        let security = state.security.read().await;
        (
            security
                .kms_endpoint
                .trim()
                .trim_end_matches('/')
                .to_string(),
            "rustio-default-kms-key".to_string(),
        )
    };
    if !kms_endpoint_valid(&endpoint) {
        mark_kms_health_failure(
            state,
            bilingual_s3_message(
                "KMSNotConfigured",
                "KMS endpoint is not configured for external mode",
            ),
        )
        .await;
        return Err(s3_kms_not_configured(
            resource,
            "KMS endpoint is not configured for external mode",
        ));
    }

    let key_id = meta.encryption.kms_key_id.clone().unwrap_or(default_key_id);
    let client = Client::builder()
        .timeout(std::time::Duration::from_secs(3))
        .build()
        .map_err(|err| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to initialize KMS client: {err}"),
                resource,
            )
        })?;
    let provider = kms_provider_kind();
    let wrapped = match provider {
        KmsProviderKind::Generic => {
            let request = KmsEncryptDataKeyRequest {
                key_id: key_id.clone(),
                plaintext_base64: BASE64.encode(data_key),
                context: kms_context_json(meta),
            };
            let response = kms_request_builder(&client, format!("{endpoint}/v1/crypto/encrypt"))
                .json(&request)
                .send()
                .await;
            let response = match response {
                Ok(value) => value,
                Err(err) => {
                    mark_kms_health_failure(
                        state,
                        bilingual_s3_message(
                            "KMSUnavailable",
                            &format!("KMS encrypt request failed: {err}"),
                        ),
                    )
                    .await;
                    return Err(s3_kms_unavailable(
                        resource,
                        &format!("KMS encrypt request failed: {err}"),
                    ));
                }
            };
            if !response.status().is_success() {
                mark_kms_health_failure(
                    state,
                    bilingual_s3_message(
                        "KMSUnavailable",
                        &format!("KMS encrypt status: {}", response.status()),
                    ),
                )
                .await;
                return Err(s3_kms_unavailable(
                    resource,
                    &format!("KMS encrypt status: {}", response.status()),
                ));
            }
            let parsed = response
                .json::<KmsEncryptDataKeyResponse>()
                .await
                .map_err(|err| {
                    s3_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "InternalError",
                        &format!("Failed to decode KMS encrypt response: {err}"),
                        resource,
                    )
                })?;
            format!("{KMS_WRAP_PREFIX_GENERIC}{}", parsed.ciphertext_base64)
        }
        KmsProviderKind::VaultTransit => {
            let key_path = utf8_percent_encode(&key_id, NON_ALPHANUMERIC).to_string();
            let request = VaultTransitEncryptDataKeyRequest {
                plaintext: BASE64.encode(data_key),
                context: Some(kms_context_base64(meta)),
            };
            let response =
                kms_request_builder(&client, format!("{endpoint}/v1/transit/encrypt/{key_path}"))
                    .json(&request)
                    .send()
                    .await;
            let response = match response {
                Ok(value) => value,
                Err(err) => {
                    mark_kms_health_failure(
                        state,
                        bilingual_s3_message(
                            "KMSUnavailable",
                            &format!("KMS encrypt request failed: {err}"),
                        ),
                    )
                    .await;
                    return Err(s3_kms_unavailable(
                        resource,
                        &format!("KMS encrypt request failed: {err}"),
                    ));
                }
            };
            if !response.status().is_success() {
                mark_kms_health_failure(
                    state,
                    bilingual_s3_message(
                        "KMSUnavailable",
                        &format!("KMS encrypt status: {}", response.status()),
                    ),
                )
                .await;
                return Err(s3_kms_unavailable(
                    resource,
                    &format!("KMS encrypt status: {}", response.status()),
                ));
            }
            let parsed = response
                .json::<VaultTransitEncryptDataKeyResponseEnvelope>()
                .await
                .map_err(|err| {
                    s3_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "InternalError",
                        &format!("Failed to decode Vault transit encrypt response: {err}"),
                        resource,
                    )
                })?;
            format!("{KMS_WRAP_PREFIX_VAULT}{}", parsed.data.ciphertext)
        }
        KmsProviderKind::Kes => {
            let key_path = utf8_percent_encode(&key_id, NON_ALPHANUMERIC).to_string();
            let request = KesGenerateDataKeyRequest {
                plaintext: BASE64.encode(data_key),
                length: data_key.len(),
                associated_data: Some(kms_context_base64(meta)),
            };
            let response =
                kms_request_builder(&client, format!("{endpoint}/v1/key/generate/{key_path}"))
                    .json(&request)
                    .send()
                    .await;
            let response = match response {
                Ok(value) => value,
                Err(err) => {
                    mark_kms_health_failure(
                        state,
                        bilingual_s3_message(
                            "KMSUnavailable",
                            &format!("KMS encrypt request failed: {err}"),
                        ),
                    )
                    .await;
                    return Err(s3_kms_unavailable(
                        resource,
                        &format!("KMS encrypt request failed: {err}"),
                    ));
                }
            };
            if !response.status().is_success() {
                mark_kms_health_failure(
                    state,
                    bilingual_s3_message(
                        "KMSUnavailable",
                        &format!("KMS encrypt status: {}", response.status()),
                    ),
                )
                .await;
                return Err(s3_kms_unavailable(
                    resource,
                    &format!("KMS encrypt status: {}", response.status()),
                ));
            }
            let parsed = response
                .json::<KesGenerateDataKeyResponse>()
                .await
                .map_err(|err| {
                    s3_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "InternalError",
                        &format!("Failed to decode KES encrypt response: {err}"),
                        resource,
                    )
                })?;
            if parsed.plaintext != BASE64.encode(data_key) {
                mark_kms_health_failure(
                    state,
                    bilingual_s3_message(
                        "KMSUnavailable",
                        "KES plaintext data key does not match generated key",
                    ),
                )
                .await;
                return Err(s3_kms_unavailable(
                    resource,
                    "KES plaintext data key does not match generated key",
                ));
            }
            format!("{KMS_WRAP_PREFIX_KES}{}", parsed.ciphertext)
        }
    };
    mark_kms_health_success(state).await;
    Ok(Some(wrapped))
}

async fn kms_decrypt_data_key_remote(
    state: &AppState,
    resource: &str,
    meta: &S3ObjectMeta,
    wrapped_key_base64: &str,
) -> Result<Option<[u8; 32]>, Response> {
    if !meta.encryption.algorithm.eq_ignore_ascii_case("aws:kms") {
        return Ok(None);
    }
    let wrapped = wrapped_key_base64.trim();
    let external_required = kms_external_enabled()
        || wrapped.starts_with(KMS_WRAP_PREFIX_GENERIC)
        || wrapped.starts_with(KMS_WRAP_PREFIX_VAULT)
        || wrapped.starts_with(KMS_WRAP_PREFIX_KES);
    let (provider, ciphertext) = if let Some(value) = wrapped.strip_prefix(KMS_WRAP_PREFIX_GENERIC)
    {
        if !kms_external_enabled() {
            mark_kms_health_failure(
                state,
                bilingual_s3_message(
                    "KMSUnavailable",
                    "KMS external is required to decrypt wrapped key",
                ),
            )
            .await;
            return Err(s3_kms_unavailable(
                resource,
                "KMS external is required to decrypt wrapped key",
            ));
        }
        (KmsProviderKind::Generic, value.to_string())
    } else if let Some(value) = wrapped.strip_prefix(KMS_WRAP_PREFIX_VAULT) {
        if !kms_external_enabled() {
            mark_kms_health_failure(
                state,
                bilingual_s3_message(
                    "KMSUnavailable",
                    "KMS external is required to decrypt wrapped key",
                ),
            )
            .await;
            return Err(s3_kms_unavailable(
                resource,
                "KMS external is required to decrypt wrapped key",
            ));
        }
        (KmsProviderKind::VaultTransit, value.to_string())
    } else if let Some(value) = wrapped.strip_prefix(KMS_WRAP_PREFIX_KES) {
        if !kms_external_enabled() {
            mark_kms_health_failure(
                state,
                bilingual_s3_message(
                    "KMSUnavailable",
                    "KMS external is required to decrypt wrapped key",
                ),
            )
            .await;
            return Err(s3_kms_unavailable(
                resource,
                "KMS external is required to decrypt wrapped key",
            ));
        }
        (KmsProviderKind::Kes, value.to_string())
    } else {
        if !kms_external_enabled() {
            return Ok(None);
        }
        (kms_provider_kind(), wrapped.to_string())
    };

    let endpoint = {
        let security = state.security.read().await;
        security
            .kms_endpoint
            .trim()
            .trim_end_matches('/')
            .to_string()
    };
    if !kms_endpoint_valid(&endpoint) {
        if external_required {
            mark_kms_health_failure(
                state,
                bilingual_s3_message(
                    "KMSNotConfigured",
                    "KMS endpoint is not configured for external mode",
                ),
            )
            .await;
            return Err(s3_kms_not_configured(
                resource,
                "KMS endpoint is not configured for external mode",
            ));
        }
        return Ok(None);
    }

    let client = Client::builder()
        .timeout(std::time::Duration::from_secs(3))
        .build()
        .map_err(|err| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to initialize KMS client: {err}"),
                resource,
            )
        })?;
    let plaintext_base64 = match provider {
        KmsProviderKind::Generic => {
            let request = KmsDecryptDataKeyRequest {
                ciphertext_base64: ciphertext.clone(),
                context: kms_context_json(meta),
            };
            let response = kms_request_builder(&client, format!("{endpoint}/v1/crypto/decrypt"))
                .json(&request)
                .send()
                .await;
            let response = match response {
                Ok(value) => value,
                Err(err) => {
                    mark_kms_health_failure(
                        state,
                        bilingual_s3_message(
                            "KMSUnavailable",
                            &format!("KMS decrypt request failed: {err}"),
                        ),
                    )
                    .await;
                    return Err(s3_kms_unavailable(
                        resource,
                        &format!("KMS decrypt request failed: {err}"),
                    ));
                }
            };
            if !response.status().is_success() {
                mark_kms_health_failure(
                    state,
                    bilingual_s3_message(
                        "KMSUnavailable",
                        &format!("KMS decrypt status: {}", response.status()),
                    ),
                )
                .await;
                return Err(s3_kms_unavailable(
                    resource,
                    &format!("KMS decrypt status: {}", response.status()),
                ));
            }
            response
                .json::<KmsDecryptDataKeyResponse>()
                .await
                .map_err(|err| {
                    s3_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "InternalError",
                        &format!("Failed to decode KMS decrypt response: {err}"),
                        resource,
                    )
                })?
                .plaintext_base64
        }
        KmsProviderKind::VaultTransit => {
            let key_id = meta
                .encryption
                .kms_key_id
                .clone()
                .unwrap_or_else(|| "rustio-default-kms-key".to_string());
            let key_path = utf8_percent_encode(&key_id, NON_ALPHANUMERIC).to_string();
            let request = VaultTransitDecryptDataKeyRequest {
                ciphertext: ciphertext.clone(),
                context: Some(kms_context_base64(meta)),
            };
            let response =
                kms_request_builder(&client, format!("{endpoint}/v1/transit/decrypt/{key_path}"))
                    .json(&request)
                    .send()
                    .await;
            let response = match response {
                Ok(value) => value,
                Err(err) => {
                    mark_kms_health_failure(
                        state,
                        bilingual_s3_message(
                            "KMSUnavailable",
                            &format!("KMS decrypt request failed: {err}"),
                        ),
                    )
                    .await;
                    return Err(s3_kms_unavailable(
                        resource,
                        &format!("KMS decrypt request failed: {err}"),
                    ));
                }
            };
            if !response.status().is_success() {
                mark_kms_health_failure(
                    state,
                    bilingual_s3_message(
                        "KMSUnavailable",
                        &format!("KMS decrypt status: {}", response.status()),
                    ),
                )
                .await;
                return Err(s3_kms_unavailable(
                    resource,
                    &format!("KMS decrypt status: {}", response.status()),
                ));
            }
            response
                .json::<VaultTransitDecryptDataKeyResponseEnvelope>()
                .await
                .map_err(|err| {
                    s3_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "InternalError",
                        &format!("Failed to decode Vault transit decrypt response: {err}"),
                        resource,
                    )
                })?
                .data
                .plaintext
        }
        KmsProviderKind::Kes => {
            let key_id = meta
                .encryption
                .kms_key_id
                .clone()
                .unwrap_or_else(|| "rustio-default-kms-key".to_string());
            let key_path = utf8_percent_encode(&key_id, NON_ALPHANUMERIC).to_string();
            let request = KesDecryptDataKeyRequest {
                ciphertext: ciphertext.clone(),
                associated_data: Some(kms_context_base64(meta)),
            };
            let response =
                kms_request_builder(&client, format!("{endpoint}/v1/key/decrypt/{key_path}"))
                    .json(&request)
                    .send()
                    .await;
            let response = match response {
                Ok(value) => value,
                Err(err) => {
                    mark_kms_health_failure(
                        state,
                        bilingual_s3_message(
                            "KMSUnavailable",
                            &format!("KMS decrypt request failed: {err}"),
                        ),
                    )
                    .await;
                    return Err(s3_kms_unavailable(
                        resource,
                        &format!("KMS decrypt request failed: {err}"),
                    ));
                }
            };
            if !response.status().is_success() {
                mark_kms_health_failure(
                    state,
                    bilingual_s3_message(
                        "KMSUnavailable",
                        &format!("KMS decrypt status: {}", response.status()),
                    ),
                )
                .await;
                return Err(s3_kms_unavailable(
                    resource,
                    &format!("KMS decrypt status: {}", response.status()),
                ));
            }
            response
                .json::<KesDecryptDataKeyResponse>()
                .await
                .map_err(|err| {
                    s3_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "InternalError",
                        &format!("Failed to decode KES decrypt response: {err}"),
                        resource,
                    )
                })?
                .plaintext
        }
    };
    let decoded = BASE64.decode(plaintext_base64).map_err(|err| {
        s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!("Failed to decode KMS plaintext key: {err}"),
            resource,
        )
    })?;
    if decoded.len() != 32 {
        return Err(s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            "KMS plaintext key length is invalid",
            resource,
        ));
    }
    let mut output = [0u8; 32];
    output.copy_from_slice(&decoded[..32]);
    mark_kms_health_success(state).await;
    Ok(Some(output))
}

async fn wrap_object_data_key(
    state: &AppState,
    resource: &str,
    meta: &S3ObjectMeta,
    data_key: &[u8; 32],
) -> Result<String, Response> {
    if let Some(remote_wrapped) =
        kms_encrypt_data_key_remote(state, resource, meta, data_key).await?
    {
        return Ok(remote_wrapped);
    }
    wrap_object_data_key_local(state, resource, meta, data_key)
}

async fn unwrap_object_data_key(
    state: &AppState,
    resource: &str,
    meta: &S3ObjectMeta,
    wrapped_key_base64: &str,
) -> Result<[u8; 32], Response> {
    if let Some(remote_data_key) =
        kms_decrypt_data_key_remote(state, resource, meta, wrapped_key_base64).await?
    {
        return Ok(remote_data_key);
    }
    unwrap_object_data_key_local(state, resource, meta, wrapped_key_base64)
}

async fn encrypt_payload_for_storage(
    state: &AppState,
    resource: &str,
    payload: &[u8],
    meta: &mut S3ObjectMeta,
) -> Result<Vec<u8>, Response> {
    if !encryption_enabled(meta) {
        meta.encryption.nonce_base64 = None;
        meta.encryption.wrapped_key_base64 = None;
        return Ok(payload.to_vec());
    }
    ensure_supported_encryption_algorithm(meta, resource)?;
    if meta.encryption.algorithm.eq_ignore_ascii_case("aws:kms")
        && meta.encryption.kms_key_id.is_none()
    {
        meta.encryption.kms_key_id = Some("rustio-default-kms-key".to_string());
    }
    let payload_nonce = random_12_bytes();
    meta.encryption.nonce_base64 = Some(BASE64.encode(payload_nonce));
    let data_key = random_32_bytes();
    meta.encryption.wrapped_key_base64 =
        Some(wrap_object_data_key(state, resource, meta, &data_key).await?);
    let cipher = Aes256Gcm::new_from_slice(&data_key).map_err(|err| {
        s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!("Failed to initialize object encryption cipher: {err}"),
            resource,
        )
    })?;
    cipher
        .encrypt(Nonce::from_slice(&payload_nonce), payload)
        .map_err(|_| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                "Failed to encrypt object payload",
                resource,
            )
        })
}

async fn decrypt_payload_from_storage(
    state: &AppState,
    resource: &str,
    payload: Vec<u8>,
    meta: Option<&S3ObjectMeta>,
) -> Result<Vec<u8>, Response> {
    let Some(meta) = meta else {
        return Ok(payload);
    };
    if !encryption_enabled(meta) {
        return Ok(payload);
    }
    ensure_supported_encryption_algorithm(meta, resource)?;
    let nonce_base64 = meta.encryption.nonce_base64.as_deref().ok_or_else(|| {
        s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            "Missing object encryption nonce metadata",
            resource,
        )
    })?;
    let nonce = BASE64.decode(nonce_base64).map_err(|err| {
        s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!("Failed to decode object encryption nonce: {err}"),
            resource,
        )
    })?;
    if nonce.len() != 12 {
        return Err(s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            "Object encryption nonce length is invalid",
            resource,
        ));
    }
    let data_key = if let Some(wrapped) = meta.encryption.wrapped_key_base64.as_deref() {
        unwrap_object_data_key(state, resource, meta, wrapped).await?
    } else {
        derive_object_encryption_key(state, meta)
    };
    let cipher = Aes256Gcm::new_from_slice(&data_key).map_err(|err| {
        s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!("Failed to initialize object decryption cipher: {err}"),
            resource,
        )
    })?;
    cipher
        .decrypt(Nonce::from_slice(&nonce), payload.as_ref())
        .map_err(|_| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                "Failed to decrypt object payload",
                resource,
            )
        })
}

async fn cleanup_ec_written_shards(shards: &[EcShardInfo]) -> usize {
    let mut cleanup_failed = 0usize;
    for shard in shards {
        if shard.checksum.is_empty() {
            continue;
        }
        if let Err(err) = tokio::fs::remove_file(&shard.path).await {
            if err.kind() != std::io::ErrorKind::NotFound {
                cleanup_failed += 1;
            }
        }
    }
    cleanup_failed
}

async fn write_ec_object(
    state: &AppState,
    bucket: &str,
    key: &str,
    payload: &[u8],
    meta: &mut S3ObjectMeta,
) -> Result<(), Response> {
    let payload = encrypt_payload_for_storage(state, key, payload, meta).await?;
    let (data_shards, parity_shards) = ec_layout();
    let total_shards = data_shards + parity_shards;
    if state.data_disks.len() < total_shards {
        return Err(s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            "erasure disk count is not enough",
            key,
        ));
    }
    let placement =
        preferred_storage_disk_indices_for_key(state, key, total_shards, &HashSet::new())
            .await
            .map_err(|message| {
                s3_error(
                    StatusCode::INTERNAL_SERVER_ERROR,
                    "InternalError",
                    &message,
                    key,
                )
            })?;

    let bucket_root = bucket_path(state, bucket)?;
    let shard_size = payload.len().div_ceil(data_shards).max(1);
    let mut shards = vec![vec![0u8; shard_size]; total_shards];
    for (index, byte) in payload.iter().enumerate() {
        let shard_index = index / shard_size;
        let offset = index % shard_size;
        if shard_index < data_shards {
            shards[shard_index][offset] = *byte;
        }
    }
    let reed_solomon = ReedSolomon::new(data_shards, parity_shards).map_err(|err| {
        s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!("Failed to create Reed-Solomon encoder: {err}"),
            key,
        )
    })?;
    reed_solomon.encode(&mut shards).map_err(|err| {
        s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!("Failed to encode Reed-Solomon shards: {err}"),
            key,
        )
    })?;

    let object_hash = sha256_hex(key.as_bytes());
    let mut shard_infos = Vec::with_capacity(total_shards);
    let mut successful_shards = 0usize;
    for shard_index in 0..total_shards {
        let disk_index = placement[shard_index];
        let shard_path = state.data_disks[disk_index]
            .join(bucket)
            .join(".rustio_ec")
            .join(&object_hash)
            .join(format!("{shard_index}.bin"));
        let mut checksum = String::new();
        let mut write_failed = false;
        if let Some(parent) = shard_path.parent() {
            if tokio::fs::create_dir_all(parent).await.is_err() {
                write_failed = true;
            }
        } else {
            write_failed = true;
        }
        if !write_failed
            && tokio::fs::write(&shard_path, &shards[shard_index])
                .await
                .is_ok()
        {
            checksum = sha256_hex(&shards[shard_index]);
            successful_shards += 1;
        }
        shard_infos.push(EcShardInfo {
            shard_index,
            disk_index,
            path: shard_path,
            checksum,
        });
    }
    if successful_shards < data_shards {
        let cleanup_failed = cleanup_ec_written_shards(&shard_infos).await;
        return Err(s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!(
                "纠删码写入未达到法定票数（{successful_shards}/{data_shards}），已回滚已写分片，清理失败 {cleanup_failed} 个 / erasure write quorum not reached ({successful_shards}/{data_shards}); written shards rolled back, cleanup failed for {cleanup_failed} shard(s)"
            ),
            key,
        ));
    }

    let manifest = EcObjectManifest {
        bucket: bucket.to_string(),
        key: key.to_string(),
        total_size: payload.len() as u64,
        shard_size,
        data_shards,
        parity_shards,
        shards: shard_infos.clone(),
        updated_at: Utc::now(),
    };
    let manifest_path = ec_manifest_path(&bucket_root, key);
    if let Some(parent) = manifest_path.parent() {
        if let Err(err) = tokio::fs::create_dir_all(parent).await {
            let cleanup_failed = cleanup_ec_written_shards(&shard_infos).await;
            return Err(s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!(
                    "创建纠删码清单目录失败，已回滚已写分片：{err}，清理失败 {cleanup_failed} 个 / failed to create erasure manifest directory; written shards rolled back: {err}; cleanup failed for {cleanup_failed} shard(s)"
                ),
                key,
            ));
        }
    }
    let bytes = serde_json::to_vec_pretty(&manifest).map_err(|err| {
        s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!("Failed to encode erasure manifest: {err}"),
            key,
        )
    })?;
    if let Err(err) = tokio::fs::write(&manifest_path, bytes).await {
        let cleanup_failed = cleanup_ec_written_shards(&shard_infos).await;
        return Err(s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!(
                "写入纠删码清单失败，已回滚已写分片：{err}，清理失败 {cleanup_failed} 个 / failed to persist erasure manifest; written shards rolled back: {err}; cleanup failed for {cleanup_failed} shard(s)"
            ),
            key,
        ));
    }
    Ok(())
}

async fn read_ec_object(
    state: &AppState,
    bucket: &str,
    key: &str,
    meta: Option<&S3ObjectMeta>,
) -> Result<Option<Vec<u8>>, Response> {
    let bucket_root = bucket_path(state, bucket)?;
    let manifest_path = ec_manifest_path(&bucket_root, key);
    let manifest_bytes = match tokio::fs::read(&manifest_path).await {
        Ok(bytes) => bytes,
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => return Ok(None),
        Err(err) => {
            return Err(s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to read erasure manifest: {err}"),
                key,
            ));
        }
    };
    let mut manifest = match serde_json::from_slice::<EcObjectManifest>(&manifest_bytes) {
        Ok(manifest) => manifest,
        Err(err) => {
            let _ = upsert_storage_job(
                state,
                StorageJobDraft {
                    kind: "scrub".to_string(),
                    target: format!("{bucket}/{key}"),
                    bucket: Some(bucket.to_string()),
                    key: Some(key.to_string()),
                    version_id: meta.map(|item| item.version_id.clone()),
                    priority: Some(900),
                    affected_disks: vec![],
                    missing_shards: 0,
                    corrupted_shards: 0,
                    source: "read_failure".to_string(),
                    details: json!({
                        "bucket": bucket,
                        "key": key,
                        "error": err.to_string(),
                    }),
                },
                "pending",
            )
            .await;
            return Err(s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to decode erasure manifest: {err}"),
                key,
            ));
        }
    };
    if manifest.data_shards == 0 {
        return Ok(None);
    }

    let total_shards = manifest.data_shards + manifest.parity_shards;
    if manifest.shards.len() < total_shards {
        let existing = manifest
            .shards
            .iter()
            .map(|shard| shard.shard_index)
            .collect::<HashSet<_>>();
        let object_hash = sha256_hex(key.as_bytes());
        for shard_index in 0..total_shards {
            if existing.contains(&shard_index) {
                continue;
            }
            let disk_index = manifest_disk_index_for_shard(&manifest, shard_index)
                .unwrap_or(shard_index % state.data_disks.len().max(1));
            let shard_path = state.data_disks[disk_index]
                .join(bucket)
                .join(".rustio_ec")
                .join(&object_hash)
                .join(format!("{shard_index}.bin"));
            manifest.shards.push(EcShardInfo {
                shard_index,
                disk_index,
                path: shard_path,
                checksum: String::new(),
            });
        }
    }
    let reed_solomon =
        ReedSolomon::new(manifest.data_shards, manifest.parity_shards).map_err(|err| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to create Reed-Solomon decoder: {err}"),
                key,
            )
        })?;
    let mut loaded = vec![None::<Vec<u8>>; total_shards];
    let mut failed = HashSet::new();
    for shard in &manifest.shards {
        if shard.shard_index >= total_shards {
            continue;
        }
        let bytes = match tokio::fs::read(&shard.path).await {
            Ok(bytes) => bytes,
            Err(_) => {
                failed.insert(shard.shard_index);
                continue;
            }
        };
        if bytes.len() != manifest.shard_size || sha256_hex(&bytes) != shard.checksum {
            failed.insert(shard.shard_index);
            continue;
        }
        loaded[shard.shard_index] = Some(bytes);
    }
    let existing = manifest
        .shards
        .iter()
        .map(|shard| shard.shard_index)
        .collect::<HashSet<_>>();
    for shard_index in 0..total_shards {
        if !existing.contains(&shard_index) || loaded[shard_index].is_none() {
            failed.insert(shard_index);
        }
    }

    let available_shards = loaded.iter().filter(|item| item.is_some()).count();
    if available_shards < manifest.data_shards {
        let affected_disks = failed
            .iter()
            .map(|shard_index| {
                manifest_disk_id_for_shard(&manifest, *shard_index, state.data_disks.len())
            })
            .collect::<Vec<_>>();
        let _ = upsert_storage_job(
            state,
            StorageJobDraft {
                kind: "rebuild".to_string(),
                target: format!("{bucket}/{key}"),
                bucket: Some(bucket.to_string()),
                key: Some(key.to_string()),
                version_id: meta.map(|item| item.version_id.clone()),
                priority: Some(1200),
                affected_disks,
                missing_shards: failed.len(),
                corrupted_shards: 0,
                source: "read_failure".to_string(),
                details: json!({
                    "bucket": bucket,
                    "key": key,
                    "available_shards": available_shards,
                    "required_shards": manifest.data_shards,
                }),
            },
            "pending",
        )
        .await;
        return Err(s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!(
                "纠删码读取未达到法定票数：可用分片 {available_shards}/{total_shards}，至少需要 {} / erasure read quorum not reached: {available_shards}/{total_shards} shards available, need at least {}",
                manifest.data_shards,
                manifest.data_shards
            ),
            key,
        ));
    }
    if failed.len() > manifest.parity_shards {
        let affected_disks = failed
            .iter()
            .map(|shard_index| {
                manifest_disk_id_for_shard(&manifest, *shard_index, state.data_disks.len())
            })
            .collect::<Vec<_>>();
        let _ = upsert_storage_job(
            state,
            StorageJobDraft {
                kind: "rebuild".to_string(),
                target: format!("{bucket}/{key}"),
                bucket: Some(bucket.to_string()),
                key: Some(key.to_string()),
                version_id: meta.map(|item| item.version_id.clone()),
                priority: Some(1300),
                affected_disks,
                missing_shards: failed.len(),
                corrupted_shards: failed.len(),
                source: "read_failure".to_string(),
                details: json!({
                    "bucket": bucket,
                    "key": key,
                    "failed_shards": failed.len(),
                    "parity_shards": manifest.parity_shards,
                }),
            },
            "pending",
        )
        .await;
        return Err(s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            "纠删码分片损坏超出奇偶校验恢复能力 / erasure shards corrupted beyond parity recovery",
            key,
        ));
    }
    if !failed.is_empty() {
        reed_solomon.reconstruct(&mut loaded).map_err(|err| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to reconstruct Reed-Solomon shards: {err}"),
                key,
            )
        })?;
        for shard_info in manifest.shards.iter_mut() {
            if !failed.contains(&shard_info.shard_index) {
                continue;
            }
            let Some(recovered) = loaded
                .get(shard_info.shard_index)
                .and_then(|item| item.as_ref())
            else {
                continue;
            };
            if let Some(parent) = shard_info.path.parent() {
                tokio::fs::create_dir_all(parent).await.map_err(|err| {
                    s3_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "InternalError",
                        &format!("Failed to create shard directory during recovery: {err}"),
                        key,
                    )
                })?;
            }
            tokio::fs::write(&shard_info.path, recovered)
                .await
                .map_err(|err| {
                    s3_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "InternalError",
                        &format!("Failed to persist recovered shard: {err}"),
                        key,
                    )
                })?;
            shard_info.checksum = sha256_hex(recovered);
        }
        let updated_manifest = serde_json::to_vec_pretty(&manifest).map_err(|err| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to encode recovered manifest: {err}"),
                key,
            )
        })?;
        tokio::fs::write(&manifest_path, updated_manifest)
            .await
            .map_err(|err| {
                s3_error(
                    StatusCode::INTERNAL_SERVER_ERROR,
                    "InternalError",
                    &format!("Failed to persist recovered manifest: {err}"),
                    key,
                )
            })?;
    }

    let mut payload = Vec::with_capacity(manifest.total_size as usize);
    for shard_index in 0..manifest.data_shards {
        let Some(bytes) = loaded[shard_index].as_ref() else {
            return Err(s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                "缺少纠删码数据分片 / missing erasure data shard",
                key,
            ));
        };
        payload.extend_from_slice(bytes);
    }
    payload.truncate(manifest.total_size as usize);
    touch_object_access_heat(state, bucket, key).await;
    Ok(Some(
        decrypt_payload_from_storage(state, key, payload, meta).await?,
    ))
}

async fn remove_ec_object(state: &AppState, bucket: &str, key: &str) -> Result<(), Response> {
    let bucket_root = bucket_path(state, bucket)?;
    let manifest_path = ec_manifest_path(&bucket_root, key);
    let manifest_bytes = match tokio::fs::read(&manifest_path).await {
        Ok(bytes) => bytes,
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => return Ok(()),
        Err(err) => {
            return Err(s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to read erasure manifest: {err}"),
                key,
            ));
        }
    };
    if let Ok(manifest) = serde_json::from_slice::<EcObjectManifest>(&manifest_bytes) {
        for shard in manifest.shards {
            let _ = tokio::fs::remove_file(shard.path).await;
        }
    }
    let _ = tokio::fs::remove_file(&manifest_path).await;
    Ok(())
}

fn bucket_path(state: &AppState, bucket: &str) -> Result<PathBuf, Response> {
    if !valid_bucket_name(bucket) {
        return Err(s3_error(
            StatusCode::BAD_REQUEST,
            "InvalidBucketName",
            "The specified bucket is not valid.",
            bucket,
        ));
    }

    if let Some(path) = failover_bucket_path(state, bucket) {
        let _ = std::fs::create_dir_all(&path);
        return Ok(path);
    }
    Ok(state.data_dir.join(bucket))
}

fn failover_bucket_path(state: &AppState, bucket: &str) -> Option<PathBuf> {
    let sites = state.site_replications.try_read().ok()?;
    let active_site = sites
        .iter()
        .find(|site| site.role == "primary" && !site.preferred_primary)?
        .site_id
        .clone();
    drop(sites);

    let rules = state.replications.try_read().ok()?;
    let managed = rules.iter().any(|rule| {
        rule.source_bucket == bucket && rule.target_site == active_site && rule.status != "paused"
    });
    drop(rules);
    if !managed {
        return None;
    }

    Some(
        state
            .data_dir
            .join(".rustio_sites")
            .join(active_site)
            .join("data")
            .join(bucket),
    )
}

fn bucket_policy_path(bucket_root: &FsPath) -> PathBuf {
    bucket_root.join(".rustio_meta").join("bucket-policy.json")
}

fn bucket_lifecycle_path(bucket_root: &FsPath) -> PathBuf {
    bucket_root
        .join(".rustio_meta")
        .join("bucket-lifecycle.json")
}

fn bucket_notifications_path(bucket_root: &FsPath) -> PathBuf {
    bucket_root
        .join(".rustio_meta")
        .join("bucket-notifications.json")
}

fn bucket_acl_path(bucket_root: &FsPath) -> PathBuf {
    bucket_root.join(".rustio_meta").join("bucket-acl.json")
}

fn bucket_public_access_block_path(bucket_root: &FsPath) -> PathBuf {
    bucket_root
        .join(".rustio_meta")
        .join("bucket-public-access-block.json")
}

fn bucket_cors_path(bucket_root: &FsPath) -> PathBuf {
    bucket_root.join(".rustio_meta").join("bucket-cors.json")
}

fn bucket_tags_path(bucket_root: &FsPath) -> PathBuf {
    bucket_root.join(".rustio_meta").join("bucket-tags.json")
}

fn bucket_encryption_path(bucket_root: &FsPath) -> PathBuf {
    bucket_root
        .join(".rustio_meta")
        .join("bucket-encryption.json")
}

fn object_path(bucket_root: &FsPath, key: &str) -> Result<PathBuf, Response> {
    if key.is_empty() {
        return Err(s3_error(
            StatusCode::BAD_REQUEST,
            "InvalidObjectName",
            "Object key cannot be empty",
            key,
        ));
    }

    let key_path = FsPath::new(key);
    for component in key_path.components() {
        match component {
            Component::Normal(_) => {}
            _ => {
                return Err(s3_error(
                    StatusCode::BAD_REQUEST,
                    "InvalidObjectName",
                    "Invalid object key path",
                    key,
                ));
            }
        }
    }
    Ok(bucket_root.join(key_path))
}

fn is_reserved_internal_key(key: &str) -> bool {
    key == ".rustio_meta"
        || key.starts_with(".rustio_meta/")
        || key == ".rustio_versions"
        || key.starts_with(".rustio_versions/")
}

fn object_meta_path(bucket_root: &FsPath, key: &str) -> Result<PathBuf, Response> {
    let mut meta_key = key.to_string();
    meta_key.push_str(".json");
    object_path(&bucket_root.join(".rustio_meta"), &meta_key)
}

fn valid_version_id(version_id: &str) -> bool {
    !version_id.is_empty()
        && version_id.len() <= 128
        && version_id.bytes().all(|byte| {
            byte.is_ascii_alphanumeric() || byte == b'-' || byte == b'_' || byte == b'.'
        })
}

fn object_versions_dir(bucket_root: &FsPath, key: &str) -> PathBuf {
    bucket_root
        .join(".rustio_versions")
        .join(sha256_hex(key.as_bytes()))
}

fn object_version_meta_path(
    bucket_root: &FsPath,
    key: &str,
    version_id: &str,
) -> Result<PathBuf, Response> {
    if !valid_version_id(version_id) {
        return Err(s3_error(
            StatusCode::BAD_REQUEST,
            "InvalidVersionId",
            "The specified version id is not valid",
            key,
        ));
    }
    Ok(object_versions_dir(bucket_root, key).join(format!("{version_id}.json")))
}

fn object_version_payload_path(
    bucket_root: &FsPath,
    key: &str,
    version_id: &str,
) -> Result<PathBuf, Response> {
    if !valid_version_id(version_id) {
        return Err(s3_error(
            StatusCode::BAD_REQUEST,
            "InvalidVersionId",
            "The specified version id is not valid",
            key,
        ));
    }
    Ok(object_versions_dir(bucket_root, key).join(format!("{version_id}.bin")))
}

fn remote_tier_root_path(config: &RemoteTierConfig) -> Result<PathBuf, String> {
    if !matches!(
        remote_tier_backend_kind(config)?,
        RemoteTierBackendKind::Filesystem
    ) {
        return Err(
            "仅 filesystem backend 支持本地路径 / only filesystem backend supports local paths"
                .to_string(),
        );
    }
    let endpoint = config.endpoint.trim();
    let path = endpoint
        .strip_prefix("file://")
        .unwrap_or(endpoint)
        .trim()
        .to_string();
    if path.is_empty() {
        return Err("远端层端点不能为空 / remote tier endpoint cannot be empty".to_string());
    }
    Ok(PathBuf::from(path))
}

fn remote_tier_object_name(
    config: &RemoteTierConfig,
    key: &str,
    version_id: &str,
    extension: &str,
) -> Result<String, String> {
    if !valid_version_id(version_id) {
        return Err("版本号无效 / invalid version id".to_string());
    }
    let mut parts = Vec::new();
    if let Some(prefix) = config.prefix.as_deref() {
        parts.extend(
            prefix
                .trim_matches('/')
                .split('/')
                .filter(|part| !part.trim().is_empty())
                .map(|part| part.trim().to_string()),
        );
    }
    parts.push(sha256_hex(key.as_bytes()));
    parts.push(format!("{version_id}.{extension}"));
    Ok(parts.join("/"))
}

fn remote_tier_object_dir(
    config: &RemoteTierConfig,
    bucket: &str,
    key: &str,
) -> Result<PathBuf, String> {
    let mut root = remote_tier_root_path(config)?;
    root.push(bucket);
    if let Some(prefix) = config.prefix.as_deref() {
        if !prefix.trim().is_empty() {
            root.push(prefix.trim());
        }
    }
    root.push(sha256_hex(key.as_bytes()));
    Ok(root)
}

fn remote_tier_object_meta_path(
    config: &RemoteTierConfig,
    bucket: &str,
    key: &str,
    version_id: &str,
) -> Result<PathBuf, String> {
    if !valid_version_id(version_id) {
        return Err("版本号无效 / invalid version id".to_string());
    }
    Ok(remote_tier_object_dir(config, bucket, key)?.join(format!("{version_id}.json")))
}

fn remote_tier_object_payload_path(
    config: &RemoteTierConfig,
    bucket: &str,
    key: &str,
    version_id: &str,
) -> Result<PathBuf, String> {
    if !valid_version_id(version_id) {
        return Err("版本号无效 / invalid version id".to_string());
    }
    Ok(remote_tier_object_dir(config, bucket, key)?.join(format!("{version_id}.bin")))
}

fn remote_tier_http_object_url(
    config: &RemoteTierConfig,
    bucket: &str,
    key: &str,
    version_id: &str,
    extension: &str,
) -> Result<String, String> {
    let base = config.endpoint.trim().trim_end_matches('/');
    let bucket_component = url_encode_component(bucket);
    let object_name = remote_tier_object_name(config, key, version_id, extension)?;
    match remote_tier_backend_kind(config)? {
        RemoteTierBackendKind::Gcs => Ok(format!(
            "{base}/storage/v1/b/{bucket_component}/o/{}?alt=media",
            url_encode_component(&object_name)
        )),
        RemoteTierBackendKind::Filesystem => Err(
            "filesystem backend 不支持 HTTP URL / filesystem backend does not support http urls"
                .to_string(),
        ),
        RemoteTierBackendKind::S3Compatible
        | RemoteTierBackendKind::Minio
        | RemoteTierBackendKind::AzureBlob => {
            let encoded = object_name
                .split('/')
                .map(url_encode_component)
                .collect::<Vec<_>>()
                .join("/");
            Ok(format!("{base}/{bucket_component}/{encoded}"))
        }
    }
}

fn remote_tier_http_upload_url(
    config: &RemoteTierConfig,
    bucket: &str,
    key: &str,
    version_id: &str,
    extension: &str,
) -> Result<String, String> {
    let base = config.endpoint.trim().trim_end_matches('/');
    let bucket_component = url_encode_component(bucket);
    let object_name = remote_tier_object_name(config, key, version_id, extension)?;
    match remote_tier_backend_kind(config)? {
        RemoteTierBackendKind::Gcs => Ok(format!(
            "{base}/upload/storage/v1/b/{bucket_component}/o?uploadType=media&name={}",
            url_encode_component(&object_name)
        )),
        _ => remote_tier_http_object_url(config, bucket, key, version_id, extension),
    }
}

fn remote_tier_http_client() -> Result<Client, String> {
    Client::builder()
        .timeout(std::time::Duration::from_secs(5))
        .build()
        .map_err(|err| {
            format!("创建远端层客户端失败 / failed to initialize remote tier client: {err}")
        })
}

fn remote_tier_http_request_builder(
    client: &Client,
    config: &RemoteTierConfig,
    method: reqwest::Method,
    url: String,
) -> reqwest::RequestBuilder {
    let mut request = client.request(method.clone(), url);
    if let Some(token) = config.credential_token.as_deref() {
        request = request.bearer_auth(token);
    }
    if let (Some(username), Some(password)) = (
        config.credential_key.as_deref(),
        config.credential_secret.as_deref(),
    ) {
        request = request.basic_auth(username, Some(password));
    }
    for (key, value) in &config.extra_headers {
        request = request.header(key, value);
    }
    if matches!(
        remote_tier_backend_kind(config),
        Ok(RemoteTierBackendKind::AzureBlob)
    ) {
        request = request.header("x-ms-version", "2023-11-03");
        if method == reqwest::Method::PUT {
            request = request.header("x-ms-blob-type", "BlockBlob");
        }
    }
    request
}

async fn update_remote_tier_runtime<F>(state: &AppState, tier_name: &str, mutate: F)
where
    F: FnOnce(&mut RemoteTierConfig),
{
    let snapshot = {
        let mut tiers = state.remote_tiers.write().await;
        let Some(tier) = tiers.get_mut(&normalize_remote_tier_name(tier_name)) else {
            return;
        };
        mutate(tier);
        tiers.clone()
    };
    let _ = AppState::persist_remote_tiers_snapshot(&state.data_dir, &snapshot);
}

async fn mark_remote_tier_health_failure(
    state: &AppState,
    tier_name: &str,
    message: impl Into<String>,
) {
    let now = Utc::now();
    let message = message.into();
    update_remote_tier_runtime(state, tier_name, move |tier| {
        tier.health_status = if tier.enabled {
            "degraded".to_string()
        } else {
            "paused".to_string()
        };
        tier.last_checked_at = Some(now);
        tier.last_error = Some(message.clone());
    })
    .await;
}

async fn mark_remote_tier_health_success(state: &AppState, tier_name: &str) {
    let now = Utc::now();
    update_remote_tier_runtime(state, tier_name, move |tier| {
        tier.health_status = if tier.enabled {
            "healthy".to_string()
        } else {
            "paused".to_string()
        };
        tier.last_checked_at = Some(now);
        tier.last_success_at = Some(now);
        tier.last_error = None;
    })
    .await;
}

async fn probe_remote_tier_connectivity(mut config: RemoteTierConfig) -> RemoteTierConfig {
    let now = Utc::now();
    config.last_checked_at = Some(now);
    if !config.enabled {
        config.health_status = "paused".to_string();
        config.last_error = None;
        return config;
    }

    let result = match remote_tier_backend_kind(&config) {
        Ok(RemoteTierBackendKind::Filesystem) => match remote_tier_root_path(&config) {
            Ok(path) => tokio::fs::create_dir_all(path).await.map_err(|err| {
                format!("创建远端层目录失败 / failed to create remote tier directory: {err}")
            }),
            Err(err) => Err(err),
        },
        Ok(_) => match remote_tier_http_client() {
            Ok(client) => {
                let response = remote_tier_http_request_builder(
                    &client,
                    &config,
                    reqwest::Method::GET,
                    config.endpoint.trim().to_string(),
                )
                .send()
                .await;
                match response {
                    Ok(response) if !response.status().is_server_error() => Ok(()),
                    Ok(response) => Err(format!(
                        "远端层健康检查返回非可用状态：{} / remote tier health probe returned unavailable status: {}",
                        response.status(),
                        response.status()
                    )),
                    Err(err) => Err(format!(
                        "远端层健康检查失败 / remote tier health probe failed: {err}"
                    )),
                }
            }
            Err(err) => Err(err),
        },
        Err(err) => Err(err),
    };

    match result {
        Ok(()) => {
            config.health_status = "healthy".to_string();
            config.last_success_at = Some(now);
            config.last_error = None;
        }
        Err(err) => {
            config.health_status = "degraded".to_string();
            config.last_error = Some(err);
        }
    }
    config
}

async fn lookup_remote_tier_config(
    state: &AppState,
    tier_name: &str,
) -> Result<RemoteTierConfig, String> {
    let normalized_name = normalize_remote_tier_name(tier_name);
    let tiers = state.remote_tiers.read().await;
    let Some(config) = tiers.get(&normalized_name).cloned() else {
        return Err(format!(
            "远端层不存在：{normalized_name} / remote tier not found: {normalized_name}"
        ));
    };
    if !config.enabled {
        return Err(format!(
            "远端层未启用：{normalized_name} / remote tier is disabled: {normalized_name}"
        ));
    }
    Ok(config)
}

async fn read_remote_tier_payload_for_meta(
    state: &AppState,
    meta: &S3ObjectMeta,
) -> Result<Option<Vec<u8>>, Response> {
    let Some(remote_tier) = meta.remote_tier.as_ref() else {
        return Ok(None);
    };
    let config = match lookup_remote_tier_config(state, &remote_tier.tier).await {
        Ok(config) => config,
        Err(_) => return Ok(None),
    };
    let bytes = match remote_tier_backend_kind(&config) {
        Ok(RemoteTierBackendKind::Filesystem) => {
            let payload_path =
                remote_tier_object_payload_path(&config, &meta.bucket, &meta.key, &meta.version_id)
                    .map_err(|err| {
                        s3_error(
                            StatusCode::INTERNAL_SERVER_ERROR,
                            "InternalError",
                            &err,
                            &meta.key,
                        )
                    })?;
            match tokio::fs::read(&payload_path).await {
                Ok(bytes) => bytes,
                Err(err) if err.kind() == std::io::ErrorKind::NotFound => return Ok(None),
                Err(err) => {
                    mark_remote_tier_health_failure(
                        state,
                        &config.name,
                        format!("读取远端层对象失败 / failed to read remote tier object: {err}"),
                    )
                    .await;
                    return Err(s3_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "InternalError",
                        &format!("Failed to read remote tier payload: {err}"),
                        &meta.key,
                    ));
                }
            }
        }
        Ok(_) => {
            let url = remote_tier_http_object_url(
                &config,
                &meta.bucket,
                &meta.key,
                &meta.version_id,
                "bin",
            )
            .map_err(|err| {
                s3_error(
                    StatusCode::INTERNAL_SERVER_ERROR,
                    "InternalError",
                    &err,
                    &meta.key,
                )
            })?;
            let client = remote_tier_http_client().map_err(|err| {
                s3_error(
                    StatusCode::INTERNAL_SERVER_ERROR,
                    "InternalError",
                    &err,
                    &meta.key,
                )
            })?;
            let response =
                remote_tier_http_request_builder(&client, &config, reqwest::Method::GET, url)
                    .send()
                    .await
                    .map_err(|err| {
                        s3_error(
                            StatusCode::INTERNAL_SERVER_ERROR,
                            "InternalError",
                            &format!("Failed to read remote tier payload: {err}"),
                            &meta.key,
                        )
                    })?;
            if response.status() == reqwest::StatusCode::NOT_FOUND {
                return Ok(None);
            }
            if !response.status().is_success() {
                mark_remote_tier_health_failure(
                    state,
                    &config.name,
                    format!(
                        "远端层读取返回异常状态：{} / remote tier read returned unexpected status: {}",
                        response.status(),
                        response.status()
                    ),
                )
                .await;
                return Err(s3_error(
                    StatusCode::INTERNAL_SERVER_ERROR,
                    "InternalError",
                    &format!("Failed to read remote tier payload: {}", response.status()),
                    &meta.key,
                ));
            }
            response
                .bytes()
                .await
                .map_err(|err| {
                    s3_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "InternalError",
                        &format!("Failed to decode remote tier payload: {err}"),
                        &meta.key,
                    )
                })?
                .to_vec()
        }
        Err(err) => {
            return Err(s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &err,
                &meta.key,
            ))
        }
    };
    mark_remote_tier_health_success(state, &config.name).await;
    Ok(Some(bytes))
}

async fn persist_remote_tier_object(
    state: &AppState,
    config: &RemoteTierConfig,
    meta: &S3ObjectMeta,
    payload: &[u8],
) -> Result<(), String> {
    let meta_bytes = serde_json::to_vec_pretty(meta).map_err(|err| {
        format!("编码远端层元数据失败 / failed to encode remote tier metadata: {err}")
    })?;
    let result: Result<(), String> = match remote_tier_backend_kind(config)? {
        RemoteTierBackendKind::Filesystem => {
            let payload_path =
                remote_tier_object_payload_path(config, &meta.bucket, &meta.key, &meta.version_id)?;
            let meta_path =
                remote_tier_object_meta_path(config, &meta.bucket, &meta.key, &meta.version_id)?;
            if let Some(parent) = payload_path.parent() {
                tokio::fs::create_dir_all(parent).await.map_err(|err| {
                    format!("创建远端层目录失败 / failed to create remote tier directory: {err}")
                })?;
            }
            tokio::fs::write(&payload_path, payload)
                .await
                .map_err(|err| {
                    format!("写入远端层对象失败 / failed to persist remote tier object: {err}")
                })?;
            tokio::fs::write(&meta_path, meta_bytes)
                .await
                .map_err(|err| {
                    format!("写入远端层元数据失败 / failed to persist remote tier metadata: {err}")
                })?;
            Ok(())
        }
        RemoteTierBackendKind::S3Compatible
        | RemoteTierBackendKind::Minio
        | RemoteTierBackendKind::AzureBlob
        | RemoteTierBackendKind::Gcs => {
            let client = remote_tier_http_client()?;
            let payload_url = remote_tier_http_upload_url(
                config,
                &meta.bucket,
                &meta.key,
                &meta.version_id,
                "bin",
            )?;
            let meta_url = remote_tier_http_upload_url(
                config,
                &meta.bucket,
                &meta.key,
                &meta.version_id,
                "json",
            )?;
            let payload_method = if matches!(
                remote_tier_backend_kind(config),
                Ok(RemoteTierBackendKind::Gcs)
            ) {
                reqwest::Method::POST
            } else {
                reqwest::Method::PUT
            };
            let payload_response = remote_tier_http_request_builder(
                &client,
                config,
                payload_method.clone(),
                payload_url,
            )
            .header(CONTENT_TYPE.as_str(), "application/octet-stream")
            .body(payload.to_vec())
            .send()
            .await
            .map_err(|err| {
                format!("写入远端层对象失败 / failed to persist remote tier object: {err}")
            })?;
            if !payload_response.status().is_success() {
                return Err(format!(
                    "写入远端层对象返回非成功状态：{} / failed to persist remote tier object with status {}",
                    payload_response.status(),
                    payload_response.status()
                ));
            }
            let meta_response =
                remote_tier_http_request_builder(&client, config, payload_method, meta_url)
                    .header(CONTENT_TYPE.as_str(), "application/json")
                    .body(meta_bytes)
                    .send()
                    .await
                    .map_err(|err| {
                        format!(
                            "写入远端层元数据失败 / failed to persist remote tier metadata: {err}"
                        )
                    })?;
            if !meta_response.status().is_success() {
                return Err(format!(
                    "写入远端层元数据返回非成功状态：{} / failed to persist remote tier metadata with status {}",
                    meta_response.status(),
                    meta_response.status()
                ));
            }
            Ok(())
        }
    };
    match result {
        Ok(()) => {
            mark_remote_tier_health_success(state, &config.name).await;
            Ok(())
        }
        Err(err) => {
            mark_remote_tier_health_failure(state, &config.name, err.clone()).await;
            Err(err)
        }
    }
}

async fn remove_remote_tier_payload_for_meta(
    state: &AppState,
    meta: &S3ObjectMeta,
) -> Result<(), Response> {
    let Some(remote_tier) = meta.remote_tier.as_ref() else {
        return Ok(());
    };
    let config = match lookup_remote_tier_config(state, &remote_tier.tier).await {
        Ok(config) => config,
        Err(_) => return Ok(()),
    };
    let result = match remote_tier_backend_kind(&config) {
        Ok(RemoteTierBackendKind::Filesystem) => {
            let meta_path =
                remote_tier_object_meta_path(&config, &meta.bucket, &meta.key, &meta.version_id)
                    .map_err(|err| {
                        s3_error(
                            StatusCode::INTERNAL_SERVER_ERROR,
                            "InternalError",
                            &err,
                            &meta.key,
                        )
                    })?;
            let payload_path =
                remote_tier_object_payload_path(&config, &meta.bucket, &meta.key, &meta.version_id)
                    .map_err(|err| {
                        s3_error(
                            StatusCode::INTERNAL_SERVER_ERROR,
                            "InternalError",
                            &err,
                            &meta.key,
                        )
                    })?;
            match tokio::fs::remove_file(&meta_path).await {
                Ok(_) => {}
                Err(err) if err.kind() == std::io::ErrorKind::NotFound => {}
                Err(err) => {
                    return Err(s3_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "InternalError",
                        &format!("Failed to remove remote tier metadata: {err}"),
                        &meta.key,
                    ))
                }
            }
            match tokio::fs::remove_file(&payload_path).await {
                Ok(_) => {}
                Err(err) if err.kind() == std::io::ErrorKind::NotFound => {}
                Err(err) => {
                    return Err(s3_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "InternalError",
                        &format!("Failed to remove remote tier payload: {err}"),
                        &meta.key,
                    ))
                }
            }
            if let Some(parent) = payload_path.parent() {
                let mut root = match remote_tier_root_path(&config) {
                    Ok(path) => path.join(&meta.bucket),
                    Err(_) => return Ok(()),
                };
                if let Some(prefix) = config.prefix.as_deref() {
                    if !prefix.trim().is_empty() {
                        root = root.join(prefix.trim());
                    }
                }
                let _ = remove_empty_dirs_until(parent, &root);
            }
            Ok(())
        }
        Ok(_) => {
            let client = remote_tier_http_client().map_err(|err| {
                s3_error(
                    StatusCode::INTERNAL_SERVER_ERROR,
                    "InternalError",
                    &err,
                    &meta.key,
                )
            })?;
            for extension in ["json", "bin"] {
                let url = remote_tier_http_object_url(
                    &config,
                    &meta.bucket,
                    &meta.key,
                    &meta.version_id,
                    extension,
                )
                .map_err(|err| {
                    s3_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "InternalError",
                        &err,
                        &meta.key,
                    )
                })?;
                let response = remote_tier_http_request_builder(
                    &client,
                    &config,
                    reqwest::Method::DELETE,
                    url,
                )
                .send()
                .await
                .map_err(|err| {
                    s3_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "InternalError",
                        &format!("Failed to remove remote tier payload: {err}"),
                        &meta.key,
                    )
                })?;
                if response.status() != reqwest::StatusCode::NOT_FOUND
                    && !response.status().is_success()
                {
                    return Err(s3_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "InternalError",
                        &format!(
                            "Failed to remove remote tier payload: {}",
                            response.status()
                        ),
                        &meta.key,
                    ));
                }
            }
            Ok(())
        }
        Err(err) => Err(s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &err,
            &meta.key,
        )),
    };
    match result {
        Ok(()) => {
            mark_remote_tier_health_success(state, &config.name).await;
            Ok(())
        }
        Err(err) => {
            mark_remote_tier_health_failure(
                state,
                &config.name,
                format!("删除远端层对象失败 / failed to remove remote tier object"),
            )
            .await;
            Err(err)
        }
    }
}

async fn read_current_object_payload(
    state: &AppState,
    bucket: &str,
    key: &str,
    meta: Option<&S3ObjectMeta>,
) -> Result<Option<Vec<u8>>, Response> {
    if let Some(meta) = meta {
        if object_restore_is_active(meta) {
            if let Some(bytes) = read_current_hot_object_payload(state, bucket, key).await? {
                return Ok(Some(bytes));
            }
        }
        if let Some(bytes) = read_remote_tier_payload_for_meta(state, meta).await? {
            return Ok(Some(bytes));
        }
    }
    match read_ec_object(state, bucket, key, meta).await? {
        Some(bytes) => Ok(Some(bytes)),
        None => {
            let bucket_root = bucket_path(state, bucket)?;
            let target_path = object_path(&bucket_root, key)?;
            let bytes = match tokio::fs::read(&target_path).await {
                Ok(bytes) => bytes,
                Err(err) if err.kind() == std::io::ErrorKind::NotFound => return Ok(None),
                Err(err) => {
                    return Err(s3_error(
                        StatusCode::INTERNAL_SERVER_ERROR,
                        "InternalError",
                        &format!("Failed to read object: {err}"),
                        key,
                    ))
                }
            };
            Ok(Some(bytes))
        }
    }
}

async fn read_current_hot_object_payload(
    state: &AppState,
    bucket: &str,
    key: &str,
) -> Result<Option<Vec<u8>>, Response> {
    let bucket_root = bucket_path(state, bucket)?;
    let target_path = object_path(&bucket_root, key)?;
    let bytes = match tokio::fs::read(&target_path).await {
        Ok(bytes) => bytes,
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => return Ok(None),
        Err(err) => {
            return Err(s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to read object: {err}"),
                key,
            ))
        }
    };
    Ok(Some(bytes))
}

async fn persist_restored_current_object_payload(
    state: &AppState,
    meta: &S3ObjectMeta,
    payload: &[u8],
) -> Result<(), Response> {
    let bucket_root = bucket_path(state, &meta.bucket)?;
    let target_path = object_path(&bucket_root, &meta.key)?;
    if let Some(parent) = target_path.parent() {
        tokio::fs::create_dir_all(parent).await.map_err(|err| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to create restore directory: {err}"),
                &meta.key,
            )
        })?;
    }
    tokio::fs::write(&target_path, payload)
        .await
        .map_err(|err| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to restore object payload: {err}"),
                &meta.key,
            )
        })?;
    Ok(())
}

async fn remove_current_hot_object_payload(
    state: &AppState,
    bucket: &str,
    key: &str,
) -> Result<(), Response> {
    let bucket_root = bucket_path(state, bucket)?;
    let target_path = object_path(&bucket_root, key)?;
    match tokio::fs::remove_file(&target_path).await {
        Ok(_) => {}
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => {}
        Err(err) => {
            return Err(s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to remove current object payload: {err}"),
                key,
            ))
        }
    }
    remove_ec_object(state, bucket, key).await?;
    if let Some(parent) = target_path.parent() {
        let _ = remove_empty_dirs_until(parent, &bucket_root);
    }
    Ok(())
}

async fn archive_object_version(
    state: &AppState,
    bucket: &str,
    key: &str,
    meta: &S3ObjectMeta,
) -> Result<(), Response> {
    let mut archived_meta = meta.clone();
    archived_meta.restore = None;
    if !valid_version_id(&archived_meta.version_id) {
        return Err(s3_error(
            StatusCode::BAD_REQUEST,
            "InvalidVersionId",
            "The specified version id is not valid",
            key,
        ));
    }

    let bucket_root = bucket_path(state, bucket)?;
    let version_dir = object_versions_dir(&bucket_root, key);
    tokio::fs::create_dir_all(&version_dir)
        .await
        .map_err(|err| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to create object version directory: {err}"),
                key,
            )
        })?;

    let archived_meta_path =
        object_version_meta_path(&bucket_root, key, &archived_meta.version_id)?;
    if !tokio::fs::try_exists(&archived_meta_path)
        .await
        .unwrap_or(false)
    {
        let bytes = serde_json::to_vec_pretty(&archived_meta).map_err(|err| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to serialize archived object metadata: {err}"),
                key,
            )
        })?;
        tokio::fs::write(&archived_meta_path, bytes)
            .await
            .map_err(|err| {
                s3_error(
                    StatusCode::INTERNAL_SERVER_ERROR,
                    "InternalError",
                    &format!("Failed to persist archived object metadata: {err}"),
                    key,
                )
            })?;
    }

    if !archived_meta.delete_marker {
        if archived_meta.remote_tier.is_some() {
            return Ok(());
        }
        let payload_path =
            object_version_payload_path(&bucket_root, key, &archived_meta.version_id)?;
        if !tokio::fs::try_exists(&payload_path).await.unwrap_or(false) {
            if let Some(payload) =
                read_current_object_payload(state, bucket, key, Some(&archived_meta)).await?
            {
                tokio::fs::write(&payload_path, payload)
                    .await
                    .map_err(|err| {
                        s3_error(
                            StatusCode::INTERNAL_SERVER_ERROR,
                            "InternalError",
                            &format!("Failed to archive object payload: {err}"),
                            key,
                        )
                    })?;
            }
        }
    }

    Ok(())
}

async fn read_archived_object_meta(
    state: &AppState,
    bucket: &str,
    key: &str,
    version_id: &str,
) -> Result<Option<S3ObjectMeta>, Response> {
    let bucket_root = bucket_path(state, bucket)?;
    let meta_path = object_version_meta_path(&bucket_root, key, version_id)?;
    let bytes = match tokio::fs::read(&meta_path).await {
        Ok(bytes) => bytes,
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => return Ok(None),
        Err(err) => {
            return Err(s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to read archived object metadata: {err}"),
                key,
            ));
        }
    };
    let meta = serde_json::from_slice::<S3ObjectMeta>(&bytes).map_err(|err| {
        s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!("Failed to decode archived object metadata: {err}"),
            key,
        )
    })?;
    if meta.bucket != bucket || meta.key != key {
        return Ok(None);
    }
    Ok(Some(meta))
}

async fn read_archived_object_payload(
    state: &AppState,
    bucket: &str,
    key: &str,
    version_id: &str,
) -> Result<Option<Vec<u8>>, Response> {
    let archived_meta = read_archived_object_meta(state, bucket, key, version_id).await?;
    let Some(meta) = archived_meta else {
        return Ok(None);
    };
    read_archived_object_payload_by_meta(state, &meta).await
}

async fn read_archived_object_payload_by_meta(
    state: &AppState,
    meta: &S3ObjectMeta,
) -> Result<Option<Vec<u8>>, Response> {
    if object_restore_is_active(meta) {
        if let Some(bytes) = read_archived_local_object_payload_by_meta(state, meta).await? {
            return Ok(Some(bytes));
        }
    }
    if let Some(bytes) = read_remote_tier_payload_for_meta(state, meta).await? {
        return Ok(Some(bytes));
    }
    read_archived_local_object_payload_by_meta(state, meta).await
}

async fn read_archived_local_object_payload_by_meta(
    state: &AppState,
    meta: &S3ObjectMeta,
) -> Result<Option<Vec<u8>>, Response> {
    let bucket_root = bucket_path(state, &meta.bucket)?;
    let payload_path = object_version_payload_path(&bucket_root, &meta.key, &meta.version_id)?;
    let bytes = match tokio::fs::read(&payload_path).await {
        Ok(bytes) => bytes,
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => return Ok(None),
        Err(err) => {
            return Err(s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to read archived object payload: {err}"),
                &meta.key,
            ));
        }
    };
    Ok(Some(bytes))
}

async fn persist_restored_archived_object_payload(
    state: &AppState,
    meta: &S3ObjectMeta,
    payload: &[u8],
) -> Result<(), Response> {
    let bucket_root = bucket_path(state, &meta.bucket)?;
    let version_dir = object_versions_dir(&bucket_root, &meta.key);
    tokio::fs::create_dir_all(&version_dir)
        .await
        .map_err(|err| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to create archived restore directory: {err}"),
                &meta.key,
            )
        })?;
    let payload_path = object_version_payload_path(&bucket_root, &meta.key, &meta.version_id)?;
    tokio::fs::write(&payload_path, payload)
        .await
        .map_err(|err| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to restore archived object payload: {err}"),
                &meta.key,
            )
        })?;
    Ok(())
}

async fn admin_prewarm_remote_archived_object(
    state: &AppState,
    meta: &S3ObjectMeta,
    is_current: bool,
    restore_days: u32,
    requested_at: DateTime<Utc>,
) -> Result<bool, String> {
    if meta.remote_tier.is_none() {
        return Ok(false);
    }
    if object_restore_is_active(meta) {
        return Ok(false);
    }
    let payload = read_remote_tier_payload_for_meta(state, meta)
        .await
        .map_err(|_| {
            bilingual_text(
                "读取远端归档对象失败",
                "failed to read remote archived object payload",
            )
        })?
        .ok_or_else(|| {
            bilingual_text(
                "远端归档对象不存在",
                "remote archived object payload does not exist",
            )
        })?;

    if is_current {
        persist_restored_current_object_payload(state, meta, &payload)
            .await
            .map_err(|_| {
                bilingual_text(
                    "回温当前对象失败",
                    "failed to persist restored current object payload",
                )
            })?;
        let mut next = meta.clone();
        next.restore = Some(ObjectRestoreStatus {
            ongoing_request: false,
            requested_at: Some(requested_at),
            expiry_at: Some(requested_at + Duration::days(restore_days as i64)),
        });
        persist_current_object_meta(state, next)
            .await
            .map_err(|_| {
                bilingual_text(
                    "写入当前对象回温元数据失败",
                    "failed to persist current object restore metadata",
                )
            })?;
    } else {
        persist_restored_archived_object_payload(state, meta, &payload)
            .await
            .map_err(|_| {
                bilingual_text(
                    "回温历史版本失败",
                    "failed to persist restored archived object payload",
                )
            })?;
        let mut next = meta.clone();
        next.restore = Some(ObjectRestoreStatus {
            ongoing_request: false,
            requested_at: Some(requested_at),
            expiry_at: Some(requested_at + Duration::days(restore_days as i64)),
        });
        persist_archived_object_meta(state, &next)
            .await
            .map_err(|_| {
                bilingual_text(
                    "写入历史版本回温元数据失败",
                    "failed to persist archived object restore metadata",
                )
            })?;
    }
    Ok(true)
}

async fn read_archived_versions_for_key(
    state: &AppState,
    bucket: &str,
    key: &str,
) -> Result<Vec<S3ObjectMeta>, Response> {
    let bucket_root = bucket_path(state, bucket)?;
    let version_dir = object_versions_dir(&bucket_root, key);
    let mut output = Vec::new();

    let mut dir = match tokio::fs::read_dir(&version_dir).await {
        Ok(reader) => reader,
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => return Ok(output),
        Err(err) => {
            return Err(s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to enumerate archived object versions: {err}"),
                key,
            ));
        }
    };

    while let Some(entry) = dir.next_entry().await.map_err(|err| {
        s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!("Failed to read archived object version entry: {err}"),
            key,
        )
    })? {
        let path = entry.path();
        if path.extension().and_then(|ext| ext.to_str()) != Some("json") {
            continue;
        }

        let bytes = tokio::fs::read(&path).await.map_err(|err| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to read archived object version metadata: {err}"),
                key,
            )
        })?;
        let meta = serde_json::from_slice::<S3ObjectMeta>(&bytes).map_err(|err| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to parse archived object version metadata: {err}"),
                key,
            )
        })?;
        if meta.bucket == bucket && meta.key == key {
            output.push(meta);
        }
    }

    output.sort_by(|left, right| right.created_at.cmp(&left.created_at));
    Ok(output)
}

async fn remove_archived_object_version(
    state: &AppState,
    bucket: &str,
    key: &str,
    version_id: &str,
) -> Result<(), Response> {
    remove_archived_object_version_with_remote(state, bucket, key, version_id, true).await
}

async fn remove_archived_object_version_with_remote(
    state: &AppState,
    bucket: &str,
    key: &str,
    version_id: &str,
    remove_remote_payload: bool,
) -> Result<(), Response> {
    let archived_meta = read_archived_object_meta(state, bucket, key, version_id).await?;
    let bucket_root = bucket_path(state, bucket)?;
    let meta_path = object_version_meta_path(&bucket_root, key, version_id)?;
    let payload_path = object_version_payload_path(&bucket_root, key, version_id)?;

    match tokio::fs::remove_file(&meta_path).await {
        Ok(_) => {}
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => {}
        Err(err) => {
            return Err(s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to remove archived version metadata: {err}"),
                key,
            ));
        }
    }

    match tokio::fs::remove_file(&payload_path).await {
        Ok(_) => {}
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => {}
        Err(err) => {
            return Err(s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to remove archived version payload: {err}"),
                key,
            ));
        }
    }

    if remove_remote_payload {
        if let Some(meta) = archived_meta.as_ref() {
            remove_remote_tier_payload_for_meta(state, meta).await?;
        }
    }

    if let Some(parent) = meta_path.parent() {
        let root = bucket_root.join(".rustio_versions");
        let _ = remove_empty_dirs_until(parent, &root);
    }
    Ok(())
}

async fn resolve_object_version_meta(
    state: &AppState,
    bucket: &str,
    key: &str,
    version_id: &str,
    current_meta: Option<S3ObjectMeta>,
) -> Result<Option<(S3ObjectMeta, bool)>, Response> {
    if let Some(meta) = current_meta {
        if meta.version_id == version_id {
            return Ok(Some((meta, true)));
        }
    }

    let archived = read_archived_object_meta(state, bucket, key, version_id).await?;
    Ok(archived.map(|meta| (meta, false)))
}

async fn list_object_versions(
    state: &AppState,
    bucket: &str,
    key: &str,
) -> Result<Vec<S3ObjectMeta>, Response> {
    let mut output = Vec::new();
    if let Some(current) = read_current_object_meta(state, bucket, key).await? {
        output.push(current);
    }

    let archived = read_archived_versions_for_key(state, bucket, key).await?;
    for item in archived {
        if output
            .iter()
            .any(|existing| existing.version_id == item.version_id)
        {
            continue;
        }
        output.push(item);
    }

    if output.is_empty() {
        let bucket_root = bucket_path(state, bucket)?;
        let target = object_path(&bucket_root, key)?;
        if let Ok(metadata) = tokio::fs::metadata(&target).await {
            let modified = metadata.modified().ok();
            let modified_at = modified.map(DateTime::<Utc>::from).unwrap_or_else(Utc::now);
            let modified_secs = modified
                .and_then(|value| value.duration_since(std::time::UNIX_EPOCH).ok())
                .map(|value| value.as_secs())
                .unwrap_or(0);
            output.push(S3ObjectMeta {
                bucket: bucket.to_string(),
                key: key.to_string(),
                version_id: "null".to_string(),
                size: metadata.len(),
                etag: format!("{:x}{:x}", metadata.len(), modified_secs),
                created_at: modified_at,
                storage_class: default_storage_class(),
                retention_mode: None,
                retention_until: None,
                legal_hold: false,
                delete_marker: false,
                remote_tier: None,
                restore: None,
                tags: Vec::new(),
                user_metadata: HashMap::new(),
                encryption: S3ObjectEncryptionMeta::default(),
            });
        }
    }

    output.sort_by(|left, right| right.created_at.cmp(&left.created_at));
    Ok(output)
}

async fn promote_latest_archived_version(
    state: &AppState,
    bucket: &str,
    key: &str,
) -> Result<Option<S3ObjectMeta>, Response> {
    let mut archived = read_archived_versions_for_key(state, bucket, key).await?;
    archived.sort_by(|left, right| right.created_at.cmp(&left.created_at));
    let Some(mut next) = archived.first().cloned() else {
        return Ok(None);
    };
    next.restore = None;

    let bucket_root = bucket_path(state, bucket)?;
    if next.delete_marker {
        let current_path = object_path(&bucket_root, key)?;
        let _ = tokio::fs::remove_file(current_path).await;
    } else if next.remote_tier.is_none() {
        let payload = read_archived_object_payload_by_meta(state, &next).await?;
        let payload = payload.ok_or_else(|| {
            s3_error(
                StatusCode::NOT_FOUND,
                "NoSuchVersion",
                "The specified archived object version payload does not exist",
                key,
            )
        })?;
        let target = object_path(&bucket_root, key)?;
        if let Some(parent) = target.parent() {
            tokio::fs::create_dir_all(parent).await.map_err(|err| {
                s3_error(
                    StatusCode::INTERNAL_SERVER_ERROR,
                    "InternalError",
                    &format!("Failed to recreate object directory: {err}"),
                    key,
                )
            })?;
        }
        tokio::fs::write(&target, &payload).await.map_err(|err| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to restore archived object payload: {err}"),
                key,
            )
        })?;
        write_ec_object(state, bucket, key, &payload, &mut next).await?;
    } else {
        let target = object_path(&bucket_root, key)?;
        let _ = tokio::fs::remove_file(target).await;
        remove_ec_object(state, bucket, key).await?;
    }

    persist_current_object_meta(state, next.clone()).await?;
    remove_archived_object_version_with_remote(state, bucket, key, &next.version_id, false).await?;
    Ok(Some(next))
}

async fn delete_object_version(
    state: &AppState,
    bucket: &str,
    key: &str,
    version_id: &str,
) -> Result<bool, Response> {
    let current_meta = read_current_object_meta(state, bucket, key).await?;

    if let Some(meta) = current_meta.clone() {
        if meta.version_id == version_id {
            if meta.legal_hold {
                return Err(s3_error(
                    StatusCode::FORBIDDEN,
                    "AccessDenied",
                    "Object is under legal hold",
                    key,
                ));
            }
            if meta
                .retention_until
                .map(|value| value > Utc::now())
                .unwrap_or(false)
            {
                return Err(s3_error(
                    StatusCode::FORBIDDEN,
                    "AccessDenied",
                    "Object retention period has not expired",
                    key,
                ));
            }
            if !meta.delete_marker {
                remove_current_hot_object_payload(state, bucket, key).await?;
                remove_remote_tier_payload_for_meta(state, &meta).await?;
            }
            remove_current_object_meta(state, bucket, key).await?;
            let _ = promote_latest_archived_version(state, bucket, key).await?;
            return Ok(true);
        }
    }

    let Some(archived_meta) = read_archived_object_meta(state, bucket, key, version_id).await?
    else {
        return Ok(false);
    };
    if archived_meta.legal_hold {
        return Err(s3_error(
            StatusCode::FORBIDDEN,
            "AccessDenied",
            "Object is under legal hold",
            key,
        ));
    }
    if archived_meta
        .retention_until
        .map(|value| value > Utc::now())
        .unwrap_or(false)
    {
        return Err(s3_error(
            StatusCode::FORBIDDEN,
            "AccessDenied",
            "Object retention period has not expired",
            key,
        ));
    }

    remove_archived_object_version(state, bucket, key, version_id).await?;
    Ok(true)
}

async fn persist_archived_object_meta(
    state: &AppState,
    meta: &S3ObjectMeta,
) -> Result<(), Response> {
    let bucket_root = bucket_path(state, &meta.bucket)?;
    let meta_path = object_version_meta_path(&bucket_root, &meta.key, &meta.version_id)?;
    if let Some(parent) = meta_path.parent() {
        tokio::fs::create_dir_all(parent).await.map_err(|err| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to create archived metadata directory: {err}"),
                &meta.key,
            )
        })?;
    }
    let bytes = serde_json::to_vec_pretty(meta).map_err(|err| {
        s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!("Failed to serialize archived object metadata: {err}"),
            &meta.key,
        )
    })?;
    tokio::fs::write(&meta_path, bytes).await.map_err(|err| {
        s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!("Failed to persist archived object metadata: {err}"),
            &meta.key,
        )
    })?;
    Ok(())
}

async fn persist_current_object_meta(state: &AppState, meta: S3ObjectMeta) -> Result<(), Response> {
    let bucket_root = bucket_path(state, &meta.bucket)?;
    let meta_path = object_meta_path(&bucket_root, &meta.key)?;
    if let Some(parent) = meta_path.parent() {
        tokio::fs::create_dir_all(parent).await.map_err(|err| {
            s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to create object metadata directory: {err}"),
                &meta.key,
            )
        })?;
    }

    let bytes = serde_json::to_vec_pretty(&meta).map_err(|err| {
        s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!("Failed to serialize object metadata: {err}"),
            &meta.key,
        )
    })?;

    tokio::fs::write(&meta_path, bytes).await.map_err(|err| {
        s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!("Failed to persist object metadata: {err}"),
            &meta.key,
        )
    })?;

    state
        .object_meta
        .write()
        .await
        .insert((meta.bucket.clone(), meta.key.clone()), meta);
    state
        .sync_metadata_raft("object-meta-upsert")
        .await
        .map_err(|err| {
            s3_error(
                StatusCode::SERVICE_UNAVAILABLE,
                "InternalError",
                &format!("metadata raft commit failed: {err}"),
                "metadata",
            )
        })?;
    Ok(())
}

async fn read_current_object_meta(
    state: &AppState,
    bucket: &str,
    key: &str,
) -> Result<Option<S3ObjectMeta>, Response> {
    if let Some(meta) = state
        .object_meta
        .read()
        .await
        .get(&(bucket.to_string(), key.to_string()))
        .cloned()
    {
        return Ok(Some(meta));
    }

    let Some(meta) = read_current_object_meta_from_disk(state, bucket, key).await? else {
        return Ok(None);
    };
    state
        .object_meta
        .write()
        .await
        .insert((bucket.to_string(), key.to_string()), meta.clone());
    Ok(Some(meta))
}

async fn read_current_object_meta_from_disk(
    state: &AppState,
    bucket: &str,
    key: &str,
) -> Result<Option<S3ObjectMeta>, Response> {
    let bucket_root = bucket_path(state, bucket)?;
    let meta_path = object_meta_path(&bucket_root, key)?;
    let bytes = match tokio::fs::read(&meta_path).await {
        Ok(bytes) => bytes,
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => return Ok(None),
        Err(err) => {
            return Err(s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to read object metadata: {err}"),
                key,
            ));
        }
    };

    let meta = serde_json::from_slice::<S3ObjectMeta>(&bytes).map_err(|err| {
        s3_error(
            StatusCode::INTERNAL_SERVER_ERROR,
            "InternalError",
            &format!("Failed to decode object metadata: {err}"),
            key,
        )
    })?;
    Ok(Some(meta))
}

async fn remove_current_object_meta(
    state: &AppState,
    bucket: &str,
    key: &str,
) -> Result<(), Response> {
    state
        .object_meta
        .write()
        .await
        .remove(&(bucket.to_string(), key.to_string()));

    let bucket_root = bucket_path(state, bucket)?;
    let meta_path = object_meta_path(&bucket_root, key)?;
    match tokio::fs::remove_file(&meta_path).await {
        Ok(_) => {}
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => {}
        Err(err) => {
            return Err(s3_error(
                StatusCode::INTERNAL_SERVER_ERROR,
                "InternalError",
                &format!("Failed to remove object metadata: {err}"),
                key,
            ));
        }
    }

    if let Some(parent) = meta_path.parent() {
        let meta_root = bucket_root.join(".rustio_meta");
        let _ = remove_empty_dirs_until(parent, &meta_root);
    }
    state
        .sync_metadata_raft("object-meta-remove")
        .await
        .map_err(|err| {
            s3_error(
                StatusCode::SERVICE_UNAVAILABLE,
                "InternalError",
                &format!("metadata raft commit failed: {err}"),
                "metadata",
            )
        })?;
    Ok(())
}

async fn build_object_meta_for_current_version(
    state: &AppState,
    bucket: &str,
    key: &str,
    size: u64,
    etag: String,
    delete_marker: bool,
) -> S3ObjectMeta {
    let now = Utc::now();
    let (versioning, object_lock_from_bucket) = state
        .buckets
        .read()
        .await
        .get(bucket)
        .map(|item| (item.versioning, item.object_lock))
        .unwrap_or((true, false));
    let version_id = if versioning || delete_marker {
        Uuid::new_v4().to_string()
    } else {
        "null".to_string()
    };

    let object_lock = state
        .bucket_object_locks
        .read()
        .await
        .get(bucket)
        .cloned()
        .unwrap_or(BucketObjectLockConfig {
            enabled: object_lock_from_bucket,
            mode: "GOVERNANCE".to_string(),
            default_retention_days: 30,
        });
    let retention = state
        .bucket_retentions
        .read()
        .await
        .get(bucket)
        .cloned()
        .unwrap_or_else(default_retention_config);
    let legal_hold = state
        .bucket_legal_holds
        .read()
        .await
        .get(bucket)
        .cloned()
        .unwrap_or_else(default_legal_hold_config)
        .enabled;

    let retention_until = if delete_marker {
        None
    } else if retention.enabled {
        Some(now + Duration::days(retention.duration_days as i64))
    } else if object_lock.enabled {
        Some(now + Duration::days(object_lock.default_retention_days as i64))
    } else {
        None
    };
    let retention_mode = if delete_marker {
        None
    } else if retention.enabled {
        Some(retention.mode)
    } else if object_lock.enabled {
        Some(object_lock.mode)
    } else {
        None
    };

    S3ObjectMeta {
        bucket: bucket.to_string(),
        key: key.to_string(),
        version_id,
        size,
        etag,
        created_at: now,
        storage_class: default_storage_class(),
        retention_mode,
        retention_until,
        legal_hold: if delete_marker { false } else { legal_hold },
        delete_marker,
        remote_tier: None,
        restore: None,
        tags: Vec::new(),
        user_metadata: HashMap::new(),
        encryption: S3ObjectEncryptionMeta::default(),
    }
}

fn valid_bucket_name(name: &str) -> bool {
    if name.len() < 3 || name.len() > 63 {
        return false;
    }
    if name.starts_with('.') || name.ends_with('.') || name.starts_with('-') || name.ends_with('-')
    {
        return false;
    }
    if name.contains("..") {
        return false;
    }
    name.chars()
        .all(|ch| ch.is_ascii_lowercase() || ch.is_ascii_digit() || ch == '.' || ch == '-')
}

fn collect_objects(
    bucket_root: &FsPath,
    dir: &FsPath,
    output: &mut Vec<DiskObjectEntry>,
) -> std::io::Result<()> {
    let mut entries = HashMap::<String, DiskObjectEntry>::new();
    collect_object_payload_files(bucket_root, dir, &mut entries)?;
    collect_object_meta_entries(bucket_root, &mut entries)?;
    output.extend(entries.into_values());
    Ok(())
}

fn collect_object_payload_files(
    bucket_root: &FsPath,
    dir: &FsPath,
    output: &mut HashMap<String, DiskObjectEntry>,
) -> std::io::Result<()> {
    for entry in std::fs::read_dir(dir)? {
        let entry = entry?;
        let path = entry.path();
        let metadata = entry.metadata()?;
        let rel = path
            .strip_prefix(bucket_root)
            .unwrap_or(&path)
            .to_string_lossy()
            .replace('\\', "/");

        if rel == ".rustio_meta"
            || rel.starts_with(".rustio_meta/")
            || rel == ".rustio_versions"
            || rel.starts_with(".rustio_versions/")
        {
            continue;
        }

        if metadata.is_dir() {
            collect_object_payload_files(bucket_root, &path, output)?;
            continue;
        }

        if !metadata.is_file() {
            continue;
        }

        let modified = metadata.modified().ok();
        let modified_at: DateTime<Utc> =
            modified.map(DateTime::<Utc>::from).unwrap_or_else(Utc::now);
        let modified_secs = modified
            .and_then(|v| v.duration_since(std::time::UNIX_EPOCH).ok())
            .map(|v| v.as_secs())
            .unwrap_or(0);

        output.insert(
            rel.clone(),
            DiskObjectEntry {
                key: rel,
                size: metadata.len(),
                etag: format!("{:x}{:x}", metadata.len(), modified_secs),
                last_modified: modified_at.to_rfc3339_opts(SecondsFormat::Secs, true),
                storage_class: default_storage_class(),
            },
        );
    }
    Ok(())
}

fn collect_object_meta_entries(
    bucket_root: &FsPath,
    output: &mut HashMap<String, DiskObjectEntry>,
) -> std::io::Result<()> {
    let mut meta_files = Vec::new();
    collect_json_files(&bucket_root.join(".rustio_meta"), &mut meta_files)?;
    for file in meta_files {
        let Ok(bytes) = std::fs::read(&file) else {
            continue;
        };
        let Ok(meta) = serde_json::from_slice::<S3ObjectMeta>(&bytes) else {
            continue;
        };
        if meta.delete_marker {
            output.remove(&meta.key);
            continue;
        }
        output.insert(
            meta.key.clone(),
            DiskObjectEntry {
                key: meta.key.clone(),
                size: meta.size,
                etag: meta.etag.clone(),
                last_modified: meta.created_at.to_rfc3339_opts(SecondsFormat::Secs, true),
                storage_class: object_storage_class(&meta).to_string(),
            },
        );
    }
    Ok(())
}

fn is_bucket_control_plane_metadata_path(bucket_root: &FsPath, path: &FsPath) -> bool {
    let rel = path
        .strip_prefix(bucket_root)
        .unwrap_or(path)
        .to_string_lossy()
        .replace('\\', "/");
    matches!(
        rel.as_str(),
        ".rustio_meta/bucket-policy.json"
            | ".rustio_meta/bucket-lifecycle.json"
            | ".rustio_meta/bucket-notifications.json"
            | ".rustio_meta/bucket-acl.json"
            | ".rustio_meta/bucket-public-access-block.json"
            | ".rustio_meta/bucket-cors.json"
            | ".rustio_meta/bucket-tags.json"
            | ".rustio_meta/bucket-encryption.json"
    )
}

fn bucket_has_objects(bucket_root: &FsPath, dir: &FsPath) -> std::io::Result<bool> {
    for entry in std::fs::read_dir(dir)? {
        let entry = entry?;
        let path = entry.path();
        let metadata = entry.metadata()?;
        if is_bucket_control_plane_metadata_path(bucket_root, &path) {
            continue;
        }
        if metadata.is_file() {
            return Ok(true);
        }
        if metadata.is_dir() && bucket_has_objects(bucket_root, &path)? {
            return Ok(true);
        }
    }
    Ok(false)
}

fn remove_empty_dirs_until(mut current: &FsPath, stop_at: &FsPath) -> std::io::Result<()> {
    while current.starts_with(stop_at) && current != stop_at {
        if std::fs::read_dir(current)?.next().is_some() {
            break;
        }
        std::fs::remove_dir(current)?;
        if let Some(parent) = current.parent() {
            current = parent;
        } else {
            break;
        }
    }
    Ok(())
}

fn weak_etag(bytes: &[u8]) -> String {
    let mut hash: u64 = 0xcbf29ce484222325;
    for byte in bytes {
        hash ^= *byte as u64;
        hash = hash.wrapping_mul(0x100000001b3);
    }
    format!("{hash:016x}")
}

fn format_http_date(value: DateTime<Utc>) -> String {
    value.format("%a, %d %b %Y %H:%M:%S GMT").to_string()
}

fn parse_http_date(value: &str) -> Option<DateTime<Utc>> {
    DateTime::parse_from_rfc2822(value)
        .ok()
        .map(|parsed| parsed.with_timezone(&Utc))
        .or_else(|| {
            DateTime::parse_from_rfc3339(value)
                .ok()
                .map(|parsed| parsed.with_timezone(&Utc))
        })
}

fn parse_range_header(headers: &HeaderMap, size: u64) -> Result<Option<(u64, u64)>, ()> {
    let Some(raw) = headers
        .get(axum::http::header::RANGE)
        .and_then(|value| value.to_str().ok())
    else {
        return Ok(None);
    };
    if size == 0 {
        return Err(());
    }

    let Some(spec) = raw.strip_prefix("bytes=") else {
        return Err(());
    };
    if spec.contains(',') {
        return Err(());
    }

    let mut split = spec.splitn(2, '-');
    let start_raw = split.next().unwrap_or_default().trim();
    let end_raw = split.next().ok_or(())?.trim();
    if start_raw.is_empty() {
        let suffix_len = end_raw.parse::<u64>().map_err(|_| ())?;
        if suffix_len == 0 {
            return Err(());
        }
        let start = size.saturating_sub(suffix_len);
        let end = size - 1;
        return Ok(Some((start, end)));
    }

    let start = start_raw.parse::<u64>().map_err(|_| ())?;
    if start >= size {
        return Err(());
    }

    let end = if end_raw.is_empty() {
        size - 1
    } else {
        end_raw.parse::<u64>().map_err(|_| ())?.min(size - 1)
    };
    if start > end {
        return Err(());
    }
    Ok(Some((start, end)))
}

fn normalize_etag_token(token: &str) -> &str {
    token
        .trim()
        .trim_start_matches("W/")
        .trim_start_matches("w/")
        .trim()
}

fn if_header_matches_etag(value: &str, etag: &str, etag_quoted: &str) -> bool {
    value.split(',').map(str::trim).any(|item| {
        let token = normalize_etag_token(item);
        token == "*" || token == etag_quoted || token.trim_matches('"') == etag
    })
}

fn precondition_response(
    method: &Method,
    status: StatusCode,
    code: &str,
    message: &str,
    key: &str,
) -> Response {
    if *method == Method::HEAD {
        status.into_response()
    } else {
        s3_error(status, code, message, key)
    }
}

fn evaluate_object_preconditions(
    method: &Method,
    headers: &HeaderMap,
    etag: &str,
    etag_quoted: &str,
    last_modified: DateTime<Utc>,
    key: &str,
) -> Option<Response> {
    let if_match = headers
        .get(axum::http::header::IF_MATCH)
        .and_then(|value| value.to_str().ok());
    if let Some(value) = if_match {
        if !if_header_matches_etag(value, etag, etag_quoted) {
            return Some(precondition_response(
                method,
                StatusCode::PRECONDITION_FAILED,
                "PreconditionFailed",
                "At least one of the pre-conditions you specified did not hold",
                key,
            ));
        }
    }

    let if_unmodified_since = headers
        .get(axum::http::header::IF_UNMODIFIED_SINCE)
        .and_then(|value| value.to_str().ok())
        .and_then(parse_http_date);
    if if_match.is_none() {
        if let Some(boundary) = if_unmodified_since {
            if last_modified > boundary {
                return Some(precondition_response(
                    method,
                    StatusCode::PRECONDITION_FAILED,
                    "PreconditionFailed",
                    "At least one of the pre-conditions you specified did not hold",
                    key,
                ));
            }
        }
    }

    let if_none_match = headers
        .get(axum::http::header::IF_NONE_MATCH)
        .and_then(|value| value.to_str().ok());
    if let Some(value) = if_none_match {
        if if_header_matches_etag(value, etag, etag_quoted) {
            return Some(StatusCode::NOT_MODIFIED.into_response());
        }
    }

    let if_modified_since = headers
        .get(axum::http::header::IF_MODIFIED_SINCE)
        .and_then(|value| value.to_str().ok())
        .and_then(parse_http_date);
    if if_none_match.is_none() {
        if let Some(boundary) = if_modified_since {
            if last_modified <= boundary {
                return Some(StatusCode::NOT_MODIFIED.into_response());
            }
        }
    }

    None
}

fn evaluate_copy_source_preconditions(
    headers: &HeaderMap,
    etag: &str,
    last_modified: DateTime<Utc>,
    resource: &str,
) -> Option<Response> {
    let etag_quoted = format!("\"{etag}\"");
    let if_match = headers
        .get(axum::http::header::HeaderName::from_static(
            "x-amz-copy-source-if-match",
        ))
        .and_then(|value| value.to_str().ok());
    if let Some(value) = if_match {
        if !if_header_matches_etag(value, etag, &etag_quoted) {
            return Some(s3_error(
                StatusCode::PRECONDITION_FAILED,
                "PreconditionFailed",
                "At least one of the pre-conditions you specified did not hold",
                resource,
            ));
        }
    }

    let if_unmodified_since = headers
        .get(axum::http::header::HeaderName::from_static(
            "x-amz-copy-source-if-unmodified-since",
        ))
        .and_then(|value| value.to_str().ok())
        .and_then(parse_http_date);
    if if_match.is_none() {
        if let Some(boundary) = if_unmodified_since {
            if last_modified > boundary {
                return Some(s3_error(
                    StatusCode::PRECONDITION_FAILED,
                    "PreconditionFailed",
                    "At least one of the pre-conditions you specified did not hold",
                    resource,
                ));
            }
        }
    }

    let if_none_match = headers
        .get(axum::http::header::HeaderName::from_static(
            "x-amz-copy-source-if-none-match",
        ))
        .and_then(|value| value.to_str().ok());
    if let Some(value) = if_none_match {
        if if_header_matches_etag(value, etag, &etag_quoted) {
            return Some(s3_error(
                StatusCode::PRECONDITION_FAILED,
                "PreconditionFailed",
                "At least one of the pre-conditions you specified did not hold",
                resource,
            ));
        }
    }

    let if_modified_since = headers
        .get(axum::http::header::HeaderName::from_static(
            "x-amz-copy-source-if-modified-since",
        ))
        .and_then(|value| value.to_str().ok())
        .and_then(parse_http_date);
    if if_none_match.is_none() {
        if let Some(boundary) = if_modified_since {
            if last_modified <= boundary {
                return Some(s3_error(
                    StatusCode::PRECONDITION_FAILED,
                    "PreconditionFailed",
                    "At least one of the pre-conditions you specified did not hold",
                    resource,
                ));
            }
        }
    }

    None
}

fn xml_escape(text: &str) -> String {
    text.replace('&', "&amp;")
        .replace('<', "&lt;")
        .replace('>', "&gt;")
        .replace('"', "&quot;")
        .replace('\'', "&apos;")
}

fn s3_xml_response(status: StatusCode, body: String) -> Response {
    (
        status,
        [(
            axum::http::header::CONTENT_TYPE,
            "application/xml; charset=utf-8",
        )],
        body,
    )
        .into_response()
}

fn bilingual_s3_message(code: &str, message: &str) -> String {
    if message.contains(" / ") {
        return message.to_string();
    }

    let (zh, en_default) = match code {
        "NoSuchBucket" => ("桶不存在", "The specified bucket does not exist"),
        "NoSuchKey" => ("对象不存在", "The specified key does not exist"),
        "NoSuchUpload" => (
            "分片上传不存在",
            "The specified multipart upload does not exist",
        ),
        "NoSuchVersion" => (
            "对象版本不存在",
            "The specified object version does not exist",
        ),
        "NoSuchBucketPolicy" => ("桶策略不存在", "The bucket policy does not exist"),
        "NoSuchCORSConfiguration" => ("CORS 配置不存在", "The CORS configuration does not exist"),
        "NoSuchTagSet" => ("标签配置不存在", "The tag set does not exist"),
        "NoSuchLifecycleConfiguration" => (
            "生命周期配置不存在",
            "The lifecycle configuration does not exist",
        ),
        "BucketAlreadyOwnedByYou" => (
            "桶已存在且归属于当前账号",
            "Your previous request to create the named bucket succeeded",
        ),
        "BucketNotEmpty" => ("桶不为空", "The bucket you tried to delete is not empty"),
        "InvalidBucketName" => ("桶名称无效", "The specified bucket is not valid"),
        "InvalidObjectName" => ("对象名称无效", "The specified object name is not valid"),
        "InvalidVersionId" => ("版本号无效", "The specified version ID is not valid"),
        "InvalidRange" => ("请求范围无效", "The requested range is not satisfiable"),
        "InvalidTag" => ("标签参数无效", "The Tag provided was not a valid tag"),
        "InvalidArgument" => ("参数无效", "Invalid Argument"),
        "InvalidRequest" => ("请求不合法", "Invalid Request"),
        "PreconditionFailed" => (
            "前置条件不满足",
            "At least one of the preconditions you specified did not hold",
        ),
        "MalformedXML" => ("XML 格式错误", "The XML you provided was not well-formed"),
        "MalformedPolicy" => ("策略文档格式错误", "The policy document is malformed"),
        "ObjectLockConfigurationNotFoundError" => (
            "对象锁配置不存在",
            "Object Lock configuration does not exist",
        ),
        "ServerSideEncryptionConfigurationNotFoundError" => (
            "桶加密配置不存在",
            "Server side encryption configuration was not found",
        ),
        "AccessDenied" => ("访问被拒绝", "Access Denied"),
        "SignatureDoesNotMatch" => (
            "签名不匹配",
            "The request signature we calculated does not match the signature you provided",
        ),
        "ExpiredToken" => ("令牌已过期", "The provided token has expired"),
        "InvalidToken" => (
            "令牌无效",
            "The security token included in the request is invalid",
        ),
        "InvalidAccessKeyId" => (
            "AccessKey 不存在或无效",
            "The Access Key Id you provided does not exist in our records.",
        ),
        "AuthorizationHeaderMalformed" => (
            "Authorization 头格式错误",
            "The authorization header is malformed",
        ),
        "AuthorizationQueryParametersError" => (
            "签名查询参数错误",
            "The query string authorization parameters are malformed",
        ),
        "XAmzContentSHA256Mismatch" => (
            "请求体 SHA256 校验不匹配",
            "The provided x-amz-content-sha256 does not match",
        ),
        "InvalidPart" => (
            "分片参数无效",
            "One or more of the specified parts could not be found",
        ),
        "MethodNotAllowed" => (
            "方法不被允许",
            "The specified method is not allowed against this resource",
        ),
        "KMSNotConfigured" => ("KMS 未配置", "KMS is not configured"),
        "KMSUnavailable" => ("KMS 不可用", "KMS service is unavailable"),
        "InternalError" => ("服务器内部错误", "We encountered an internal error"),
        _ => ("S3 请求失败", "S3 request failed"),
    };

    let text = message.trim();
    if text.is_empty() {
        return format!("{zh} / {en_default}");
    }

    if contains_cjk_chars(text) && !contains_ascii_alpha(text) {
        return format!("{text} / {en_default}");
    }

    format!("{zh} / {text}")
}

fn contains_ascii_alpha(text: &str) -> bool {
    text.chars().any(|ch| ch.is_ascii_alphabetic())
}

fn contains_cjk_chars(text: &str) -> bool {
    text.chars().any(|ch| {
        matches!(
            ch as u32,
            0x3400..=0x4DBF
                | 0x4E00..=0x9FFF
                | 0xF900..=0xFAFF
                | 0x20000..=0x2A6DF
                | 0x2A700..=0x2B73F
                | 0x2B740..=0x2B81F
                | 0x2B820..=0x2CEAF
                | 0x2EBF0..=0x2EE5F
        )
    })
}

#[cfg(test)]
mod s3_message_tests {
    use super::bilingual_s3_message;

    #[test]
    fn s3_message_keeps_existing_bilingual_text() {
        let msg = bilingual_s3_message("InvalidToken", "令牌无效 / invalid token");
        assert_eq!(msg, "令牌无效 / invalid token");
    }

    #[test]
    fn s3_message_wraps_english_only_text() {
        let msg = bilingual_s3_message(
            "InvalidToken",
            "The security token included in the request is invalid",
        );
        assert_eq!(
            msg,
            "令牌无效 / The security token included in the request is invalid"
        );
    }

    #[test]
    fn s3_message_wraps_chinese_only_text() {
        let msg = bilingual_s3_message("AccessDenied", "访问被拒绝");
        assert_eq!(msg, "访问被拒绝 / Access Denied");
    }
}

#[cfg(test)]
mod policy_evaluator_tests {
    use super::{
        evaluate_policy_statement, S3AuthType, S3CredentialIdentity, S3IdentityKind,
        S3PolicyRequest,
    };
    use axum::http::{HeaderMap, Method, Uri};
    use serde_json::json;

    #[test]
    fn evaluate_policy_statement_supports_not_action_and_conditions() {
        let uri: Uri = "/reports-bucket?prefix=reports/&max-keys=10"
            .parse()
            .expect("uri");
        let mut headers = HeaderMap::new();
        headers.insert("x-forwarded-proto", "https".parse().expect("header"));
        let identity = S3CredentialIdentity {
            access_key: "sa-reporter".to_string(),
            secret_key: "secret".to_string(),
            session_token: None,
            principal: Some("reporter".to_string()),
            is_root: false,
            kind: S3IdentityKind::ServiceAccount,
            role_arn: None,
            session_name: None,
            session_policy: None,
        };
        let request = S3PolicyRequest {
            method: &Method::GET,
            uri: &uri,
            headers: &headers,
            identity: Some(&identity),
            auth_type: S3AuthType::Basic,
        };
        let statement = json!({
            "Effect": "Allow",
            "NotAction": ["s3:DeleteObject", "s3:PutObject"],
            "Resource": ["arn:aws:s3:::reports-bucket"],
            "Condition": {
                "StringEquals": {
                    "aws:username": "reporter",
                    "s3:prefix": "reports/"
                },
                "NumericLessThanEquals": {
                    "s3:max-keys": 100
                },
                "Bool": {
                    "aws:SecureTransport": true
                }
            }
        });

        let result = evaluate_policy_statement(
            &statement,
            &request,
            "s3:ListBucket",
            &["arn:aws:s3:::reports-bucket".to_string()],
            false,
        );
        assert_eq!(result, Some(true));

        let denied_action = evaluate_policy_statement(
            &statement,
            &request,
            "s3:DeleteObject",
            &["arn:aws:s3:::reports-bucket/reports/a.txt".to_string()],
            false,
        );
        assert_eq!(denied_action, None);
    }

    #[test]
    fn evaluate_policy_statement_supports_not_resource_and_if_exists() {
        let uri: Uri = "/data-bucket/private/secret.txt".parse().expect("uri");
        let headers = HeaderMap::new();
        let identity = S3CredentialIdentity {
            access_key: "sts-reader".to_string(),
            secret_key: "secret".to_string(),
            session_token: Some("token".to_string()),
            principal: Some("reader".to_string()),
            is_root: false,
            kind: S3IdentityKind::StsSession,
            role_arn: None,
            session_name: None,
            session_policy: None,
        };
        let request = S3PolicyRequest {
            method: &Method::GET,
            uri: &uri,
            headers: &headers,
            identity: Some(&identity),
            auth_type: S3AuthType::AwsSigV4Header,
        };
        let statement = json!({
            "Effect": "Allow",
            "Action": ["s3:GetObject"],
            "NotResource": ["arn:aws:s3:::data-bucket/private/*"],
            "Condition": {
                "StringEqualsIfExists": {
                    "s3:VersionId": "v1"
                }
            }
        });

        let excluded = evaluate_policy_statement(
            &statement,
            &request,
            "s3:GetObject",
            &["arn:aws:s3:::data-bucket/private/secret.txt".to_string()],
            false,
        );
        assert_eq!(excluded, None);

        let uri: Uri = "/data-bucket/public/ok.txt".parse().expect("uri");
        let request = S3PolicyRequest {
            method: &Method::GET,
            uri: &uri,
            headers: &headers,
            identity: Some(&identity),
            auth_type: S3AuthType::AwsSigV4Header,
        };
        let included = evaluate_policy_statement(
            &statement,
            &request,
            "s3:GetObject",
            &["arn:aws:s3:::data-bucket/public/ok.txt".to_string()],
            false,
        );
        assert_eq!(included, Some(true));
    }
}

#[cfg(test)]
mod external_auth_helper_tests {
    use super::{ldap_escape_filter_value, resolve_external_role};

    #[test]
    fn ldap_escape_filter_value_escapes_reserved_bytes() {
        assert_eq!(
            ldap_escape_filter_value(r#"alice*(ops)\root"#),
            r#"alice\2a\28ops\29\5croot"#
        );
    }

    #[test]
    fn resolve_external_role_prefers_group_mapping() {
        let mapping = vec![
            ("platform-admins".to_string(), "admin".to_string()),
            ("ops".to_string(), "operator".to_string()),
        ];
        let role = resolve_external_role(
            None,
            &["ops".to_string(), "random".to_string()],
            &mapping,
            "viewer",
        );
        assert_eq!(role, "operator");
    }

    #[test]
    fn resolve_external_role_prefers_mapping_order_over_group_order() {
        let mapping = vec![
            ("auditors".to_string(), "auditor".to_string()),
            ("ops".to_string(), "operator".to_string()),
        ];
        let role = resolve_external_role(
            None,
            &["ops".to_string(), "auditors".to_string()],
            &mapping,
            "viewer",
        );
        assert_eq!(role, "auditor");
    }
}

#[cfg(test)]
mod tier_and_tenant_compat_tests {
    use std::collections::HashMap;

    use chrono::Utc;
    use rustio_core::{RemoteTierConfig, TenantSpec};

    use super::{
        normalize_remote_tier_config, remote_tier_http_object_url, remote_tier_http_upload_url,
        resolve_bucket_tenant_id, tenant_matches_domain_identifier, tenant_matches_identifier,
    };

    #[test]
    fn normalize_remote_tier_config_accepts_http_backends() {
        let tier = normalize_remote_tier_config(RemoteTierConfig {
            name: "warm".to_string(),
            endpoint: "https://tier.example.internal".to_string(),
            backend: "gcs".to_string(),
            prefix: Some("archive".to_string()),
            storage_class: String::new(),
            enabled: true,
            credential_key: Some("service-account".to_string()),
            credential_secret: Some("service-secret".to_string()),
            credential_token: None,
            extra_headers: HashMap::from([("x-test".to_string(), "1".to_string())]),
            secret_version: 2,
            health_status: String::new(),
            last_checked_at: None,
            last_success_at: None,
            last_error: None,
        })
        .expect("http remote tier should normalize");

        assert_eq!(tier.name, "WARM");
        assert_eq!(tier.backend, "gcs");
        assert_eq!(tier.storage_class, "WARM");
        assert_eq!(tier.health_status, "unknown");
        assert_eq!(
            remote_tier_http_object_url(&tier, "reports", "daily/2026-03.csv", "v1", "bin")
                .expect("gcs object url should build"),
            "https://tier.example.internal/storage/v1/b/reports/o/archive%2F9fc37ff5e5b21e7606616e36ce6aa9dd1cadd4ade5a994207faa647ed110576c%2Fv1%2Ebin?alt=media"
        );
        assert_eq!(
            remote_tier_http_upload_url(&tier, "reports", "daily/2026-03.csv", "v1", "bin")
                .expect("gcs upload url should build"),
            "https://tier.example.internal/upload/storage/v1/b/reports/o?uploadType=media&name=archive%2F9fc37ff5e5b21e7606616e36ce6aa9dd1cadd4ade5a994207faa647ed110576c%2Fv1%2Ebin"
        );
    }

    #[test]
    fn tenant_project_aliases_resolve_for_bucket_requests() {
        let tenant = TenantSpec {
            id: "tenant-a".to_string(),
            display_name: "租户 A".to_string(),
            owner_group: "platform-admins".to_string(),
            project_id: Some("project-a".to_string()),
            project_name: Some("项目 A".to_string()),
            domain_id: Some("domain-a".to_string()),
            domain_name: Some("主域".to_string()),
            enabled: true,
            status: "active".to_string(),
            hard_limit_bytes: 1024,
            used_bytes: 0,
            created_at: Utc::now(),
            updated_at: Utc::now(),
            labels: HashMap::new(),
        };

        assert!(tenant_matches_identifier(&tenant, "tenant-a"));
        assert!(tenant_matches_identifier(&tenant, "project-a"));
        assert!(tenant_matches_identifier(&tenant, "项目 A"));
        assert!(tenant_matches_domain_identifier(&tenant, "domain-a"));
        assert!(tenant_matches_domain_identifier(&tenant, "主域"));
        assert_eq!(
            resolve_bucket_tenant_id(&[tenant], None, Some("project-a".to_string()))
                .expect("project alias should resolve"),
            "tenant-a"
        );
    }
}

#[cfg(test)]
mod object_meta_cache_tests {
    use std::{
        collections::HashMap,
        sync::{Mutex, OnceLock},
    };

    use chrono::Utc;
    use rustio_core::{S3ObjectEncryptionMeta, S3ObjectMeta};
    use uuid::Uuid;

    use crate::state::AppState;

    use super::{object_meta_path, read_current_object_meta, read_current_object_meta_from_disk};

    fn test_env_lock() -> &'static Mutex<()> {
        static LOCK: OnceLock<Mutex<()>> = OnceLock::new();
        LOCK.get_or_init(|| Mutex::new(()))
    }

    #[tokio::test]
    async fn background_meta_read_does_not_warm_object_meta_cache() {
        let _guard = test_env_lock()
            .lock()
            .expect("env lock should be available");
        let temp_dir = std::env::temp_dir().join(format!("rustio-object-meta-{}", Uuid::new_v4()));
        let bucket = "reports";
        let bucket_dir = temp_dir.join(bucket);
        std::fs::create_dir_all(&bucket_dir).expect("bucket dir should be created");

        let previous_data_dir = std::env::var("RUSTIO_DATA_DIR").ok();
        std::env::set_var("RUSTIO_DATA_DIR", &temp_dir);

        let meta = S3ObjectMeta {
            bucket: bucket.to_string(),
            key: "daily/summary.json".to_string(),
            version_id: "v1".to_string(),
            size: 128,
            etag: "etag-1".to_string(),
            created_at: Utc::now(),
            storage_class: "STANDARD".to_string(),
            retention_mode: None,
            retention_until: None,
            legal_hold: false,
            delete_marker: false,
            remote_tier: None,
            restore: None,
            tags: Vec::new(),
            user_metadata: HashMap::new(),
            encryption: S3ObjectEncryptionMeta::default(),
        };
        let meta_path =
            object_meta_path(&bucket_dir, &meta.key).expect("object meta path should build");
        if let Some(parent) = meta_path.parent() {
            std::fs::create_dir_all(parent).expect("meta dir should be created");
        }
        std::fs::write(
            &meta_path,
            serde_json::to_vec(&meta).expect("meta bytes should serialize"),
        )
        .expect("meta file should be written");

        let state = AppState::bootstrap();
        assert!(state.object_meta.read().await.is_empty());

        let disk_meta = read_current_object_meta_from_disk(state.as_ref(), bucket, &meta.key)
            .await
            .expect("disk read should succeed")
            .expect("meta should exist on disk");
        assert_eq!(disk_meta.version_id, meta.version_id);
        assert!(state.object_meta.read().await.is_empty());

        let cached_meta = read_current_object_meta(state.as_ref(), bucket, &meta.key)
            .await
            .expect("cached read should succeed")
            .expect("meta should be cached");
        assert_eq!(cached_meta.version_id, meta.version_id);
        assert_eq!(state.object_meta.read().await.len(), 1);

        if let Some(value) = previous_data_dir {
            std::env::set_var("RUSTIO_DATA_DIR", value);
        } else {
            std::env::remove_var("RUSTIO_DATA_DIR");
        }
        let _ = std::fs::remove_dir_all(&temp_dir);
    }
}

#[cfg(test)]
mod bucket_has_objects_tests {
    use std::sync::{Mutex, OnceLock};

    use uuid::Uuid;

    use super::bucket_has_objects;

    fn test_env_lock() -> &'static Mutex<()> {
        static LOCK: OnceLock<Mutex<()>> = OnceLock::new();
        LOCK.get_or_init(|| Mutex::new(()))
    }

    #[test]
    fn bucket_control_plane_metadata_does_not_make_bucket_non_empty() {
        let _guard = test_env_lock()
            .lock()
            .expect("env lock should be available");
        let bucket_dir =
            std::env::temp_dir().join(format!("rustio-bucket-empty-check-{}", Uuid::new_v4()));
        let meta_dir = bucket_dir.join(".rustio_meta");
        std::fs::create_dir_all(&meta_dir).expect("bucket meta dir should be created");
        std::fs::write(meta_dir.join("bucket-policy.json"), b"{}")
            .expect("bucket policy metadata should be written");
        std::fs::write(meta_dir.join("bucket-tags.json"), b"[]")
            .expect("bucket tags metadata should be written");

        let has_objects =
            bucket_has_objects(&bucket_dir, &bucket_dir).expect("bucket emptiness check should work");
        assert!(
            !has_objects,
            "bucket control-plane metadata should not block bucket deletion"
        );

        let _ = std::fs::remove_dir_all(&bucket_dir);
    }

    #[test]
    fn archived_object_versions_still_make_bucket_non_empty() {
        let _guard = test_env_lock()
            .lock()
            .expect("env lock should be available");
        let bucket_dir = std::env::temp_dir()
            .join(format!("rustio-bucket-version-check-{}", Uuid::new_v4()));
        let version_dir = bucket_dir.join(".rustio_versions").join("docs").join("guide.txt");
        std::fs::create_dir_all(&version_dir).expect("version dir should be created");
        std::fs::write(version_dir.join("v1.json"), b"{}")
            .expect("archived version metadata should be written");

        let has_objects =
            bucket_has_objects(&bucket_dir, &bucket_dir).expect("bucket emptiness check should work");
        assert!(
            has_objects,
            "archived object versions should still block bucket deletion"
        );

        let _ = std::fs::remove_dir_all(&bucket_dir);
    }
}

fn s3_error(status: StatusCode, code: &str, message: &str, resource: &str) -> Response {
    let message = bilingual_s3_message(code, message);
    let body = format!(
        r#"<?xml version="1.0" encoding="UTF-8"?><Error><Code>{}</Code><Message>{}</Message><Resource>{}</Resource><RequestId>{}</RequestId></Error>"#,
        xml_escape(code),
        xml_escape(&message),
        xml_escape(resource),
        Uuid::new_v4()
    );
    s3_xml_response(status, body)
}

async fn s3_create_bucket(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
    Path(bucket): Path<String>,
) -> Result<Json<ApiEnvelope<BucketSpec>>, AppError> {
    auth.require(Permission::BucketWrite)?;
    let mut buckets = state.buckets.write().await;
    if buckets.contains_key(&bucket) {
        return Err(AppError::bad_request(
            "存储桶已存在 / bucket already exists",
        ));
    }

    let spec = BucketSpec {
        name: bucket.clone(),
        tenant_id: "default".to_string(),
        versioning: true,
        object_lock: false,
        ilm_policy: None,
        replication_policy: None,
    };

    buckets.insert(bucket.clone(), spec.clone());
    drop(buckets);

    state
        .bucket_object_locks
        .write()
        .await
        .insert(bucket.clone(), default_object_lock_config(&spec));
    state
        .bucket_retentions
        .write()
        .await
        .insert(bucket.clone(), default_retention_config());
    state
        .bucket_legal_holds
        .write()
        .await
        .insert(bucket.clone(), default_legal_hold_config());
    state
        .bucket_notifications
        .write()
        .await
        .insert(bucket.clone(), Vec::new());
    state
        .bucket_lifecycle_rules
        .write()
        .await
        .insert(bucket.clone(), Vec::new());
    state
        .bucket_acls
        .write()
        .await
        .insert(bucket.clone(), default_bucket_acl_config());
    state
        .bucket_public_access_blocks
        .write()
        .await
        .insert(bucket.clone(), default_bucket_public_access_block_config());
    state
        .append_audit(
            &auth.username,
            "s3.bucket.create",
            &format!("bucket/{bucket}"),
            "success",
            None,
            json!({}),
        )
        .await;
    Ok(wrap(spec))
}

#[derive(Debug, Deserialize)]
struct ListObjectQuery {
    prefix: Option<String>,
}

#[derive(Debug, Serialize)]
struct S3ListResponse {
    bucket: String,
    objects: Vec<S3ObjectMeta>,
}

async fn s3_list_objects(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
    Path(bucket): Path<String>,
    Query(query): Query<ListObjectQuery>,
) -> Result<Json<ApiEnvelope<S3ListResponse>>, AppError> {
    auth.require(Permission::BucketRead)?;
    ensure_metadata_read_barrier_api(&state).await?;
    if !state.buckets.read().await.contains_key(&bucket) {
        return Err(AppError::not_found("存储桶不存在 / bucket not found"));
    }

    let prefix = query.prefix.unwrap_or_default();
    let objects = state
        .object_meta
        .read()
        .await
        .values()
        .filter(|meta| meta.bucket == bucket && meta.key.starts_with(&prefix))
        .cloned()
        .collect::<Vec<_>>();

    Ok(wrap(S3ListResponse { bucket, objects }))
}

async fn s3_put_object(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
    Path((bucket, key)): Path<(String, String)>,
    body: Bytes,
) -> Result<Json<ApiEnvelope<S3ObjectMeta>>, AppError> {
    auth.require(Permission::BucketWrite)?;
    if !state.buckets.read().await.contains_key(&bucket) {
        return Err(AppError::not_found("存储桶不存在 / bucket not found"));
    }

    let etag = Uuid::new_v4().to_string();
    let meta = S3ObjectMeta {
        bucket: bucket.clone(),
        key: key.clone(),
        version_id: Uuid::new_v4().to_string(),
        size: body.len() as u64,
        etag,
        created_at: Utc::now(),
        storage_class: default_storage_class(),
        retention_mode: None,
        retention_until: None,
        legal_hold: false,
        delete_marker: false,
        remote_tier: None,
        restore: None,
        tags: Vec::new(),
        user_metadata: HashMap::new(),
        encryption: S3ObjectEncryptionMeta::default(),
    };

    state
        .object_store
        .write()
        .await
        .insert((bucket.clone(), key.clone()), body.to_vec());
    state
        .object_meta
        .write()
        .await
        .insert((bucket.clone(), key.clone()), meta.clone());

    state
        .push_event(
            "s3.object.put",
            "s3-gateway",
            json!({ "bucket": bucket, "key": key, "size": meta.size }),
        )
        .await;

    Ok(wrap(meta))
}

async fn s3_get_object(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
    Path((bucket, key)): Path<(String, String)>,
) -> Result<impl IntoResponse, AppError> {
    auth.require(Permission::BucketRead)?;
    ensure_metadata_read_barrier_api(&state).await?;
    let store = state.object_store.read().await;
    let bytes = store
        .get(&(bucket.clone(), key.clone()))
        .ok_or_else(|| AppError::not_found("对象不存在 / object not found"))?
        .clone();

    let meta = state
        .object_meta
        .read()
        .await
        .get(&(bucket, key))
        .cloned()
        .ok_or_else(|| AppError::not_found("对象元数据缺失 / object metadata missing"))?;

    let mut response = (StatusCode::OK, bytes).into_response();
    response.headers_mut().insert(
        axum::http::header::CONTENT_TYPE,
        axum::http::HeaderValue::from_static("application/octet-stream"),
    );
    response.headers_mut().insert(
        axum::http::header::HeaderName::from_static("x-rustio-version-id"),
        axum::http::HeaderValue::from_str(&meta.version_id)
            .map_err(|_| AppError::internal("version_id 请求头无效 / invalid version_id header"))?,
    );
    response.headers_mut().insert(
        axum::http::header::ETAG,
        axum::http::HeaderValue::from_str(&meta.etag)
            .map_err(|_| AppError::internal("etag 请求头无效 / invalid etag header"))?,
    );

    Ok(response)
}

async fn s3_delete_object(
    State(state): State<Arc<AppState>>,
    auth: AuthContext,
    Path((bucket, key)): Path<(String, String)>,
) -> Result<Json<ApiEnvelope<serde_json::Value>>, AppError> {
    auth.require(Permission::BucketWrite)?;
    let removed = state
        .object_store
        .write()
        .await
        .remove(&(bucket.clone(), key.clone()))
        .is_some();
    state
        .object_meta
        .write()
        .await
        .remove(&(bucket.clone(), key.clone()));

    if !removed {
        return Err(AppError::not_found("对象不存在 / object not found"));
    }

    state
        .push_event(
            "s3.object.delete",
            "s3-gateway",
            json!({ "bucket": bucket, "key": key }),
        )
        .await;
    Ok(wrap(json!({ "deleted": true })))
}

fn ensure_confirm_header(headers: &HeaderMap) -> Result<(), AppError> {
    let confirmed = headers
        .get("x-rustio-confirm")
        .and_then(|value| value.to_str().ok())
        .map(|value| value.eq_ignore_ascii_case("true"))
        .unwrap_or(false);

    if confirmed {
        Ok(())
    } else {
        Err(AppError::precondition(
            "dangerous action requires x-rustio-confirm: true",
        ))
    }
}

fn extract_access_token(headers: &HeaderMap, query_token: Option<String>) -> Option<String> {
    if let Some(token) = query_token {
        return Some(token);
    }

    headers
        .get(axum::http::header::AUTHORIZATION)
        .and_then(|value| value.to_str().ok())
        .and_then(|value| value.strip_prefix("Bearer "))
        .map(|value| value.to_string())
}

fn wrap<T>(data: T) -> Json<ApiEnvelope<T>> {
    Json(ApiEnvelope {
        data,
        request_id: Uuid::new_v4().to_string(),
    })
}
